                  <div className="space-y-6">
                    <div>
                      <h4 className="font-bold text-gray-700 mb-1 text-sm">توظيف الاستراتيجيات:</h4>
                      <p className="text-gray-600 text-sm bg-gray-50 p-3 rounded-lg border italic">
                        {activeLesson.effectiveStrategiesDeployment || 'لا يوجد وصف'}
                      </p>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-700 mb-1 text-sm">أساليب التقويم:</h4>
                      <p className="text-gray-600 text-sm bg-gray-50 p-3 rounded-lg border">
                        {activeLesson.evaluationMethods || 'لا يوجد وصف'}
                      </p>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-700 mb-1 text-sm">القيم والمواطنة:</h4>
                      <p className="text-gray-600 text-sm bg-gray-50 p-3 rounded-lg border">
                        {activeLesson.valuesAndCitizenship || 'لا يوجد وصف'}
                      </p>
                    </div>
                  </div>
                </div>

                <div className="mt-8 pt-6 border-t flex justify-end gap-3">
                  <button className="bg-indigo-600 text-white px-6 py-2 rounded-lg text-sm font-bold hover:bg-indigo-700">اعتماد الزيارة</button>
                  <button className="bg-gray-200 text-gray-700 px-6 py-2 rounded-lg text-sm font-bold hover:bg-gray-300">إضافة ملاحظات</button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default SupervisorDashboard;

export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  email: string;
}

export type AttachmentType = 'link' | 'image' | 'video' | 'file';

export interface Strategy {
  text: string;
  attachment?: {
    type: AttachmentType;
    url: string;
    name?: string;
  };
}

export interface Lesson {
  id: string;
  teacherId: string;
  teacherName: string;
  title: string;
  strategiesCount: number;
  strategies: Strategy[];
  selfLearningSkills: {
    thinking: boolean;
    collaboration: boolean;
    criticalThinking: boolean;
    higherOrderThinking: boolean;
  };
  effectiveStrategiesDeployment: string;
  evaluationMethods: string;
  valuesAndCitizenship: string;
  createdAt: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState } from 'react';
import { User, Lesson, Strategy, AttachmentType } from '../types';
import { suggestStrategies } from '../services/geminiService';

interface TeacherDashboardProps {
  user: User;
  addLesson: (lesson: Lesson) => void;
  lessons: Lesson[];
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ user, addLesson, lessons }) => {
  const [showForm, setShowForm] = useState(false);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);

  // Form State
  const [title, setTitle] = useState('');
  const [strategies, setStrategies] = useState<Strategy[]>([{ text: '' }]);
  const [selfLearning, setSelfLearning] = useState({
    thinking: false,
    collaboration: false,
    criticalThinking: false,
    higherOrderThinking: false,
  });
  const [deployment, setDeployment] = useState('');
  const [evaluations, setEvaluations] = useState('');
  const [values, setValues] = useState('');

  const handleAddStrategy = () => {
    if (strategies.length < 10) {
      setStrategies([...strategies, { text: '' }]);
    }
  };

  const handleRemoveStrategy = (index: number) => {
    const newStrats = strategies.filter((_, i) => i !== index);
    setStrategies(newStrats);
  };

  const updateStrategyText = (index: number, val: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], text: val };
    setStrategies(newStrats);
  };

  const setStrategyAttachment = (index: number, type: AttachmentType, url: string, name?: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], attachment: { type, url, name } };
    setStrategies(newStrats);
  };

  const removeAttachment = (index: number) => {
    const newStrats = [...strategies];
    delete newStrats[index].attachment;
    setStrategies(newStrats);
  };

  const handleFileChange = (index: number, type: AttachmentType, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setStrategyAttachment(index, type, reader.result as string, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSuggest = async () => {
    if (!title) return alert('يرجى كتابة عنوان الدرس أولاً');
    setLoadingSuggestions(true);
    const suggested = await suggestStrategies(title);
    setStrategies(suggested.slice(0, 10).map(s => ({ text: s })));
    setLoadingSuggestions(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalStrategies = strategies.filter(s => s.text.trim() !== '');
    const newLesson: Lesson = {
      id: Math.random().toString(36).substr(2, 9),
      teacherId: user.id,
      teacherName: user.name,
      title,
      strategiesCount: finalStrategies.length,
      strategies: finalStrategies,
      selfLearningSkills: selfLearning,
      effectiveStrategiesDeployment: deployment,
      evaluationMethods: evaluations,
      valuesAndCitizenship: values,
      createdAt: new Date().toLocaleDateString('ar-SA'),
    };
    addLesson(newLesson);
    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setTitle('');
    setStrategies([{ text: '' }]);
    setSelfLearning({
      thinking: false,
      collaboration: false,
      criticalThinking: false,
      higherOrderThinking: false,
    });
    setDeployment('');
    setEvaluations('');
    setValues('');
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">قائمة الدروس</h2>
          <p className="text-gray-500">إدارة الدروس والزيارات الإشرافية الخاصة بك</p>
        </div>
        <button
          onClick={() => setShowForm(!showForm)}
          className="bg-indigo-600 text-white px-6 py-2 rounded-lg font-bold hover:bg-indigo-700 transition shadow-md flex items-center gap-2"
        >
          {showForm ? 'إلغاء' : (
            <>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
              </svg>
              إضافة درس جديد
            </>
          )}
        </button>
      </div>

      {showForm && (
        <div className="bg-white rounded-xl shadow-lg p-6 border-t-4 border-indigo-600 animate-fadeIn">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-1">عنوان الدرس</label>
                  <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500"
                    placeholder="مثال: التكاثر في النباتات"
                  />
                </div>

                <div>
                  <div className="flex justify-between items-center mb-2">
                    <label className="text-sm font-semibold text-gray-700">استراتيجيات التدريس ({strategies.length}/10)</label>
                    <button
                      type="button"
                      onClick={handleSuggest}
                      disabled={loadingSuggestions}
                      className="text-xs text-indigo-600 font-bold hover:underline flex items-center gap-1"
                    >
                      {loadingSuggestions ? 'جاري التحميل...' : '🤖 اقتراحات الذكاء الاصطناعي'}
                    </button>
                  </div>
                  <div className="space-y-4 max-h-[500px] overflow-y-auto p-1 scrollbar-thin scrollbar-thumb-indigo-200">
                    {strategies.map((strat, idx) => (
                      <div key={idx} className="p-3 border rounded-lg bg-gray-50 space-y-2">
                        <div className="flex gap-2">
                          <input
                            type="text"
                            value={strat.text}
                            onChange={(e) => updateStrategyText(idx, e.target.value)}
                            className="flex-1 px-3 py-1 text-sm border rounded-md"
                            placeholder={`استراتيجية رقم ${idx + 1}`}
                          />
                          {strategies.length > 1 && (
                            <button
                              type="button"
                              onClick={() => handleRemoveStrategy(idx)}
                              className="text-red-500 p-1 hover:bg-red-50 rounded"
                            >
                              &times;
                            </button>
                          )}
                        </div>

                        <div className="flex flex-wrap gap-2 items-center">
                          {!strat.attachment ? (
                            <div className="flex gap-2">
                              <label className="cursor-pointer bg-white border border-gray-300 px-2 py-1 rounded text-[10px] hover:bg-gray-100 flex items-center gap-1">
                                <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileChange(idx, 'image', e)} />
                                🖼️ صورة
                              </label>
                              <label className="cursor-pointer bg-white border border-gray-300 px-2 py-1 rounded text-[10px] hover:bg-gray-100 flex items-center gap-1">
                                <input type="file" accept="video/*" className="hidden" onChange={(e) => handleFileChange(idx, 'video', e)} />
                                🎥 فيديو
                              </label>
                              <label className="cursor-pointer bg-white border border-gray-300 px-2 py-1 rounded text-[10px] hover:bg-gray-100 flex items-center gap-1">
                                <input type="file" className="hidden" onChange={(e) => handleFileChange(idx, 'file', e)} />
                                📄 ملف
                              </label>
                              <button
                                type="button"
                                onClick={() => {
                                  const url = prompt('أدخل الرابط:');
                                  if (url) setStrategyAttachment(idx, 'link', url, 'رابط');
                                }}
                                className="bg-white border border-gray-300 px-2 py-1 rounded text-[10px] hover:bg-gray-100 flex items-center gap-1"
                              >
                                🔗 رابط
                              </button>
                            </div>
                          ) : (
                            <div className="flex items-center gap-2 bg-indigo-50 px-2 py-1 rounded-md border border-indigo-100 w-full justify-between">
                              <span className="text-[10px] text-indigo-700 truncate max-w-[150px]">
                                {strat.attachment.type === 'link' ? '🔗' : strat.attachment.type === 'image' ? '🖼️' : strat.attachment.type === 'video' ? '🎥' : '📄'} 
                                {strat.attachment.name || 'مرفق'}
                              </span>
                              <button type="button" onClick={() => removeAttachment(idx)} className="text-red-500 text-xs hover:font-bold">&times;</button>
                            </div>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                  {strategies.length < 10 && (
                    <button
                      type="button"
                      onClick={handleAddStrategy}
                      className="mt-2 text-sm text-indigo-600 hover:text-indigo-800 font-semibold"
                    >
                      + إضافة استراتيجية أخرى
                    </button>
                  )}
                </div>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">مهارات التعلم الذاتي</label>
                  <div className="grid grid-cols-2 gap-2">
                    {[
                      { key: 'thinking', label: 'التفكير' },
                      { key: 'collaboration', label: 'التعاون' },
                      { key: 'criticalThinking', label: 'التفكير النقدي' },
                      { key: 'higherOrderThinking', label: 'التفكير العليا وربطها بالواقع' }
                    ].map((skill) => (
                      <label key={skill.key} className="flex items-center gap-2 p-2 border rounded-lg hover:bg-slate-50 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={selfLearning[skill.key as keyof typeof selfLearning]}
                          onChange={(e) => setSelfLearning({ ...selfLearning, [skill.key]: e.target.checked })}
                          className="w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                        />
                        <span className="text-xs">{skill.label}</span>
                      </label>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-1">توظيف استراتيجيات تدريس فعالة</label>
                  <textarea
                    rows={2}
                    value={deployment}
                    onChange={(e) => setDeployment(e.target.value)}
                    className="w-full px-4 py-2 border rounded-lg text-sm"
                    placeholder="كيف سيتم توظيف الاستراتيجيات؟"
                  />
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">أساليب تقويم متنوعة</label>
                <textarea
                  rows={2}
                  value={evaluations}
                  onChange={(e) => setEvaluations(e.target.value)}
                  className="w-full px-4 py-2 border rounded-lg text-sm"
                  placeholder="الاختبارات، الملاحظة، التقويم الذاتي..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">القيم والاتجاهات والمواطنة</label>
                <textarea
                  rows={2}
                  value={values}
                  onChange={(e) => setValues(e.target.value)}
                  className="w-full px-4 py-2 border rounded-lg text-sm"
                  placeholder="القيم المكتسبة من الدرس..."
                />
              </div>
            </div>

            <div className="flex justify-end">
              <button
                type="submit"
                className="bg-green-600 text-white px-8 py-3 rounded-lg font-bold hover:bg-green-700 transition shadow-lg"
              >
                حفظ الدرس
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Lessons List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {lessons.length === 0 ? (
          <div className="col-span-full text-center py-20 bg-white rounded-xl border-2 border-dashed border-gray-200">
            <p className="text-gray-400">لا يوجد دروس مضافة حتى الآن</p>
          </div>
        ) : (
          lessons.map((lesson) => (
            <div key={lesson.id} className="bg-white rounded-xl shadow-md overflow-hidden hover:shadow-lg transition-shadow border border-gray-100">
              <div className="bg-indigo-50 p-4 border-b">
                <h3 className="text-lg font-bold text-indigo-900 truncate">{lesson.title}</h3>
                <span className="text-xs text-indigo-500">{lesson.createdAt}</span>
              </div>
              <div className="p-4 space-y-3">
                <div className="flex items-center gap-2">
                  <span className="px-2 py-1 bg-amber-100 text-amber-800 text-xs rounded-full font-bold">
                    {lesson.strategiesCount} استراتيجيات
                  </span>
                </div>
                <div className="text-xs text-gray-600 line-clamp-2">
                  <strong>التقويم:</strong> {lesson.evaluationMethods || 'لم يحدد'}
                </div>
                <div className="flex flex-wrap gap-1">
                   {Object.entries(lesson.selfLearningSkills)
                     .filter(([_, active]) => active)
                     .map(([key]) => (
                       <span key={key} className="text-[10px] bg-slate-100 px-2 py-0.5 rounded border">
                         {key === 'thinking' ? 'تفكير' : key === 'collaboration' ? 'تعاون' : 'نقد'}
                       </span>
                     ))}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default TeacherDashboard;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ lessons }) => {
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);

  // Group lessons by teacher
  const teachers = useMemo(() => {
    const map = new Map<string, { id: string; name: string; lessonCount: number }>();
    lessons.forEach(l => {
      if (!map.has(l.teacherId)) {
        map.set(l.teacherId, { id: l.teacherId, name: l.teacherName, lessonCount: 0 });
      }
      map.get(l.teacherId)!.lessonCount++;
    });
    return Array.from(map.values());
  }, [lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return null;
    const { type, url, name } = strategy.attachment;

    switch (type) {
      case 'image':
        return (
          <div className="mt-2">
            <img src={url} alt={name} className="max-h-32 rounded-lg border shadow-sm cursor-zoom-in hover:opacity-90 transition-opacity" onClick={() => window.open(url)} />
            <p className="text-[10px] text-gray-400 mt-1">{name}</p>
          </div>
        );
      case 'video':
        return (
          <div className="mt-2">
            <video src={url} controls className="max-h-48 w-full rounded-lg border shadow-sm" />
            <p className="text-[10px] text-gray-400 mt-1">{name}</p>
          </div>
        );
      case 'link':
        return (
          <a href={url} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-1 text-xs text-indigo-600 hover:underline mt-1 font-medium bg-indigo-50 px-2 py-1 rounded">
            🔗 زيارة الرابط
          </a>
        );
      case 'file':
        return (
          <a href={url} download={name} className="inline-flex items-center gap-1 text-xs text-green-600 hover:underline mt-1 font-medium bg-green-50 px-2 py-1 rounded">
            📄 تحميل الملف ({name})
          </a>
        );
      default:
        return null;
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
      {/* Teachers List Sidebar */}
      <div className="lg:col-span-1 bg-white rounded-xl shadow-md p-4 space-y-4">
        <h2 className="text-lg font-bold text-gray-800 border-b pb-2">قائمة المعلمين</h2>
        <div className="space-y-2">
          {teachers.length === 0 ? (
            <p className="text-gray-400 text-sm text-center py-4">لا يوجد بيانات حالياً</p>
          ) : (
            teachers.map((teacher) => (
              <button
                key={teacher.id}
                onClick={() => {
                  setSelectedTeacherId(teacher.id);
                  setSelectedLessonId(null);
                }}
                className={`w-full text-right p-3 rounded-lg transition-all border ${
                  selectedTeacherId === teacher.id
                    ? 'bg-indigo-50 border-indigo-200 text-indigo-700 ring-2 ring-indigo-100'
                    : 'bg-white border-transparent text-gray-600 hover:bg-slate-50'
                }`}
              >
                <div className="font-bold">{teacher.name}</div>
                <div className="text-xs opacity-70">{teacher.lessonCount} دروس مسجلة</div>
              </button>
            ))
          )}
        </div>
      </div>

      {/* Main View Area */}
      <div className="lg:col-span-3 space-y-6">
        {!selectedTeacherId ? (
          <div className="bg-white rounded-xl shadow-md p-20 text-center space-y-4 border-2 border-dashed border-gray-200">
            <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center mx-auto text-indigo-600">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
              </svg>
            </div>
            <div>
              <h3 className="text-xl font-bold text-gray-700">مرحباً بك في لوحة المشرف</h3>
              <p className="text-gray-500">يرجى اختيار معلم من القائمة الجانبية لمراجعة سجلاته</p>
            </div>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="bg-white p-4 rounded-xl shadow-sm border-r-4 border-indigo-600">
              <h2 className="text-xl font-bold">سجل المعلم: {teachers.find(t => t.id === selectedTeacherId)?.name}</h2>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              {teacherLessons.map(lesson => (
                <button
                  key={lesson.id}
                  onClick={() => setSelectedLessonId(lesson.id)}
                  className={`text-right p-4 rounded-xl shadow-sm border transition-all ${
                    selectedLessonId === lesson.id
                      ? 'bg-amber-50 border-amber-200'
                      : 'bg-white border-gray-100 hover:border-indigo-200'
                  }`}
                >
                  <h4 className="font-bold text-gray-800">{lesson.title}</h4>
                  <p className="text-xs text-gray-500">{lesson.createdAt}</p>
                </button>
              ))}
            </div>

            {/* Lesson Details Detail View */}
            {activeLesson && (
              <div className="bg-white rounded-xl shadow-lg p-6 animate-fadeIn border border-indigo-50">
                <div className="flex justify-between items-start border-b pb-4 mb-6">
                  <div>
                    <h3 className="text-2xl font-black text-indigo-800">{activeLesson.title}</h3>
                    <p className="text-sm text-gray-500">تمت الإضافة في {activeLesson.createdAt}</p>
                  </div>
                  <div className="bg-indigo-100 text-indigo-800 px-4 py-1 rounded-full text-sm font-bold">
                    {activeLesson.strategiesCount} استراتيجيات
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-4">
                    <div>
                      <h4 className="font-bold text-gray-700 mb-2 flex items-center gap-2">
                        <span className="w-1.5 h-6 bg-amber-400 rounded-full"></span>
                        استراتيجيات التدريس
                      </h4>
                      <div className="space-y-4 mr-4">
                        {activeLesson.strategies.map((s, i) => (
                          <div key={i} className="bg-slate-50 p-3 rounded-lg border border-slate-100">
                            <div className="text-sm font-medium text-gray-800">• {s.text}</div>
                            {renderAttachment(s)}
                          </div>
                        ))}
                      </div>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-700 mb-2 flex items-center gap-2">
                        <span className="w-1.5 h-6 bg-blue-400 rounded-full"></span>
                        مهارات التعلم الذاتي
                      </h4>
                      <div className="flex flex-wrap gap-2">
                        {activeLesson.selfLearningSkills.thinking && <span className="bg-blue-50 text-blue-700 px-3 py-1 rounded-md text-xs border border-blue-100">التفكير</span>}
                        {activeLesson.selfLearningSkills.collaboration && <span className="bg-green-50 text-green-700 px-3 py-1 rounded-md text-xs border border-green-100">التعاون</span>}
                        {activeLesson.selfLearningSkills.criticalThinking && <span className="bg-purple-50 text-purple-700 px-3 py-1 rounded-md text-xs border border-purple-100">التفكير النقدي</span>}
                        {activeLesson.selfLearningSkills.higherOrderThinking && <span className="bg-rose-50 text-rose-700 px-3 py-1 rounded-md text-xs border border-rose-100">تفكير عليا / واقع</span>}
                      </div>
                    </div>
                  </div>

                  <div className="space-y-6">
                    <div>
                      <h4 className="font-bold text-gray-700 mb-1 text-sm">توظيف الاستراتيجيات:</h4>
                      <p className="text-gray-600 text-sm bg-gray-50 p-3 rounded-lg border italic">
                        {activeLesson.effectiveStrategiesDeployment || 'لا يوجد وصف'}
                      </p>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-700 mb-1 text-sm">أساليب التقويم:</h4>
                      <p className="text-gray-600 text-sm bg-gray-50 p-3 rounded-lg border">
                        {activeLesson.evaluationMethods || 'لا يوجد وصف'}
                      </p>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-700 mb-1 text-sm">القيم والمواطنة:</h4>
                      <p className="text-gray-600 text-sm bg-gray-50 p-3 rounded-lg border">
                        {activeLesson.valuesAndCitizenship || 'لا يوجد وصف'}
                      </p>
                    </div>
                  </div>
                </div>

                <div className="mt-8 pt-6 border-t flex justify-end gap-3">
                  <button className="bg-indigo-600 text-white px-6 py-2 rounded-lg text-sm font-bold hover:bg-indigo-700">اعتماد الزيارة</button>
                  <button className="bg-gray-200 text-gray-700 px-6 py-2 rounded-lg text-sm font-bold hover:bg-gray-300">إضافة ملاحظات</button>
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default SupervisorDashboard;

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Lesson } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [lessons, setLessons] = useState<Lesson[]>(() => {
    const saved = localStorage.getItem('app_lessons');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('app_lessons', JSON.stringify(lessons));
  }, [lessons]);

  const handleLogin = (user: User) => {
    setAuth({ user, isAuthenticated: true });
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
  };

  const addLesson = (newLesson: Lesson) => {
    setLessons(prev => [newLesson, ...prev]);
  };

  const deleteLesson = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الدرس؟')) {
      setLessons(prev => prev.filter(l => l.id !== id));
    }
  };

  const updateLesson = (updatedLesson: Lesson) => {
    setLessons(prev => prev.map(l => (l.id === updatedLesson.id ? updatedLesson : l)));
  };

  if (!auth.isAuthenticated) {
    return <LoginForm onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-slate-50">
      <nav className="bg-indigo-700 text-white shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center gap-2">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
              </svg>
              <span className="text-xl font-bold">الزيارات الإشرافية للمجال الأول</span>
            </div>
            <div className="flex items-center gap-4">
              <div className="text-sm">
                مرحباً، <span className="font-semibold">{auth.user?.name}</span>
                <span className="mx-2 text-indigo-300">|</span>
                <span className="bg-indigo-600 px-2 py-1 rounded text-xs uppercase tracking-wider">
                  {auth.user?.role === UserRole.TEACHER ? 'معلم' : 'مشرف'}
                </span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-red-500 hover:bg-red-600 px-4 py-2 rounded-md text-sm font-medium transition-colors"
              >
                تسجيل الخروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            addLesson={addLesson} 
            deleteLesson={deleteLesson}
            updateLesson={updateLesson}
            lessons={lessons.filter(l => l.teacherId === auth.user?.id)} 
          />
        ) : (
          <SupervisorDashboard lessons={lessons} />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { User, Lesson, Strategy, AttachmentType } from '../types';
import { suggestStrategies } from '../services/geminiService';

interface TeacherDashboardProps {
  user: User;
  addLesson: (lesson: Lesson) => void;
  deleteLesson: (id: string) => void;
  updateLesson: (lesson: Lesson) => void;
  lessons: Lesson[];
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ user, addLesson, deleteLesson, updateLesson, lessons }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const formRef = useRef<HTMLDivElement>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [strategies, setStrategies] = useState<Strategy[]>([{ text: '' }]);
  const [selfLearning, setSelfLearning] = useState({
    thinking: false,
    collaboration: false,
    criticalThinking: false,
    higherOrderThinking: false,
  });
  const [deployment, setDeployment] = useState('');
  const [evaluations, setEvaluations] = useState('');
  const [values, setValues] = useState('');

  const handleAddStrategy = () => {
    if (strategies.length < 10) {
      setStrategies([...strategies, { text: '' }]);
    }
  };

  const handleRemoveStrategy = (index: number) => {
    const newStrats = strategies.filter((_, i) => i !== index);
    setStrategies(newStrats);
  };

  const updateStrategyText = (index: number, val: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], text: val };
    setStrategies(newStrats);
  };

  const setStrategyAttachment = (index: number, type: AttachmentType, url: string, name?: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], attachment: { type, url, name } };
    setStrategies(newStrats);
  };

  const removeAttachment = (index: number) => {
    const newStrats = [...strategies];
    delete newStrats[index].attachment;
    setStrategies(newStrats);
  };

  const handleFileChange = (index: number, type: AttachmentType, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setStrategyAttachment(index, type, reader.result as string, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSuggest = async () => {
    if (!title) return alert('يرجى كتابة عنوان الدرس أولاً');
    setLoadingSuggestions(true);
    const suggested = await suggestStrategies(title);
    setStrategies(suggested.slice(0, 10).map(s => ({ text: s })));
    setLoadingSuggestions(false);
  };

  const handleEdit = (lesson: Lesson) => {
    setEditingId(lesson.id);
    setTitle(lesson.title);
    setStrategies(lesson.strategies.length > 0 ? lesson.strategies : [{ text: '' }]);
    setSelfLearning(lesson.selfLearningSkills);
    setDeployment(lesson.effectiveStrategiesDeployment);
    setEvaluations(lesson.evaluationMethods);
    setValues(lesson.valuesAndCitizenship);
    setShowForm(true);
    setTimeout(() => {
      formRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalStrategies = strategies.filter(s => s.text.trim() !== '');

    const lessonData: Lesson = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      teacherId: user.id,
      teacherName: user.name,
      title,
      strategiesCount: finalStrategies.length,
      strategies: finalStrategies,
      selfLearningSkills: selfLearning,
      effectiveStrategiesDeployment: deployment,
      evaluationMethods: evaluations,
      valuesAndCitizenship: values,
      createdAt: editingId ? (lessons.find(l => l.id === editingId)?.createdAt || new Date().toLocaleDateString('ar-SA')) : new Date().toLocaleDateString('ar-SA'),
    };

    if (editingId) {
      updateLesson(lessonData);
    } else {
      addLesson(lessonData);
    }

    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setEditingId(null);
    setTitle('');
    setStrategies([{ text: '' }]);
    setSelfLearning({
      thinking: false,
      collaboration: false,
      criticalThinking: false,
      higherOrderThinking: false,
    });
    setDeployment('');
    setEvaluations('');
    setValues('');
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">قائمة الدروس</h2>
          <p className="text-gray-500">إدارة الدروس والزيارات الإشرافية الخاصة بك</p>
        </div>
        <button
          onClick={() => {
            if (showForm) resetForm();
            setShowForm(!showForm);
          }}
          className={`${showForm ? 'bg-gray-500' : 'bg-indigo-600'} text-white px-6 py-2 rounded-lg font-bold hover:opacity-90 transition shadow-md flex items-center gap-2`}
        >
          {showForm ? 'إلغاء' : (
            <>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
              </svg>
              إضافة درس جديد
            </>
          )}
        </button>
      </div>

      {showForm && (
        <div ref={formRef} className="bg-white rounded-xl shadow-lg p-6 border-t-4 border-indigo-600 animate-fadeIn">
          <div className="mb-4 flex justify-between items-center">
             <h3 className="text-lg font-bold text-gray-700">{editingId ? 'تعديل الدرس' : 'إضافة درس جديد'}</h3>
             {editingId && <button onClick={resetForm} className="text-xs text-red-500 hover:underline">بدء إضافة درس جديد بدلاً من التعديل</button>}
          </div>
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-1">عنوان الدرس</label>
                  <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-indigo-500"
                    placeholder="مثال: التكاثر في النباتات"
                  />
                </div>

                <div>
                  <div className="flex justify-between items-center mb-2">
                    <label className="text-sm font-semibold text-gray-700">استراتيجيات التدريس ({strategies.length}/10)</label>
                    <button
                      type="button"
                      onClick={handleSuggest}
                      disabled={loadingSuggestions}
                      className="text-xs text-indigo-600 font-bold hover:underline flex items-center gap-1"
                    >
                      {loadingSuggestions ? 'جاري التحميل...' : '🤖 اقتراحات الذكاء الاصطناعي'}
                    </button>
                  </div>
                  <div className="space-y-4 max-h-[500px] overflow-y-auto p-1 scrollbar-thin scrollbar-thumb-indigo-200">
                    {strategies.map((strat, idx) => (
                      <div key={idx} className="p-3 border rounded-lg bg-gray-50 space-y-2">
                        <div className="flex gap-2">
                          <input
                            type="text"
                            value={strat.text}
                            onChange={(e) => updateStrategyText(idx, e.target.value)}
                            className="flex-1 px-3 py-1 text-sm border rounded-md"
                            placeholder={`استراتيجية رقم ${idx + 1}`}
                          />
                          {strategies.length > 1 && (
                            <button
                              type="button"
                              onClick={() => handleRemoveStrategy(idx)}
                              className="text-red-500 p-1 hover:bg-red-50 rounded"
                            >
                              &times;
                            </button>
                          )}
                        </div>

                        <div className="flex flex-wrap gap-2 items-center">
                          {!strat.attachment ? (
                            <div className="flex gap-2">
                              <label className="cursor-pointer bg-white border border-gray-300 px-2 py-1 rounded text-[10px] hover:bg-gray-100 flex items-center gap-1">
                                <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileChange(idx, 'image', e)} />
                                🖼️ صورة
                              </label>
                              <label className="cursor-pointer bg-white border border-gray-300 px-2 py-1 rounded text-[10px] hover:bg-gray-100 flex items-center gap-1">
                                <input type="file" accept="video/*" className="hidden" onChange={(e) => handleFileChange(idx, 'video', e)} />
                                🎥 فيديو
                              </label>
                              <label className="cursor-pointer bg-white border border-gray-300 px-2 py-1 rounded text-[10px] hover:bg-gray-100 flex items-center gap-1">
                                <input type="file" className="hidden" onChange={(e) => handleFileChange(idx, 'file', e)} />
                                📄 ملف
                              </label>
                              <button
                                type="button"
                                onClick={() => {
                                  const url = prompt('أدخل الرابط:');
                                  if (url) setStrategyAttachment(idx, 'link', url, 'رابط');
                                }}
                                className="bg-white border border-gray-300 px-2 py-1 rounded text-[10px] hover:bg-gray-100 flex items-center gap-1"
                              >
                                🔗 رابط
                              </button>
                            </div>
                          ) : (
                            <div className="flex items-center gap-2 bg-indigo-50 px-2 py-1 rounded-md border border-indigo-100 w-full justify-between">
                              <span className="text-[10px] text-indigo-700 truncate max-w-[150px]">
                                {strat.attachment.type === 'link' ? '🔗' : strat.attachment.type === 'image' ? '🖼️' : strat.attachment.type === 'video' ? '🎥' : '📄'} 
                                {strat.attachment.name || 'مرفق'}
                              </span>
                              <button type="button" onClick={() => removeAttachment(idx)} className="text-red-500 text-xs hover:font-bold">&times;</button>
                            </div>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                  {strategies.length < 10 && (
                    <button
                      type="button"
                      onClick={handleAddStrategy}
                      className="mt-2 text-sm text-indigo-600 hover:text-indigo-800 font-semibold"
                    >
                      + إضافة استراتيجية أخرى
                    </button>
                  )}
                </div>
              </div>

              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-2">مهارات التعلم الذاتي</label>
                  <div className="grid grid-cols-2 gap-2">
                    {[
                      { key: 'thinking', label: 'التفكير' },
                      { key: 'collaboration', label: 'التعاون' },
                      { key: 'criticalThinking', label: 'التفكير النقدي' },
                      { key: 'higherOrderThinking', label: 'التفكير العليا وربطها بالواقع' }
                    ].map((skill) => (
                      <label key={skill.key} className="flex items-center gap-2 p-2 border rounded-lg hover:bg-slate-50 cursor-pointer">
                        <input
                          type="checkbox"
                          checked={selfLearning[skill.key as keyof typeof selfLearning]}
                          onChange={(e) => setSelfLearning({ ...selfLearning, [skill.key]: e.target.checked })}
                          className="w-4 h-4 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                        />
                        <span className="text-xs">{skill.label}</span>
                      </label>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-semibold text-gray-700 mb-1">توظيف استراتيجيات تدريس فعالة</label>
                  <textarea
                    rows={2}
                    value={deployment}
                    onChange={(e) => setDeployment(e.target.value)}
                    className="w-full px-4 py-2 border rounded-lg text-sm"
                    placeholder="كيف سيتم توظيف الاستراتيجيات؟"
                  />
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">أساليب تقويم متنوعة</label>
                <textarea
                  rows={2}
                  value={evaluations}
                  onChange={(e) => setEvaluations(e.target.value)}
                  className="w-full px-4 py-2 border rounded-lg text-sm"
                  placeholder="الاختبارات، الملاحظة، التقويم الذاتي..."
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1">القيم والاتجاهات والمواطنة</label>
                <textarea
                  rows={2}
                  value={values}
                  onChange={(e) => setValues(e.target.value)}
                  className="w-full px-4 py-2 border rounded-lg text-sm"
                  placeholder="القيم المكتسبة من الدرس..."
                />
              </div>
            </div>

            <div className="flex justify-end gap-3">
               {editingId && <button type="button" onClick={resetForm} className="bg-gray-100 text-gray-600 px-6 py-3 rounded-lg font-bold hover:bg-gray-200">إلغاء التعديل</button>}
              <button
                type="submit"
                className="bg-green-600 text-white px-8 py-3 rounded-lg font-bold hover:bg-green-700 transition shadow-lg"
              >
                {editingId ? 'تحديث الدرس' : 'حفظ الدرس'}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Lessons List */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {lessons.length === 0 ? (
          <div className="col-span-full text-center py-20 bg-white rounded-xl border-2 border-dashed border-gray-200">
            <p className="text-gray-400">لا يوجد دروس مضافة حتى الآن</p>
          </div>
        ) : (
          lessons.map((lesson) => (
            <div key={lesson.id} className="bg-white rounded-xl shadow-md overflow-hidden hover:shadow-lg transition-shadow border border-gray-100 flex flex-col">
              <div className="bg-indigo-50 p-4 border-b flex justify-between items-start">
                <div className="max-w-[70%]">
                  <h3 className="text-lg font-bold text-indigo-900 truncate" title={lesson.title}>{lesson.title}</h3>
                  <span className="text-xs text-indigo-500">{lesson.createdAt}</span>
                </div>
                <div className="flex gap-2">
                   <button 
                    onClick={() => handleEdit(lesson)}
                    className="p-1.5 text-blue-600 hover:bg-blue-100 rounded-lg transition-colors"
                    title="تعديل"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
