import React, { useState, useRef } from 'react';
import { User, Lesson, Strategy, AttachmentType } from '../types';
import { suggestStrategies } from '../services/geminiService';

interface TeacherDashboardProps {
  user: User;
  addLesson: (lesson: Lesson) => void;
  deleteLesson: (id: string) => void;
  updateLesson: (lesson: Lesson) => void;
  lessons: Lesson[];
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ user, addLesson, deleteLesson, updateLesson, lessons }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const formRef = useRef<HTMLDivElement>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [strategies, setStrategies] = useState<Strategy[]>([{ text: '' }]);
  const [selfLearning, setSelfLearning] = useState({
    thinking: false,
    collaboration: false,
    criticalThinking: false,
    higherOrderThinking: false,
  });
  const [deployment, setDeployment] = useState('');
  const [evaluations, setEvaluations] = useState('');
  const [values, setValues] = useState('');

  const handleAddStrategy = () => {
    if (strategies.length < 10) {
      setStrategies([...strategies, { text: '' }]);
    }
  };

  const handleRemoveStrategy = (index: number) => {
    const newStrats = strategies.filter((_, i) => i !== index);
    setStrategies(newStrats);
  };

  const updateStrategyText = (index: number, val: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], text: val };
    setStrategies(newStrats);
  };

  const setStrategyAttachment = (index: number, type: AttachmentType, url: string, name?: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], attachment: { type, url, name: name || 'مرفق' } };
    setStrategies(newStrats);
  };

  const removeAttachment = (index: number) => {
    const newStrats = [...strategies];
    delete newStrats[index].attachment;
    setStrategies(newStrats);
  };

  const handleFileChange = (index: number, type: AttachmentType, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setStrategyAttachment(index, type, reader.result as string, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddLink = (index: number) => {
    const url = prompt('يرجى إدخال رابط الموقع (مثال: https://google.com):');
    if (url && url.trim()) {
      let formattedUrl = url.trim();
      if (!formattedUrl.startsWith('http')) {
        formattedUrl = 'https://' + formattedUrl;
      }
      setStrategyAttachment(index, 'link', formattedUrl, 'رابط تعليمي');
    }
  };

  const handleSuggest = async () => {
    if (!title) return alert('يرجى كتابة عنوان الدرس أولاً');
    setLoadingSuggestions(true);
    const suggested = await suggestStrategies(title);
    setStrategies(suggested.slice(0, 10).map(s => ({ text: s })));
    setLoadingSuggestions(false);
  };

  const handleEdit = (lesson: Lesson) => {
    setEditingId(lesson.id);
    setTitle(lesson.title);
    setStrategies(lesson.strategies.length > 0 ? lesson.strategies : [{ text: '' }]);
    setSelfLearning(lesson.selfLearningSkills);
    setDeployment(lesson.effectiveStrategiesDeployment);
    setEvaluations(lesson.evaluationMethods);
    setValues(lesson.valuesAndCitizenship);
    setShowForm(true);
    setTimeout(() => {
      formRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalStrategies = strategies.filter(s => s.text.trim() !== '');

    const lessonData: Lesson = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      teacherId: user.id,
      teacherName: user.name,
      title,
      strategiesCount: finalStrategies.length,
      strategies: finalStrategies,
      selfLearningSkills: selfLearning,
      effectiveStrategiesDeployment: deployment,
      evaluationMethods: evaluations,
      valuesAndCitizenship: values,
      createdAt: editingId ? (lessons.find(l => l.id === editingId)?.createdAt || new Date().toLocaleDateString('ar-SA')) : new Date().toLocaleDateString('ar-SA'),
    };

    if (editingId) {
      updateLesson(lessonData);
    } else {
      addLesson(lessonData);
    }

    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setEditingId(null);
    setTitle('');
    setStrategies([{ text: '' }]);
    setSelfLearning({
      thinking: false,
      collaboration: false,
      criticalThinking: false,
      higherOrderThinking: false,
    });
    setDeployment('');
    setEvaluations('');
    setValues('');
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">قائمة الدروس</h2>
          <p className="text-gray-500">إدارة الدروس والزيارات الإشرافية الخاصة بك</p>
        </div>
        <button
          onClick={() => {
            if (showForm) resetForm();
            setShowForm(!showForm);
          }}
          className={`${showForm ? 'bg-slate-500' : 'bg-indigo-600'} text-white px-6 py-2 rounded-lg font-bold hover:opacity-90 transition shadow-md flex items-center gap-2`}
        >
          {showForm ? 'إلغاء' : (
            <>
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" />
              </svg>
              إضافة درس جديد
            </>
          )}
        </button>
      </div>

      {showForm && (
        <div ref={formRef} className="bg-white rounded-xl shadow-lg p-6 border-t-4 border-indigo-600 animate-fadeIn relative">
          <div className="mb-6 flex justify-between items-center bg-slate-50 p-4 rounded-lg">
             <h3 className="text-xl font-bold text-indigo-900">{editingId ? 'تعديل بيانات الدرس' : 'إدخال بيانات درس جديد'}</h3>
             <div className="flex gap-2">
               {editingId && (
                 <button 
                  type="button"
                  onClick={() => { deleteLesson(editingId); setShowForm(false); resetForm(); }}
                  className="bg-red-50 text-red-600 px-3 py-1 rounded-md text-sm font-bold border border-red-100 hover:bg-red-100 transition"
                >
                  حذف هذا الدرس نهائياً
                </button>
               )}
               {editingId && <button onClick={resetForm} className="text-xs text-indigo-500 hover:underline">إلغاء التعديل</button>}
             </div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">عنوان الدرس / الموضوع</label>
                  <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full px-4 py-3 border-2 border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition-all outline-none text-lg"
                    placeholder="أدخل عنوان الدرس هنا..."
                  />
                </div>

                <div>
                  <div className="flex justify-between items-center mb-2">
                    <label className="text-sm font-bold text-gray-700">استراتيجيات التدريس (الحد الأقصى 10)</label>
                    <button
                      type="button"
                      onClick={handleSuggest}
                      disabled={loadingSuggestions}
                      className="text-xs text-indigo-600 font-bold hover:underline flex items-center gap-1 bg-indigo-50 px-2 py-1 rounded"
                    >
                      {loadingSuggestions ? 'جاري التحميل...' : '🤖 اقتراحات الذكاء الاصطناعي'}
                    </button>
                  </div>
                  <div className="space-y-4 max-h-[500px] overflow-y-auto p-1 scrollbar-thin scrollbar-thumb-indigo-200 bg-slate-50 rounded-xl p-3 border">
                    {strategies.map((strat, idx) => (
                      <div key={idx} className="p-3 border rounded-lg bg-white shadow-sm space-y-2 relative group">
                        <div className="flex gap-2">
                          <input
                            type="text"
                            value={strat.text}
                            onChange={(e) => updateStrategyText(idx, e.target.value)}
                            className="flex-1 px-3 py-2 text-sm border-0 bg-slate-50 rounded-lg focus:ring-1 focus:ring-indigo-300 outline-none"
                            placeholder={`الاستراتيجية رقم ${idx + 1}`}
                          />
                          {strategies.length > 1 && (
                            <button
                              type="button"
                              onClick={() => handleRemoveStrategy(idx)}
                              className="text-red-400 hover:text-red-600 p-1"
                              title="حذف الاستراتيجية"
                            >
                              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                              </svg>
                            </button>
                          )}
                        </div>

                        <div className="flex flex-wrap gap-2 items-center">
                          {!strat.attachment ? (
                            <div className="flex gap-2 w-full overflow-x-auto pb-1">
                              <label className="cursor-pointer bg-slate-50 border border-slate-200 px-2 py-1.5 rounded-lg text-[10px] hover:bg-indigo-50 hover:border-indigo-200 flex items-center gap-1 transition-colors whitespace-nowrap">
                                <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileChange(idx, 'image', e)} />
                                🖼️ صورة
                              </label>
                              <label className="cursor-pointer bg-slate-50 border border-slate-200 px-2 py-1.5 rounded-lg text-[10px] hover:bg-indigo-50 hover:border-indigo-200 flex items-center gap-1 transition-colors whitespace-nowrap">
                                <input type="file" accept="video/*" className="hidden" onChange={(e) => handleFileChange(idx, 'video', e)} />
                                🎥 فيديو
                              </label>
                              <label className="cursor-pointer bg-slate-50 border border-slate-200 px-2 py-1.5 rounded-lg text-[10px] hover:bg-indigo-50 hover:border-indigo-200 flex items-center gap-1 transition-colors whitespace-nowrap">
                                <input type="file" className="hidden" onChange={(e) => handleFileChange(idx, 'file', e)} />
                                📄 ملف
                              </label>
                              <button
                                type="button"
                                onClick={() => handleAddLink(idx)}
                                className="bg-slate-50 border border-slate-200 px-2 py-1.5 rounded-lg text-[10px] hover:bg-indigo-50 hover:border-indigo-200 flex items-center gap-1 transition-colors whitespace-nowrap"
                              >
                                🔗 إضافة رابط
                              </button>
                            </div>
                          ) : (
                            <div className="flex items-center gap-2 bg-indigo-50 px-3 py-1.5 rounded-lg border border-indigo-100 w-full justify-between">
                              <span className="text-xs text-indigo-700 font-bold truncate">
                                {strat.attachment.type === 'link' ? '🔗' : strat.attachment.type === 'image' ? '🖼️' : strat.attachment.type === 'video' ? '🎥' : '📄'} 
                                {strat.attachment.name}
                              </span>
                              <button type="button" onClick={() => removeAttachment(idx)} className="text-red-500 hover:text-red-700 p-1" title="حذف المرفق">
                                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                                </svg>
                              </button>
                            </div>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                  {strategies.length < 10 && (
                    <button
                      type="button"
                      onClick={handleAddStrategy}
                      className="mt-3 text-sm text-indigo-600 hover:text-indigo-800 font-bold flex items-center gap-1 bg-white border border-indigo-200 px-4 py-2 rounded-lg shadow-sm w-full justify-center hover:bg-indigo-50 transition"
                    >
                      + إضافة استراتيجية جديدة
                    </button>
                  )}
                </div>
              </div>

              <div className="space-y-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3">تنمية مهارات التعلم الذاتي</label>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {[
                      { key: 'thinking', label: 'مهارات التفكير' },
                      { key: 'collaboration', label: 'التعاون والمشاركة' },
                      { key: 'criticalThinking', label: 'التفكير النقدي' },
                      { key: 'higherOrderThinking', label: 'التفكير العليا والواقع' }
                    ].map((skill) => (
                      <label key={skill.key} className={`flex items-center gap-3 p-3 border-2 rounded-xl transition-all cursor-pointer ${selfLearning[skill.key as keyof typeof selfLearning] ? 'bg-indigo-50 border-indigo-300 shadow-sm' : 'bg-white border-slate-100 hover:border-slate-200'}`}>
                        <input
                          type="checkbox"
                          checked={selfLearning[skill.key as keyof typeof selfLearning]}
                          onChange={(e) => setSelfLearning({ ...selfLearning, [skill.key]: e.target.checked })}
                          className="w-5 h-5 text-indigo-600 border-gray-300 rounded focus:ring-indigo-500"
                        />
                        <span className="text-sm font-medium text-gray-700">{skill.label}</span>
                      </label>
                    ))}
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-2">آلية توظيف الاستراتيجيات المذكورة</label>
                  <textarea
                    rows={3}
                    value={deployment}
                    onChange={(e) => setDeployment(e.target.value)}
                    className="w-full px-4 py-3 border-2 border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                    placeholder="اشرح باختصار كيف سيتم تطبيق الاستراتيجيات في الدرس..."
                  />
                </div>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-4 border-t border-slate-100">
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">أساليب التقويم المتنوعة</label>
                <textarea
                  rows={2}
                  value={evaluations}
                  onChange={(e) => setEvaluations(e.target.value)}
                  className="w-full px-4 py-3 border-2 border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                  placeholder="الاختبارات القصيرة، الملاحظة، بطاقات التقويم..."
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">القيم والاتجاهات والمواطنة المكتسبة</label>
                <textarea
                  rows={2}
                  value={values}
                  onChange={(e) => setValues(e.target.value)}
                  className="w-full px-4 py-3 border-2 border-slate-100 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none text-sm"
                  placeholder="ما هي القيم التربوية التي يهدف الدرس لتعزيزها؟"
                />
              </div>
            </div>

            <div className="flex justify-end gap-4 pt-6">
              <button
                type="submit"
                className="bg-indigo-600 text-white px-10 py-4 rounded-xl font-black text-lg hover:bg-indigo-700 transition shadow-xl active:scale-95 flex items-center gap-2"
              >
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 13l4 4L19 7" />
                </svg>
                {editingId ? 'تحديث كافة البيانات' : 'حفظ ونشر الدرس'}
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Lessons List View */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {lessons.length === 0 ? (
          <div className="col-span-full text-center py-24 bg-white rounded-2xl border-2 border-dashed border-slate-200">
            <div className="text-slate-300 mb-4 flex justify-center">
               <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                 <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
               </svg>
            </div>
            <p className="text-slate-500 font-bold text-xl">لا توجد دروس مسجلة حالياً</p>
            <p className="text-slate-400 mt-2">ابدأ بإضافة أول درس لك باستخدام الزر في الأعلى</p>
          </div>
        ) : (
          lessons.map((lesson) => (
            <div key={lesson.id} className="bg-white rounded-2xl shadow-md overflow-hidden hover:shadow-xl transition-all border border-slate-100 flex flex-col group animate-fadeIn">
              <div className="bg-gradient-to-l from-indigo-50 to-white p-5 border-b flex justify-between items-start">
                <div className="max-w-[75%]">
                  <h3 className="text-xl font-extrabold text-indigo-950 truncate" title={lesson.title}>{lesson.title}</h3>
                  <div className="flex items-center gap-1 mt-1">
                    <svg className="w-3.5 h-3.5 text-indigo-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z" />
                    </svg>
                    <span className="text-xs text-indigo-400 font-medium">{lesson.createdAt}</span>
                  </div>
                </div>
                <div className="flex gap-1.5">
                   <button 
                    onClick={() => handleEdit(lesson)}
                    className="p-2 text-indigo-600 bg-indigo-50 hover:bg-indigo-100 rounded-xl transition-all shadow-sm"
                    title="تعديل الدرس"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                    </svg>
                  </button>
                  <button 
                    onClick={() => deleteLesson(lesson.id)}
                    className="p-2 text-red-500 bg-red-50 hover:bg-red-100 rounded-xl transition-all shadow-sm"
                    title="حذف الدرس"
                  >
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                    </svg>
                  </button>
                </div>
              </div>
              <div className="p-5 space-y-4 flex-1">
                <div className="flex items-center gap-2">
                  <span className="px-3 py-1 bg-amber-50 text-amber-700 text-xs rounded-full font-black border border-amber-100">
                    {lesson.strategiesCount} استراتيجيات
                  </span>
                  {lesson.strategies.some(s => s.attachment) && (
                     <span className="px-3 py-1 bg-green-50 text-green-700 text-xs rounded-full font-black border border-green-100">
                      يحتوي مرفقات
                    </span>
                  )}
                </div>

                <div className="text-sm text-slate-600">
                  <p className="font-bold text-slate-800 mb-1">التقويم:</p>
                  <p className="line-clamp-2 italic text-xs leading-relaxed">{lesson.evaluationMethods || 'لم يتم إدخال أساليب تقويم'}</p>
                </div>

                <div className="flex flex-wrap gap-1.5 mt-auto">
                   {Object.entries(lesson.selfLearningSkills)
                     .filter(([_, active]) => active)
                     .map(([key]) => (
                       <span key={key} className="text-[10px] bg-slate-100 text-slate-700 px-2 py-1 rounded-lg border border-slate-200 font-bold">
                         {key === 'thinking' ? 'تفكير' : key === 'collaboration' ? 'تعاون' : key === 'criticalThinking' ? 'نقد' : 'تفكير عليا'}
                       </span>
                     ))}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default TeacherDashboard;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ lessons }) => {
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);

  // Group lessons by teacher
  const teachers = useMemo(() => {
    const map = new Map<string, { id: string; name: string; lessonCount: number }>();
    lessons.forEach(l => {
      if (!map.has(l.teacherId)) {
        map.set(l.teacherId, { id: l.teacherId, name: l.teacherName, lessonCount: 0 });
      }
      map.get(l.teacherId)!.lessonCount++;
    });
    return Array.from(map.values());
  }, [lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return null;
    const { type, url, name } = strategy.attachment;

    switch (type) {
      case 'image':
        return (
          <div className="mt-3 group relative inline-block">
            <img 
              src={url} 
              alt={name} 
              className="max-h-52 rounded-xl border-2 border-white shadow-md cursor-zoom-in hover:scale-[1.02] transition-transform" 
              onClick={() => window.open(url)} 
            />
            <div className="absolute top-2 right-2 bg-black/60 text-white text-[10px] px-2 py-1 rounded-full backdrop-blur-sm opacity-0 group-hover:opacity-100 transition-opacity">
              عرض كامل
            </div>
            {name && <p className="text-[10px] text-slate-400 mt-1 mr-1">{name}</p>}
          </div>
        );
      case 'video':
        return (
          <div className="mt-3">
            <video src={url} controls className="max-h-72 w-full rounded-xl border-2 border-white shadow-md bg-black" />
            <p className="text-[10px] text-slate-400 mt-2 mr-1">{name}</p>
          </div>
        );
      case 'link':
        // The URL is already formatted in the teacher dashboard
        return (
          <div className="mt-3">
            <a 
              href={url} 
              target="_blank" 
              rel="noopener noreferrer" 
              className="inline-flex items-center gap-3 text-sm text-white bg-indigo-600 hover:bg-indigo-700 px-5 py-2.5 rounded-xl font-black shadow-lg shadow-indigo-200 transition-all active:scale-95 hover:-translate-y-0.5"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 6H6a2 2 0 00-2 2v10a2 2 0 002 2h10a2 2 0 002-2v-4M14 4h6m0 0v6m0-6L10 14" />
              </svg>
              مشاهدة المرفق الخارجي (رابط)
            </a>
            <div className="mt-1 text-[10px] text-indigo-400 font-medium truncate max-w-xs">{url}</div>
          </div>
        );
      case 'file':
        return (
          <div className="mt-3">
            <a 
              href={url} 
              download={name} 
              className="inline-flex items-center gap-3 text-sm text-white bg-green-600 hover:bg-green-700 px-5 py-2.5 rounded-xl font-black shadow-lg shadow-green-200 transition-all active:scale-95 hover:-translate-y-0.5"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
              </svg>
              تحميل الملف المرفق
            </a>
            <p className="text-[10px] text-green-500 mt-1 font-bold">{name}</p>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
      {/* Teachers List Sidebar */}
      <div className="lg:col-span-1 bg-white rounded-2xl shadow-xl p-5 space-y-4 border border-slate-100">
        <h2 className="text-xl font-black text-slate-800 border-b-2 border-indigo-50 pb-3 mb-4">قائمة المعلمين</h2>
        <div className="space-y-3 overflow-y-auto max-h-[70vh] pr-1">
          {teachers.length === 0 ? (
            <div className="text-center py-10">
              <div className="bg-slate-50 w-12 h-12 rounded-full flex items-center justify-center mx-auto mb-3">
                 <svg className="w-6 h-6 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" />
                 </svg>
              </div>
              <p className="text-slate-400 text-sm">لا يوجد معلمين مسجلين</p>
            </div>
          ) : (
            teachers.map((teacher) => (
              <button
                key={teacher.id}
                onClick={() => {
                  setSelectedTeacherId(teacher.id);
                  setSelectedLessonId(null);
                }}
                className={`w-full text-right p-4 rounded-xl transition-all border-2 group ${
                  selectedTeacherId === teacher.id
                    ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg shadow-indigo-100 scale-[1.02]'
                    : 'bg-white border-slate-50 text-slate-700 hover:border-indigo-100 hover:bg-indigo-50/30'
                }`}
              >
                <div className="font-extrabold text-lg leading-tight">{teacher.name}</div>
                <div className={`text-xs mt-1 font-bold ${selectedTeacherId === teacher.id ? 'text-indigo-100' : 'text-slate-400'}`}>
                  {teacher.lessonCount} دروس موثقة
                </div>
              </button>
            ))
          )}
        </div>
      </div>

      {/* Main View Area */}
      <div className="lg:col-span-3 space-y-6">
        {!selectedTeacherId ? (
          <div className="bg-white rounded-2xl shadow-xl p-24 text-center space-y-6 border-2 border-dashed border-slate-200 animate-fadeIn">
            <div className="w-24 h-24 bg-indigo-50 rounded-full flex items-center justify-center mx-auto text-indigo-500 animate-pulse">
              <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" />
              </svg>
            </div>
            <div>
              <h3 className="text-2xl font-black text-slate-800">مرحباً بك في نظام متابعة الزيارات</h3>
              <p className="text-slate-500 mt-2 max-w-md mx-auto text-lg">يرجى اختيار أحد المعلمين من القائمة الجانبية لاستعراض خططهم الدراسية وتقارير الزيارات الخاصة بهم</p>
