                >
                  <div className="bg-amber-100 text-amber-800 text-[10px] font-black px-2 py-0.5 rounded-full inline-block mb-2">وثيقة درس</div>
                  <h4 className="font-extrabold text-slate-900 text-lg leading-snug line-clamp-2">{lesson.title}</h4>
                  <p className="text-xs text-slate-400 mt-2 font-medium">{lesson.createdAt}</p>
                </button>
