export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  code: string;
  password?: string;
}

export type AttachmentType = 'link' | 'image' | 'video' | 'file';

export interface Strategy {
  text: string;
  attachment?: {
    type: AttachmentType;
    url: string;
    name?: string;
  };
}

export interface Lesson {
  id: string;
  teacherId: string;
  teacherName: string;
  title: string;
  strategiesCount: number;
  strategies: Strategy[];
  selfLearningSkills: {
    thinking: boolean;
    collaboration: boolean;
    criticalThinking: boolean;
    higherOrderThinking: boolean;
  };
  effectiveStrategiesDeployment: string;
  evaluationMethods: string;
  valuesAndCitizenship: string;
  createdAt: string;
  status?: 'pending' | 'confirmed';
  supervisorNotes?: string;
  observationalNotes?: string; // New field for specific observational feedback
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState } from 'react';
import { UserRole, User } from '../types';

interface LoginFormProps {
  onLogin: (user: User) => void;
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin }) => {
  const [code, setCode] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanCode = code.trim();
    const cleanPass = password.trim();

    if (!cleanCode || !cleanPass) {
      setError('يرجى إدخال رقم التعريف وكلمة المرور');
      return;
    }

    // Validation logic:
    // For demo purposes: Password is "pass" + code
    const expectedPassword = cleanCode.toUpperCase().startsWith('S') || cleanCode.startsWith('99') 
      ? `admin${cleanCode}` 
      : `pass${cleanCode}`;

    if (cleanPass !== expectedPassword) {
      setError('كلمة المرور غير صحيحة لهذه الهوية');
      return;
    }

    let role = UserRole.TEACHER;
    let name = `معلم (${cleanCode})`;

    if (cleanCode.toUpperCase().startsWith('S') || cleanCode.startsWith('99')) {
      role = UserRole.SUPERVISOR;
      name = `مشرف (${cleanCode})`;
    }

    onLogin({
      id: cleanCode,
      name: name,
      role,
      code: cleanCode,
      password: cleanPass
    });
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 font-['Tajawal']">
      <div className="max-w-md w-full bg-white rounded-3xl shadow-xl p-10 space-y-8 border border-slate-100">
        <div className="text-center">
          <div className="w-20 h-20 bg-indigo-600 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-indigo-100 rotate-3 group hover:rotate-0 transition-transform duration-300">
             <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
             </svg>
          </div>
          <h1 className="text-3xl font-black text-slate-900 mb-2">منصة المجال الأول</h1>
          <p className="text-slate-500 font-medium">تسجيل الدخول للنظام</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <label className="block text-sm font-bold text-slate-700 mr-1">رقم التعريف الوظيفي</label>
            <input
              type="text"
              required
              value={code}
              onChange={(e) => { setCode(e.target.value); setError(''); }}
              className="w-full px-6 py-3 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-center font-bold"
              placeholder="أدخل الكود"
            />
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-bold text-slate-700 mr-1">كلمة المرور</label>
            <input
              type="password"
              required
              value={password}
              onChange={(e) => { setPassword(e.target.value); setError(''); }}
              className="w-full px-6 py-3 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-center font-bold"
              placeholder="••••••••"
            />
          </div>

          {error && <p className="text-red-500 text-xs font-bold text-center mt-2 bg-red-50 py-2 rounded-lg">{error}</p>}

          <button
            type="submit"
            className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black text-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 mt-4 active:scale-95"
          >
            دخول
          </button>
        </form>

        <div className="bg-amber-50 rounded-2xl p-4 border border-amber-100">
           <p className="text-[10px] text-amber-800 font-bold text-center leading-relaxed">
             * ملاحظة للمعلمين: كلمة المرور هي pass متبوعة بالكود (مثال: pass123456)
             <br/>
             * ملاحظة للمشرفين: كلمة المرور هي admin متبوعة بالكود (مثال: adminS123)
           </p>
        </div>
      </div>
    </div>
  );
};

