import React, { useState, useMemo } from 'react';
import { Lesson, Strategy, UserRole } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
  updateLesson: (lesson: Lesson) => void;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ lessons, updateLesson }) => {
  const [view, setView] = useState<'lessons' | 'users'>('lessons');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);
  const [obsNoteInput, setObsNoteInput] = useState('');

  // Group lessons by teacher
  const teachers = useMemo(() => {
    const map = new Map<string, { id: string; name: string; lessonCount: number; code: string; passwordHint: string }>();
    lessons.forEach(l => {
      if (!map.has(l.teacherId)) {
        map.set(l.teacherId, { 
          id: l.teacherId, 
          name: l.teacherName, 
          lessonCount: 0,
          code: l.teacherId,
          passwordHint: `pass${l.teacherId}`
        });
      }
      map.get(l.teacherId)!.lessonCount++;
    });
    return Array.from(map.values());
  }, [lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const handleConfirmVisit = () => {
    if (activeLesson) {
      const updated = { ...activeLesson, status: 'confirmed' as const };
      updateLesson(updated);
      alert('تم اعتماد توثيق الزيارة بنجاح');
    }
  };

  const handleSaveObsNote = () => {
    if (activeLesson && obsNoteInput.trim()) {
      const updated = { ...activeLesson, observationalNotes: obsNoteInput };
      updateLesson(updated);
      setObsNoteInput('');
      alert('تم حفظ ملحوظة المشاهدة');
    }
  };

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return null;
    const { type, url, name } = strategy.attachment;
    switch (type) {
      case 'image':
        return <img src={url} alt={name} className="max-h-40 rounded-lg border mt-2 shadow-sm" onClick={() => window.open(url)} />;
      case 'video':
        return <video src={url} controls className="max-h-40 w-full rounded-lg border mt-2" />;
      case 'link':
        return <a href={url} target="_blank" rel="noopener noreferrer" className="inline-block mt-2 text-indigo-600 font-bold bg-indigo-50 px-3 py-1 rounded-lg">🔗 فتح الرابط التعليمي</a>;
      case 'file':
        return <a href={url} download={name} className="inline-block mt-2 text-green-600 font-bold bg-green-50 px-3 py-1 rounded-lg">📄 تحميل الملف</a>;
      default: return null;
    }
  };

  if (view === 'users') {
    return (
      <div className="space-y-6 animate-fadeIn">
        <div className="flex justify-between items-center bg-white p-6 rounded-2xl shadow-md border-b-4 border-amber-500">
          <h2 className="text-2xl font-black text-slate-800">إدارة حسابات المعلمين</h2>
          <button onClick={() => setView('lessons')} className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold shadow-lg shadow-indigo-100">العودة لمراجعة الدروس</button>
        </div>

        <div className="bg-white rounded-3xl shadow-xl overflow-hidden border border-slate-100">
          <table className="w-full text-right border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b">
                <th className="p-4 font-black text-slate-600">اسم المعلم</th>
                <th className="p-4 font-black text-slate-600 text-center">رقم التعريف (Username)</th>
                <th className="p-4 font-black text-slate-600 text-center">كلمة المرور (Password)</th>
                <th className="p-4 font-black text-slate-600 text-center">عدد الدروس</th>
              </tr>
            </thead>
            <tbody>
              {teachers.length === 0 ? (
                <tr><td colSpan={4} className="p-10 text-center text-slate-400 font-bold">لا يوجد معلمين مسجلين حالياً</td></tr>
              ) : (
                teachers.map(t => (
                  <tr key={t.id} className="border-b hover:bg-slate-50 transition-colors">
                    <td className="p-4 font-bold text-slate-800">{t.name}</td>
                    <td className="p-4 text-center"><code className="bg-slate-100 px-3 py-1 rounded-lg font-mono font-bold text-indigo-600">{t.code}</code></td>
                    <td className="p-4 text-center"><code className="bg-amber-50 px-3 py-1 rounded-lg font-mono font-bold text-amber-700">{t.passwordHint}</code></td>
                    <td className="p-4 text-center"><span className="bg-slate-100 px-3 py-1 rounded-full text-xs font-black">{t.lessonCount} دروس</span></td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
        <div className="bg-blue-50 p-6 rounded-2xl border border-blue-100">
          <p className="text-sm text-blue-800 font-bold">💡 ملاحظة إرشادية: النظام يولد كلمات المرور تلقائياً للمعلمين بناءً على أرقامهم الوظيفية لضمان سهولة الوصول.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
      {/* Sidebar */}
      <div className="lg:col-span-1 bg-white rounded-2xl shadow-xl p-5 space-y-4 border border-slate-100">
        <div className="flex flex-col gap-2 mb-4">
          <h2 className="text-xl font-black text-slate-800 border-b-2 border-indigo-50 pb-3">قائمة المعلمين</h2>
          <button 
            onClick={() => setView('users')}
            className="w-full text-sm bg-amber-500 text-white py-2 rounded-xl font-black shadow-md hover:bg-amber-600 transition"
          >
            إدارة الحسابات ⚙️
          </button>
        </div>

        <div className="space-y-3 overflow-y-auto max-h-[60vh]">
          {teachers.map((teacher) => (
            <button
              key={teacher.id}
              onClick={() => { setSelectedTeacherId(teacher.id); setSelectedLessonId(null); }}
              className={`w-full text-right p-4 rounded-xl transition-all border-2 ${
                selectedTeacherId === teacher.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-50 text-slate-700 hover:bg-indigo-50/30'
              }`}
            >
              <div className="font-extrabold text-lg leading-tight">{teacher.name}</div>
              <div className={`text-xs mt-1 font-bold ${selectedTeacherId === teacher.id ? 'text-indigo-100' : 'text-slate-400'}`}>
                {teacher.lessonCount} دروس موثقة
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Main Area */}
      <div className="lg:col-span-3 space-y-6">
        {!selectedTeacherId ? (
          <div className="bg-white rounded-2xl shadow-xl p-24 text-center space-y-6 border-2 border-dashed border-slate-200 animate-fadeIn">
            <div className="w-24 h-24 bg-indigo-50 rounded-full flex items-center justify-center mx-auto text-indigo-500">
              <svg className="w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2" /></svg>
            </div>
            <h3 className="text-2xl font-black text-slate-800">مرحباً بك في نظام متابعة الزيارات</h3>
            <p className="text-slate-500 max-w-md mx-auto">اختر معلماً للبدء بمراجعة توثيق دروسه</p>
          </div>
        ) : (
          <div className="space-y-6 animate-fadeIn">
            <div className="bg-white p-5 rounded-2xl shadow-md border-r-8 border-indigo-600 flex justify-between items-center">
              <h2 className="text-2xl font-black text-slate-900">سجل المعلم: {teachers.find(t => t.id === selectedTeacherId)?.name}</h2>
              <button onClick={() => setSelectedTeacherId(null)} className="text-indigo-600 font-bold hover:underline">إغلاق السجل</button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {teacherLessons.map(lesson => (
                <button
                  key={lesson.id}
                  onClick={() => setSelectedLessonId(lesson.id)}
                  className={`text-right p-5 rounded-2xl border-2 transition-all relative ${
                    selectedLessonId === lesson.id ? 'bg-amber-50 border-amber-400 shadow-lg scale-[1.03]' : 'bg-white border-slate-50 hover:border-indigo-200'
                  }`}
                >
                  {lesson.status === 'confirmed' && <div className="absolute -top-2 -left-2 bg-green-500 text-white p-1 rounded-full shadow-lg border-2 border-white">✓</div>}
                  <h4 className="font-extrabold text-slate-900 text-lg">{lesson.title}</h4>
                  <p className="text-xs text-slate-400 mt-2">{lesson.createdAt}</p>
                </button>
              ))}
            </div>

            {activeLesson && (
              <div className="bg-white rounded-3xl shadow-2xl p-8 animate-slideUp border border-slate-100 space-y-10">
                <div className="flex justify-between items-start border-b pb-6">
                  <div>
                    <h3 className="text-3xl font-black text-indigo-900">{activeLesson.title}</h3>
                    <p className="text-sm text-slate-500 mt-2">تاريخ التوثيق: {activeLesson.createdAt}</p>
                  </div>
                  <div className="flex gap-2">
                    {activeLesson.status === 'confirmed' && <span className="bg-green-100 text-green-800 px-6 py-2 rounded-2xl text-sm font-black">معتمد</span>}
                    <span className="bg-indigo-600 text-white px-6 py-2 rounded-2xl text-sm font-black">{activeLesson.strategiesCount} استراتيجيات</span>
                  </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                  <div className="space-y-8">
                    {/* Observational Notes Box - Specifically requested */}
                    <div className="bg-slate-50 p-6 rounded-2xl border-2 border-indigo-200 shadow-sm">
                      <h4 className="font-black text-indigo-900 mb-4 flex items-center gap-2">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                        صندوق ملحوظات المشاهدة الإشرافية
                      </h4>
                      {activeLesson.observationalNotes ? (
                        <div className="bg-white p-4 rounded-xl border border-indigo-100 text-slate-700 font-bold italic mb-4">
                          {activeLesson.observationalNotes}
                        </div>
                      ) : (
                        <p className="text-xs text-slate-400 mb-3 font-bold italic">لا توجد ملحوظات مشاهدة لهذا الدرس حالياً.</p>
                      )}
                      <textarea 
                        value={obsNoteInput}
                        onChange={(e) => setObsNoteInput(e.target.value)}
                        placeholder="اكتب هنا الملحوظات التي شاهدتها خلال الزيارة الصفية..."
                        className="w-full p-4 rounded-xl border-2 border-white focus:border-indigo-300 outline-none text-sm min-h-[100px] shadow-inner"
                      />
                      <button 
                        onClick={handleSaveObsNote}
                        className="mt-3 bg-indigo-500 text-white px-6 py-2 rounded-xl text-sm font-black hover:bg-indigo-600 transition"
                      >
                        حفظ ملحوظة المشاهدة
                      </button>
                    </div>

                    <div className="space-y-4">
                      <h4 className="font-black text-slate-800 text-lg">الاستراتيجيات والمرفقات</h4>
                      {activeLesson.strategies.map((s, i) => (
                        <div key={i} className="bg-white p-5 rounded-2xl border-2 border-slate-50 shadow-sm">
                          <div className="font-extrabold text-slate-900">{i+1}. {s.text}</div>
                          {renderAttachment(s)}
                        </div>
                      ))}
                    </div>
                  </div>

                  <div className="space-y-6">
                    <div className="bg-slate-50 p-6 rounded-2xl">
                      <h4 className="font-black text-indigo-950 mb-3 text-sm">وصف توظيف الاستراتيجيات:</h4>
                      <p className="text-slate-700 leading-relaxed font-bold bg-white p-4 rounded-xl">{activeLesson.effectiveStrategiesDeployment || 'لم يحدد'}</p>
                    </div>
                    <div className="bg-emerald-50 p-6 rounded-2xl">
                      <h4 className="font-black text-emerald-950 mb-3 text-sm">أساليب ومناشط التقويم:</h4>
                      <p className="text-slate-700 leading-relaxed font-bold bg-white p-4 rounded-xl">{activeLesson.evaluationMethods || 'لم يحدد'}</p>
                    </div>
                    <div className="bg-amber-50 p-6 rounded-2xl">
                      <h4 className="font-black text-amber-950 mb-3 text-sm">القيم والاتجاهات:</h4>
                      <p className="text-slate-700 leading-relaxed font-bold bg-white p-4 rounded-xl">{activeLesson.valuesAndCitizenship || 'لم يحدد'}</p>
                    </div>
                  </div>
                </div>

                <div className="pt-8 border-t flex flex-wrap justify-end gap-4">
                  <button onClick={() => {
                    const directive = prompt('أدخل التوجيه الفني المباشر للمعلم:', activeLesson.supervisorNotes || '');
                    if (directive !== null) updateLesson({ ...activeLesson, supervisorNotes: directive });
                  }} className="bg-slate-800 text-white px-8 py-3.5 rounded-2xl font-black flex items-center gap-2">
                    📢 إرسال توجيهات فنية
                  </button>
                  {activeLesson.status !== 'confirmed' && (
                    <button onClick={handleConfirmVisit} className="bg-indigo-600 text-white px-10 py-3.5 rounded-2xl font-black shadow-lg shadow-indigo-100 active:scale-95">
                      ✓ اعتماد توثيق الزيارة
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default SupervisorDashboard;

import React, { useState, useRef } from 'react';
import { User, Lesson, Strategy, AttachmentType } from '../types';
import { suggestStrategies } from '../services/geminiService';

interface TeacherDashboardProps {
  user: User;
  addLesson: (lesson: Lesson) => void;
  deleteLesson: (id: string) => void;
  updateLesson: (lesson: Lesson) => void;
  lessons: Lesson[];
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ user, addLesson, deleteLesson, updateLesson, lessons }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const formRef = useRef<HTMLDivElement>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [strategies, setStrategies] = useState<Strategy[]>([{ text: '' }]);
  const [selfLearning, setSelfLearning] = useState({
    thinking: false,
    collaboration: false,
    criticalThinking: false,
    higherOrderThinking: false,
  });
  const [deployment, setDeployment] = useState('');
  const [evaluations, setEvaluations] = useState('');
  const [values, setValues] = useState('');

  const handleAddStrategy = () => {
    if (strategies.length < 10) {
      setStrategies([...strategies, { text: '' }]);
    }
  };

  const handleRemoveStrategy = (index: number) => {
    const newStrats = strategies.filter((_, i) => i !== index);
    setStrategies(newStrats);
  };

  const updateStrategyText = (index: number, val: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], text: val };
    setStrategies(newStrats);
  };

  const setStrategyAttachment = (index: number, type: AttachmentType, url: string, name?: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], attachment: { type, url, name: name || 'مرفق' } };
    setStrategies(newStrats);
  };

  const removeAttachment = (index: number) => {
    const newStrats = [...strategies];
    delete newStrats[index].attachment;
    setStrategies(newStrats);
  };

  const handleFileChange = (index: number, type: AttachmentType, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setStrategyAttachment(index, type, reader.result as string, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddLink = (index: number) => {
    const url = prompt('يرجى إدخال رابط الموقع (مثال: https://google.com):');
    if (url && url.trim()) {
      let formattedUrl = url.trim();
      if (!formattedUrl.startsWith('http')) {
        formattedUrl = 'https://' + formattedUrl;
      }
      setStrategyAttachment(index, 'link', formattedUrl, 'رابط تعليمي');
    }
  };

  const handleSuggest = async () => {
    if (!title) return alert('يرجى كتابة عنوان الدرس أولاً');
    setLoadingSuggestions(true);
    const suggested = await suggestStrategies(title);
    setStrategies(suggested.slice(0, 10).map(s => ({ text: s })));
    setLoadingSuggestions(false);
  };

  const handleEdit = (lesson: Lesson) => {
    setEditingId(lesson.id);
    setTitle(lesson.title);
    setStrategies(lesson.strategies.length > 0 ? lesson.strategies : [{ text: '' }]);
    setSelfLearning(lesson.selfLearningSkills);
    setDeployment(lesson.effectiveStrategiesDeployment);
    setEvaluations(lesson.evaluationMethods);
    setValues(lesson.valuesAndCitizenship);
    setShowForm(true);
    setTimeout(() => {
      formRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalStrategies = strategies.filter(s => s.text.trim() !== '');

    const lessonData: Lesson = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      teacherId: user.id,
      teacherName: user.name,
      title,
      strategiesCount: finalStrategies.length,
      strategies: finalStrategies,
      selfLearningSkills: selfLearning,
      effectiveStrategiesDeployment: deployment,
      evaluationMethods: evaluations,
      valuesAndCitizenship: values,
      createdAt: editingId ? (lessons.find(l => l.id === editingId)?.createdAt || new Date().toLocaleDateString('ar-SA')) : new Date().toLocaleDateString('ar-SA'),
      status: editingId ? lessons.find(l => l.id === editingId)?.status : 'pending',
      supervisorNotes: editingId ? lessons.find(l => l.id === editingId)?.supervisorNotes : undefined,
      observationalNotes: editingId ? lessons.find(l => l.id === editingId)?.observationalNotes : undefined
    };

    if (editingId) {
      updateLesson(lessonData);
    } else {
      addLesson(lessonData);
    }

    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setEditingId(null);
    setTitle('');
    setStrategies([{ text: '' }]);
    setSelfLearning({
      thinking: false,
      collaboration: false,
      criticalThinking: false,
      higherOrderThinking: false,
    });
    setDeployment('');
    setEvaluations('');
    setValues('');
  };

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">قائمة الدروس الموثقة</h2>
          <p className="text-gray-500">متابعة الزيارات الإشرافية وحالة الاعتماد</p>
        </div>
        <button
          onClick={() => { if (showForm) resetForm(); setShowForm(!showForm); }}
          className={`${showForm ? 'bg-slate-500' : 'bg-indigo-600'} text-white px-6 py-2 rounded-lg font-bold hover:opacity-90 transition shadow-md flex items-center gap-2`}
        >
          {showForm ? 'إلغاء' : '+ إضافة درس جديد'}
        </button>
      </div>

      {showForm && (
        <div ref={formRef} className="bg-white rounded-xl shadow-lg p-6 border-t-4 border-indigo-600 animate-fadeIn relative">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-1">عنوان الدرس / الموضوع</label>
                  <input type="text" required value={title} onChange={(e) => setTitle(e.target.value)} className="w-full px-4 py-3 border-2 border-slate-100 rounded-xl focus:border-indigo-500 outline-none font-bold" />
                </div>
                <div>
                  <div className="flex justify-between items-center mb-2">
                    <label className="text-sm font-bold text-gray-700">الاستراتيجيات (الحد الأقصى 10)</label>
                    <button type="button" onClick={handleSuggest} className="text-xs text-indigo-600 font-bold bg-indigo-50 px-2 py-1 rounded">🤖 اقتراحات</button>
                  </div>
                  <div className="space-y-3 bg-slate-50 p-4 rounded-xl border max-h-[400px] overflow-y-auto">
                    {strategies.map((strat, idx) => (
                      <div key={idx} className="bg-white p-3 rounded-lg border shadow-sm space-y-2">
                        <input type="text" value={strat.text} onChange={(e) => updateStrategyText(idx, e.target.value)} className="w-full text-sm border-0 bg-slate-50 rounded p-2 focus:ring-1 focus:ring-indigo-300 outline-none" />
                        <div className="flex gap-2">
                           {!strat.attachment ? (
                             <>
                               <label className="cursor-pointer bg-slate-100 px-2 py-1 rounded text-[10px] font-bold">📂 ملف<input type="file" className="hidden" onChange={(e) => handleFileChange(idx, 'file', e)} /></label>
                               <button type="button" onClick={() => handleAddLink(idx)} className="bg-slate-100 px-2 py-1 rounded text-[10px] font-bold">🔗 رابط</button>
                             </>
                           ) : (
                             <div className="flex items-center gap-2 text-[10px] font-bold text-indigo-600">📎 {strat.attachment.name} <button type="button" onClick={() => removeAttachment(idx)} className="text-red-500">×</button></div>
                           )}
                        </div>
                      </div>
                    ))}
                    {strategies.length < 10 && <button type="button" onClick={handleAddStrategy} className="text-xs font-bold text-indigo-600 hover:underline">+ استراتيجية أخرى</button>}
                  </div>
                </div>
              </div>
              <div className="space-y-6">
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-3">مهارات التعلم الذاتي</label>
                  <div className="grid grid-cols-2 gap-3">
                    {Object.keys(selfLearning).map((key) => (
                      <label key={key} className="flex items-center gap-2 p-3 border rounded-xl cursor-pointer hover:bg-slate-50">
                        <input type="checkbox" checked={selfLearning[key as keyof typeof selfLearning]} onChange={(e) => setSelfLearning({ ...selfLearning, [key]: e.target.checked })} className="w-4 h-4 text-indigo-600" />
                        <span className="text-xs font-bold">{key === 'thinking' ? 'تفكير' : key === 'collaboration' ? 'تعاون' : key === 'criticalThinking' ? 'نقد' : 'تفكير عليا'}</span>
                      </label>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-bold text-gray-700 mb-2">آلية توظيف الاستراتيجيات</label>
                  <textarea rows={3} value={deployment} onChange={(e) => setDeployment(e.target.value)} className="w-full p-4 border-2 border-slate-100 rounded-xl outline-none text-sm" />
                </div>
              </div>
            </div>
            <div className="flex justify-end pt-4 border-t">
              <button type="submit" className="bg-indigo-600 text-white px-10 py-3 rounded-xl font-black shadow-lg">حفظ ونشر التوثيق</button>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {lessons.map((lesson) => (
          <div key={lesson.id} className="bg-white rounded-2xl shadow-md border-b-4 border-slate-100 hover:shadow-xl transition-all flex flex-col overflow-hidden">
            <div className={`p-4 text-white font-black flex justify-between items-center ${lesson.status === 'confirmed' ? 'bg-green-600' : 'bg-amber-500'}`}>
              <span className="text-xs">{lesson.status === 'confirmed' ? 'تم الاعتماد ✓' : 'بانتظار المراجعة...'}</span>
              <div className="flex gap-2">
                <button onClick={() => handleEdit(lesson)} className="hover:text-white/80">✎</button>
                <button onClick={() => deleteLesson(lesson.id)} className="hover:text-white/80">×</button>
              </div>
            </div>
            <div className="p-5 flex-1 space-y-4">
              <h3 className="text-xl font-black text-slate-800">{lesson.title}</h3>
              <p className="text-[10px] font-bold text-slate-400">التاريخ: {lesson.createdAt}</p>

              {/* Supervisor Feedback in Teacher View */}
              {(lesson.supervisorNotes || lesson.observationalNotes) && (
                <div className="space-y-2">
                  {lesson.observationalNotes && (
                    <div className="bg-indigo-50 p-3 rounded-xl border border-indigo-100">
                      <p className="text-[10px] font-black text-indigo-700">🔎 ملحوظة المشاهدة:</p>
                      <p className="text-[11px] text-slate-600 italic font-bold leading-relaxed">{lesson.observationalNotes}</p>
                    </div>
                  )}
                  {lesson.supervisorNotes && (
                    <div className="bg-amber-50 p-3 rounded-xl border border-amber-100">
                      <p className="text-[10px] font-black text-amber-700">📢 توجيه المشرف:</p>
                      <p className="text-[11px] text-slate-600 italic font-bold leading-relaxed">{lesson.supervisorNotes}</p>
                    </div>
                  )}
                </div>
              )}

              <div className="flex flex-wrap gap-1.5 pt-2">
                <span className="bg-slate-100 px-2 py-1 rounded text-[10px] font-black">⚡ {lesson.strategiesCount} استراتيجيات</span>
                {Object.entries(lesson.selfLearningSkills).filter(([_,v])=>v).map(([k]) => (
                   <span key={k} className="bg-indigo-50 text-indigo-600 px-2 py-1 rounded text-[10px] font-black border border-indigo-100">
                     {k === 'thinking' ? 'تفكير' : k === 'collaboration' ? 'تعاون' : 'نقد'}
                   </span>
                ))}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TeacherDashboard;

export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  code: string;
  password?: string;
}

export type AttachmentType = 'link' | 'image' | 'video' | 'file';

export interface Strategy {
  text: string;
  attachment?: {
    type: AttachmentType;
    url: string;
    name?: string;
  };
}

export interface Lesson {
  id: string;
  teacherId: string;
  teacherName: string;
  title: string;
  strategiesCount: number;
  strategies: Strategy[];
  selfLearningSkills: {
    thinking: boolean;
    collaboration: boolean;
    criticalThinking: boolean;
    higherOrderThinking: boolean;
  };
  effectiveStrategiesDeployment: string;
  evaluationMethods: string;
  valuesAndCitizenship: string;
  createdAt: string;
  status?: 'pending' | 'confirmed';
  supervisorNotes?: string;
  observationalNotes?: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Lesson } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [lessons, setLessons] = useState<Lesson[]>(() => {
    const saved = localStorage.getItem('app_lessons');
    return saved ? JSON.parse(saved) : [];
  });

  const [customPasswords, setCustomPasswords] = useState<Record<string, string>>(() => {
    const saved = localStorage.getItem('app_passwords');
    return saved ? JSON.parse(saved) : {};
  });

  useEffect(() => {
    localStorage.setItem('app_lessons', JSON.stringify(lessons));
  }, [lessons]);

  useEffect(() => {
    localStorage.setItem('app_passwords', JSON.stringify(customPasswords));
  }, [customPasswords]);

  const handleLogin = (user: User) => {
    setAuth({ user, isAuthenticated: true });
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
  };

  const addLesson = (newLesson: Lesson) => {
    setLessons(prev => [{ ...newLesson, status: 'pending' }, ...prev]);
  };

  const deleteLesson = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الدرس؟')) {
      setLessons(prev => prev.filter(l => l.id !== id));
    }
  };

  const updateLesson = (updatedLesson: Lesson) => {
    setLessons(prev => prev.map(l => (l.id === updatedLesson.id ? updatedLesson : l)));
  };

  const resetTeacherPassword = (teacherId: string) => {
    const newPass = Math.random().toString(36).slice(-8);
    setCustomPasswords(prev => ({ ...prev, [teacherId]: newPass }));
    return newPass;
  };

  if (!auth.isAuthenticated) {
    return <LoginForm onLogin={handleLogin} customPasswords={customPasswords} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 font-['Tajawal']">
      <nav className="bg-indigo-700 text-white shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-20 items-center">
            <div className="flex items-center gap-3">
              <div className="bg-white/10 p-2 rounded-xl">
                <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
                </svg>
              </div>
              <span className="text-xl font-black tracking-tight">الزيارات الإشرافية للمجال الأول</span>
            </div>
            <div className="flex items-center gap-6">
              <div className="hidden md:flex flex-col items-end">
                <span className="text-xs font-bold text-indigo-300 uppercase">المستخدم الحالي</span>
                <span className="text-sm font-black">{auth.user?.name}</span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-red-500/90 hover:bg-red-600 px-5 py-2.5 rounded-xl text-sm font-black transition-all shadow-lg active:scale-95 flex items-center gap-2"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h7a3 3 0 013 3v1" />
                </svg>
                خروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-10 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            addLesson={addLesson} 
            deleteLesson={deleteLesson}
            updateLesson={updateLesson}
            lessons={lessons.filter(l => l.teacherId === auth.user?.id)} 
          />
        ) : (
          <SupervisorDashboard 
            lessons={lessons} 
            updateLesson={updateLesson} 
            customPasswords={customPasswords}
            onResetPassword={resetTeacherPassword}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { UserRole, User } from '../types';

interface LoginFormProps {
  onLogin: (user: User) => void;
  customPasswords?: Record<string, string>;
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin, customPasswords = {} }) => {
  const [code, setCode] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanCode = code.trim();
    const cleanPass = password.trim();

    if (!cleanCode || !cleanPass) {
      setError('يرجى إدخال رقم التعريف وكلمة المرور');
      return;
    }

    const isSupervisor = cleanCode.toUpperCase().startsWith('S') || cleanCode.startsWith('99');

    // Check if there is a custom password for this teacher
    const teacherCustomPass = customPasswords[cleanCode];
    const defaultPass = isSupervisor ? `admin${cleanCode}` : `pass${cleanCode}`;
    const expectedPassword = teacherCustomPass || defaultPass;

    if (cleanPass !== expectedPassword) {
      setError('كلمة المرور غير صحيحة');
      return;
    }

    let role = isSupervisor ? UserRole.SUPERVISOR : UserRole.TEACHER;
    let name = isSupervisor ? `مشرف (${cleanCode})` : `معلم (${cleanCode})`;

    onLogin({
      id: cleanCode,
      name: name,
      role,
      code: cleanCode
    });
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 font-['Tajawal']">
      <div className="max-w-md w-full bg-white rounded-3xl shadow-xl p-10 space-y-8 border border-slate-100">
        <div className="text-center">
          <div className="w-20 h-20 bg-indigo-600 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg rotate-3">
             <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
             </svg>
          </div>
          <h1 className="text-3xl font-black text-slate-900 mb-2">منصة المجال الأول</h1>
          <p className="text-slate-500 font-medium">تسجيل الدخول للنظام</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-slate-700 mr-1 mb-1">رقم التعريف</label>
            <input
              type="text"
              required
              value={code}
              onChange={(e) => setCode(e.target.value)}
              className="w-full px-6 py-3 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-center font-bold"
              placeholder="Username"
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 mr-1 mb-1">كلمة المرور</label>
            <input
              type="password"
              required
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="w-full px-6 py-3 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-center font-bold"
              placeholder="••••••••"
            />
          </div>

          {error && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-2 rounded-lg">{error}</p>}

          <button
            type="submit"
            className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black text-xl hover:bg-indigo-700 transition shadow-xl mt-4"
          >
            دخول
          </button>
        </form>

        <div className="bg-amber-50 rounded-2xl p-4 border border-amber-100 text-[10px] text-amber-800 font-bold text-center leading-relaxed">
           * ملاحظة: المشرف يبدأ بـ S أو 99. المعلم يستخدم رقمه الوظيفي.
        </div>
      </div>
    </div>
  );
};

export default LoginForm;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
  updateLesson: (lesson: Lesson) => void;
  customPasswords: Record<string, string>;
  onResetPassword: (teacherId: string) => string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ lessons, updateLesson, customPasswords, onResetPassword }) => {
  const [view, setView] = useState<'lessons' | 'users'>('lessons');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);
  const [obsNote, setObsNote] = useState('');

  const teachers = useMemo(() => {
    const map = new Map<string, { id: string; name: string; lessonCount: number; code: string }>();
    lessons.forEach(l => {
      if (!map.has(l.teacherId)) {
        map.set(l.teacherId, { id: l.teacherId, name: l.teacherName, lessonCount: 0, code: l.teacherId });
      }
      map.get(l.teacherId)!.lessonCount++;
    });
    return Array.from(map.values());
  }, [lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const handleConfirmVisit = () => {
    if (activeLesson) {
      updateLesson({ ...activeLesson, status: 'confirmed' });
      alert('تم اعتماد توثيق الزيارة');
    }
  };

  const handleSaveObsNote = () => {
    if (activeLesson && obsNote.trim()) {
      updateLesson({ ...activeLesson, observationalNotes: obsNote });
      setObsNote('');
      alert('تم حفظ ملاحظات المشاهدة');
    }
  };

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return null;
    const { type, url, name } = strategy.attachment;
    if (type === 'image') return <img src={url} alt={name} className="max-h-40 rounded-lg mt-2 border shadow-sm" onClick={() => window.open(url)} />;
    if (type === 'video') return <video src={url} controls className="max-h-40 w-full mt-2 rounded-lg" />;
    if (type === 'link') return <a href={url} target="_blank" rel="noopener noreferrer" className="inline-block mt-2 text-indigo-600 font-bold bg-indigo-50 px-3 py-1 rounded-lg">🔗 فتح الرابط</a>;
    return <a href={url} download={name} className="inline-block mt-2 text-green-600 font-bold bg-green-50 px-3 py-1 rounded-lg">📄 تحميل الملف</a>;
  };

  if (view === 'users') {
    return (
      <div className="space-y-6 animate-fadeIn">
        <div className="flex justify-between items-center bg-white p-6 rounded-2xl shadow-md border-b-4 border-amber-500">
          <h2 className="text-2xl font-black text-slate-800">إدارة حسابات المعلمين</h2>
          <button onClick={() => setView('lessons')} className="bg-indigo-600 text-white px-6 py-2 rounded-xl font-bold shadow-lg">العودة للدروس</button>
        </div>

        <div className="bg-white rounded-3xl shadow-xl overflow-x-auto border border-slate-100">
          <table className="w-full text-right border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b">
                <th className="p-4 font-black text-slate-600">اسم المعلمة</th>
                <th className="p-4 font-black text-slate-600 text-center">رقم التعريف (Username)</th>
                <th className="p-4 font-black text-slate-600 text-center">كلمة المرور الحالية</th>
                <th className="p-4 font-black text-slate-600 text-center">الإجراءات</th>
              </tr>
            </thead>
            <tbody>
              {teachers.length === 0 ? (
                <tr><td colSpan={4} className="p-10 text-center text-slate-400 font-bold">لا يوجد معلمين مسجلين</td></tr>
              ) : (
                teachers.map(t => (
                  <tr key={t.id} className="border-b hover:bg-slate-50 transition-colors">
                    <td className="p-4 font-bold text-slate-800">{t.name}</td>
                    <td className="p-4 text-center font-mono font-bold text-indigo-600">{t.code}</td>
                    <td className="p-4 text-center font-mono font-bold text-amber-700">{customPasswords[t.id] || `pass${t.id}`}</td>
                    <td className="p-4 text-center">
                      <button 
                        onClick={() => {
                          const newPass = onResetPassword(t.id);
                          alert(`تمت إعادة تعيين كلمة المرور الجديدة: ${newPass}`);
                        }}
                        className="bg-amber-100 text-amber-700 px-4 py-2 rounded-xl text-xs font-black hover:bg-amber-200 transition"
                      >
                        إعادة إنشاء كلمة المرور 🔄
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
      <div className="lg:col-span-1 bg-white rounded-2xl shadow-xl p-5 space-y-4 border border-slate-100">
        <h2 className="text-xl font-black text-slate-800 border-b-2 border-indigo-50 pb-3">قائمة المعلمين</h2>
        <button onClick={() => setView('users')} className="w-full text-sm bg-amber-500 text-white py-2 rounded-xl font-black shadow-md mb-2">إدارة الحسابات ⚙️</button>
        <div className="space-y-3 overflow-y-auto max-h-[50vh]">
          {teachers.map((teacher) => (
            <button
              key={teacher.id}
              onClick={() => { setSelectedTeacherId(teacher.id); setSelectedLessonId(null); }}
              className={`w-full text-right p-4 rounded-xl transition-all border-2 ${
                selectedTeacherId === teacher.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-50 text-slate-700 hover:bg-indigo-50/30'
              }`}
            >
              <div className="font-extrabold text-lg leading-tight">{teacher.name}</div>
              <div className={`text-xs mt-1 font-bold ${selectedTeacherId === teacher.id ? 'text-indigo-100' : 'text-slate-400'}`}>
                {teacher.lessonCount} دروس
              </div>
            </button>
          ))}
        </div>
      </div>

      <div className="lg:col-span-3 space-y-6">
        {!selectedTeacherId ? (
          <div className="bg-white rounded-2xl shadow-xl p-24 text-center border-2 border-dashed border-slate-200 animate-fadeIn">
            <h3 className="text-2xl font-black text-slate-800">مرحباً بك في نظام متابعة الزيارات</h3>
            <p className="text-slate-500 mt-2">يرجى اختيار معلمة من القائمة لاستعراض الدروس</p>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="bg-white p-5 rounded-2xl shadow-md border-r-8 border-indigo-600 flex justify-between items-center">
              <h2 className="text-2xl font-black text-slate-900">سجل المعلمة: {teachers.find(t => t.id === selectedTeacherId)?.name}</h2>
              <button onClick={() => setSelectedTeacherId(null)} className="text-indigo-600 font-bold hover:underline">إغلاق</button>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
              {teacherLessons.map(lesson => (
                <button
                  key={lesson.id}
                  onClick={() => setSelectedLessonId(lesson.id)}
                  className={`text-right p-5 rounded-2xl border-2 transition-all relative ${
                    selectedLessonId === lesson.id ? 'bg-amber-50 border-amber-400 shadow-lg scale-[1.02]' : 'bg-white border-slate-50 hover:border-indigo-200'
                  }`}
                >
                  {lesson.status === 'confirmed' && <div className="absolute -top-2 -left-2 bg-green-500 text-white p-1 rounded-full text-[10px] shadow-lg border-2 border-white font-bold">✓ معتمد</div>}
                  <h4 className="font-extrabold text-slate-900 text-lg leading-snug">{lesson.title}</h4>
                  <p className="text-xs text-slate-400 mt-2">{lesson.createdAt}</p>
                </button>
              ))}
            </div>

            {activeLesson && (
              <div className="bg-white rounded-3xl shadow-2xl p-8 animate-slideUp border border-slate-100 space-y-8">
                <div className="border-b pb-6 flex justify-between items-start">
                  <div>
                    <h3 className="text-3xl font-black text-indigo-900">{activeLesson.title}</h3>
                    <p className="text-sm text-slate-500 mt-1">تاريخ التوثيق: {activeLesson.createdAt}</p>
                  </div>
                  <div className="flex gap-2">
                    {activeLesson.status === 'confirmed' && <span className="bg-green-100 text-green-800 px-4 py-2 rounded-2xl text-xs font-black">معتمد ✓</span>}
                    <span className="bg-indigo-600 text-white px-4 py-2 rounded-2xl text-xs font-black">{activeLesson.strategiesCount} استراتيجيات</span>
                  </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-10">
                  <div className="space-y-6">
                    {/* Observational Notes Box - Specifically requested */}
                    <div className="bg-slate-50 p-6 rounded-2xl border-2 border-indigo-100 shadow-inner">
                      <h4 className="font-black text-indigo-900 mb-4 flex items-center gap-2">
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                         ملحوظات المشاهدة الإشرافية
                      </h4>
                      <textarea 
                        value={obsNote || activeLesson.observationalNotes || ''} 
                        onChange={(e) => setObsNote(e.target.value)}
                        placeholder="أدخل ملحوظاتك على المشاهدة الصفية لهذا الدرس..."
                        className="w-full p-4 rounded-xl border-2 bg-white outline-none focus:border-indigo-300 text-sm min-h-[120px] font-bold text-slate-700"
                      />
