                  <div className="space-y-6">
                    <div className="bg-slate-50 p-6 rounded-2xl">
                      <h4 className="font-black text-indigo-950 mb-3 text-xs">توظيف الاستراتيجيات:</h4>
                      <p className="text-slate-700 leading-relaxed font-bold bg-white p-4 rounded-xl text-sm italic">{activeLesson.effectiveStrategiesDeployment || 'لا يوجد وصف'}</p>
