                    <div className="bg-emerald-50 p-6 rounded-2xl">
                      <h4 className="font-black text-emerald-950 mb-3 text-xs">أساليب التقويم:</h4>
                      <p className="text-slate-700 leading-relaxed font-bold bg-white p-4 rounded-xl text-sm">{activeLesson.evaluationMethods || 'لا يوجد وصف'}</p>
