                  }} className="bg-slate-800 text-white px-8 py-3 rounded-2xl font-black flex items-center gap-2 shadow-lg">📢 إرسال توجيهات فنية</button>
                  {activeLesson.status !== 'confirmed' && (
                    <button onClick={handleConfirmVisit} className="bg-indigo-600 text-white px-10 py-3 rounded-2xl font-black shadow-lg shadow-indigo-100 active:scale-95">✓ اعتماد توثيق الزيارة</button>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default SupervisorDashboard;

import React, { useState, useRef } from 'react';
import { User, Lesson, Strategy, AttachmentType } from '../types';
import { suggestStrategies } from '../services/geminiService';

interface TeacherDashboardProps {
  user: User;
  addLesson: (lesson: Lesson) => void;
  deleteLesson: (id: string) => void;
  updateLesson: (lesson: Lesson) => void;
  lessons: Lesson[];
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ user, addLesson, deleteLesson, updateLesson, lessons }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const formRef = useRef<HTMLDivElement>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [strategies, setStrategies] = useState<Strategy[]>([{ text: '' }]);
  const [selfLearning, setSelfLearning] = useState({
    thinking: false,
    collaboration: false,
    criticalThinking: false,
    higherOrderThinking: false,
  });
  const [deployment, setDeployment] = useState('');
  const [evaluations, setEvaluations] = useState('');
  const [values, setValues] = useState('');

  const handleAddStrategy = () => {
    if (strategies.length < 10) {
      setStrategies([...strategies, { text: '' }]);
    }
  };

  const handleRemoveStrategy = (index: number) => {
    const newStrats = strategies.filter((_, i) => i !== index);
    setStrategies(newStrats);
  };

  const updateStrategyText = (index: number, val: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], text: val };
    setStrategies(newStrats);
  };

  const setStrategyAttachment = (index: number, type: AttachmentType, url: string, name?: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], attachment: { type, url, name: name || 'مرفق' } };
    setStrategies(newStrats);
  };

  const removeAttachment = (index: number) => {
    const newStrats = [...strategies];
    delete newStrats[index].attachment;
    setStrategies(newStrats);
  };

  const handleFileChange = (index: number, type: AttachmentType, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setStrategyAttachment(index, type, reader.result as string, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddLink = (index: number) => {
    const url = prompt('يرجى إدخال رابط الموقع (مثال: https://google.com):');
    if (url && url.trim()) {
      let formattedUrl = url.trim();
      if (!formattedUrl.startsWith('http')) {
        formattedUrl = 'https://' + formattedUrl;
      }
      setStrategyAttachment(index, 'link', formattedUrl, 'رابط تعليمي');
    }
  };

  const handleSuggest = async () => {
    if (!title) return alert('يرجى كتابة عنوان الدرس أولاً');
    setLoadingSuggestions(true);
    const suggested = await suggestStrategies(title);
    setStrategies(suggested.slice(0, 10).map(s => ({ text: s })));
    setLoadingSuggestions(false);
  };

  const handleEdit = (lesson: Lesson) => {
    setEditingId(lesson.id);
    setTitle(lesson.title);
    setStrategies(lesson.strategies.length > 0 ? lesson.strategies : [{ text: '' }]);
    setSelfLearning(lesson.selfLearningSkills);
    setDeployment(lesson.effectiveStrategiesDeployment);
    setEvaluations(lesson.evaluationMethods);
    setValues(lesson.valuesAndCitizenship);
    setShowForm(true);
    setTimeout(() => {
      formRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalStrategies = strategies.filter(s => s.text.trim() !== '');

    const lessonData: Lesson = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      teacherId: user.id,
      teacherName: user.name,
      title,
      strategiesCount: finalStrategies.length,
      strategies: finalStrategies,
      selfLearningSkills: selfLearning,
      effectiveStrategiesDeployment: deployment,
      evaluationMethods: evaluations,
      valuesAndCitizenship: values,
      createdAt: editingId ? (lessons.find(l => l.id === editingId)?.createdAt || new Date().toLocaleDateString('ar-SA')) : new Date().toLocaleDateString('ar-SA'),
      status: editingId ? lessons.find(l => l.id === editingId)?.status : 'pending',
      supervisorNotes: editingId ? lessons.find(l => l.id === editingId)?.supervisorNotes : undefined,
      observationalNotes: editingId ? lessons.find(l => l.id === editingId)?.observationalNotes : undefined
    };

    if (editingId) {
      updateLesson(lessonData);
    } else {
      addLesson(lessonData);
    }

    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setEditingId(null);
    setTitle('');
    setStrategies([{ text: '' }]);
    setSelfLearning({
      thinking: false,
      collaboration: false,
      criticalThinking: false,
      higherOrderThinking: false,
    });
    setDeployment('');
    setEvaluations('');
    setValues('');
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-black text-slate-800">سجل الدروس الموثقة</h2>
          <p className="text-slate-500 font-bold">متابعة الزيارات الإشرافية وحالة الاعتماد</p>
        </div>
        <button
          onClick={() => { if (showForm) resetForm(); setShowForm(!showForm); }}
          className={`${showForm ? 'bg-slate-500' : 'bg-indigo-600'} text-white px-8 py-3 rounded-2xl font-black shadow-lg transition-all active:scale-95`}
        >
          {showForm ? 'إلغاء' : '+ إضافة درس جديد'}
        </button>
      </div>

      {showForm && (
        <div ref={formRef} className="bg-white rounded-3xl shadow-2xl p-8 border-t-8 border-indigo-600 animate-fadeIn relative">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="space-y-6">
                <div>
                  <label className="block text-sm font-black text-slate-700 mb-2">عنوان الدرس / الموضوع</label>
                  <input type="text" required value={title} onChange={(e) => setTitle(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none font-black text-lg" placeholder="اكتب عنوان الدرس هنا..." />
                </div>
                <div>
                  <div className="flex justify-between items-center mb-3">
                    <label className="text-sm font-black text-slate-700">الاستراتيجيات (الحد الأقصى 10)</label>
                    <button type="button" onClick={handleSuggest} className="text-xs font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl hover:bg-indigo-100 transition">🤖 اقتراحات ذكية</button>
                  </div>
                  <div className="space-y-4 bg-slate-50 p-5 rounded-2xl border-2 border-slate-100 max-h-[450px] overflow-y-auto">
                    {strategies.map((strat, idx) => (
                      <div key={idx} className="bg-white p-4 rounded-xl shadow-sm border space-y-3 relative group">
                        <input type="text" value={strat.text} onChange={(e) => updateStrategyText(idx, e.target.value)} className="w-full text-sm border-0 bg-slate-50 rounded-xl p-3 focus:ring-2 focus:ring-indigo-100 outline-none font-bold" placeholder={`الاستراتيجية رقم ${idx+1}`} />
                        <div className="flex flex-wrap gap-2">
                           {!strat.attachment ? (
                             <>
                               <label className="cursor-pointer bg-slate-100 hover:bg-indigo-50 px-3 py-2 rounded-xl text-[10px] font-black transition-colors">📂 إرفاق ملف<input type="file" className="hidden" onChange={(e) => handleFileChange(idx, 'file', e)} /></label>
                               <button type="button" onClick={() => handleAddLink(idx)} className="bg-slate-100 hover:bg-indigo-50 px-3 py-2 rounded-xl text-[10px] font-black transition-colors">🔗 إرفاق رابط</button>
                             </>
                           ) : (
                             <div className="flex items-center gap-2 bg-indigo-50 text-indigo-700 px-3 py-2 rounded-xl text-[10px] font-black border border-indigo-100">
                                📎 {strat.attachment.name} 
                                <button type="button" onClick={() => removeAttachment(idx)} className="text-red-500 font-black px-1 hover:scale-125 transition-transform">×</button>
                             </div>
                           )}
                        </div>
                      </div>
                    ))}
                    {strategies.length < 10 && <button type="button" onClick={handleAddStrategy} className="text-sm font-black text-indigo-600 hover:underline w-full text-center py-2">+ إضافة استراتيجية أخرى</button>}
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <div>
                  <label className="block text-sm font-black text-slate-700 mb-4">مهارات التعلم الذاتي</label>
                  <div className="grid grid-cols-2 gap-4">
                    {Object.keys(selfLearning).map((key) => (
                      <label key={key} className={`flex items-center gap-3 p-4 border-2 rounded-2xl cursor-pointer transition-all ${selfLearning[key as keyof typeof selfLearning] ? 'bg-indigo-50 border-indigo-300' : 'bg-white border-slate-100 hover:border-slate-200'}`}>
                        <input type="checkbox" checked={selfLearning[key as keyof typeof selfLearning]} onChange={(e) => setSelfLearning({ ...selfLearning, [key]: e.target.checked })} className="w-5 h-5 text-indigo-600 rounded" />
                        <span className="text-sm font-black text-slate-700">{key === 'thinking' ? 'تفكير' : key === 'collaboration' ? 'تعاون' : key === 'criticalThinking' ? 'نقد' : 'تفكير عليا'}</span>
                      </label>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-black text-slate-700 mb-3">آلية توظيف الاستراتيجيات</label>
                  <textarea rows={4} value={deployment} onChange={(e) => setDeployment(e.target.value)} className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-3xl outline-none focus:border-indigo-300 text-sm font-bold shadow-inner" placeholder="اشرح كيف ستطبق الاستراتيجيات..." />
                </div>
              </div>
            </div>
            <div className="flex justify-end pt-8 border-t gap-4">
              <button type="button" onClick={() => { setShowForm(false); resetForm(); }} className="bg-slate-200 text-slate-600 px-10 py-4 rounded-2xl font-black">إلغاء</button>
              <button type="submit" className="bg-indigo-600 text-white px-12 py-4 rounded-2xl font-black shadow-xl shadow-indigo-100 transition hover:bg-indigo-700">حفظ ونشر التوثيق ✓</button>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {lessons.map((lesson) => (
          <div key={lesson.id} className="bg-white rounded-3xl shadow-xl border border-slate-100 hover:shadow-2xl transition-all flex flex-col overflow-hidden relative group">
            <div className={`p-5 text-white font-black flex justify-between items-center ${lesson.status === 'confirmed' ? 'bg-green-600' : 'bg-amber-500'}`}>
              <span className="text-sm font-black tracking-tight">{lesson.status === 'confirmed' ? 'تم الاعتماد ✓' : 'بانتظار المراجعة...'}</span>
              <div className="flex gap-3">
                <button onClick={() => handleEdit(lesson)} className="hover:scale-110 transition-transform bg-white/20 p-1.5 rounded-lg">✎</button>
                <button onClick={() => deleteLesson(lesson.id)} className="hover:scale-110 transition-transform bg-white/20 p-1.5 rounded-lg">×</button>
              </div>
            </div>
            <div className="p-7 flex-1 space-y-6">
              <div>
                <h3 className="text-2xl font-black text-slate-900 mb-1 leading-tight">{lesson.title}</h3>
                <p className="text-[11px] font-black text-slate-400">التاريخ: {lesson.createdAt}</p>
              </div>

              {/* Supervisor Feedback Sections */}
              {(lesson.observationalNotes || lesson.supervisorNotes) && (
                <div className="space-y-3">
                  {lesson.observationalNotes && (
                    <div className="bg-indigo-50 p-4 rounded-2xl border-2 border-indigo-100 relative group">
                      <div className="absolute -top-3 -right-3 bg-indigo-600 text-white p-1 rounded-lg text-[10px] font-black">🔎 ملحوظة مشاهدة</div>
                      <p className="text-xs text-slate-700 italic font-black leading-relaxed mt-1">{lesson.observationalNotes}</p>
                    </div>
                  )}
                  {lesson.supervisorNotes && (
                    <div className="bg-amber-50 p-4 rounded-2xl border-2 border-amber-100 relative group">
                      <div className="absolute -top-3 -right-3 bg-amber-600 text-white p-1 rounded-lg text-[10px] font-black">📢 توجيه إشرافي</div>
                      <p className="text-xs text-slate-700 italic font-black leading-relaxed mt-1">{lesson.supervisorNotes}</p>
                    </div>
                  )}
                </div>
              )}

              <div className="flex flex-wrap gap-2 pt-2 border-t border-slate-50">
                <span className="bg-slate-100 text-slate-700 px-3 py-1.5 rounded-xl text-[10px] font-black border">⚡ {lesson.strategiesCount} استراتيجيات</span>
                {Object.entries(lesson.selfLearningSkills).filter(([_,v])=>v).map(([k]) => (
                   <span key={k} className="bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-xl text-[10px] font-black border border-indigo-100">
                     {k === 'thinking' ? 'تفكير' : k === 'collaboration' ? 'تعاون' : 'نقد'}
                   </span>
                ))}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default TeacherDashboard;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
  updateLesson: (lesson: Lesson) => void;
  customPasswords: Record<string, string>;
  onResetPassword: (teacherId: string) => string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ lessons, updateLesson, customPasswords, onResetPassword }) => {
  const [view, setView] = useState<'lessons' | 'users'>('lessons');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);
  const [obsNote, setObsNote] = useState('');

  // استخراج قائمة المعلمين الفريدة من الدروس
  const teachers = useMemo(() => {
    const map = new Map<string, { id: string; name: string; lessonCount: number; code: string }>();
    lessons.forEach(l => {
      if (!map.has(l.teacherId)) {
        map.set(l.teacherId, { id: l.teacherId, name: l.teacherName, lessonCount: 0, code: l.teacherId });
      }
      map.get(l.teacherId)!.lessonCount++;
    });
    return Array.from(map.values());
  }, [lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const handleConfirmVisit = () => {
    if (activeLesson) {
      updateLesson({ ...activeLesson, status: 'confirmed' });
      alert('تم اعتماد توثيق الزيارة بنجاح');
    }
  };

  const handleSaveObsNote = () => {
    if (activeLesson && obsNote.trim()) {
      updateLesson({ ...activeLesson, observationalNotes: obsNote });
      setObsNote('');
      alert('تم حفظ ملحوظة المشاهدة الإشرافية');
    }
  };

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return null;
    const { type, url, name } = strategy.attachment;
    if (type === 'image') return <img src={url} alt={name} className="max-h-48 rounded-xl mt-3 border shadow-md hover:scale-[1.02] transition-transform cursor-pointer" onClick={() => window.open(url)} />;
    if (type === 'video') return <video src={url} controls className="max-h-48 w-full mt-3 rounded-xl shadow-md bg-black" />;
    if (type === 'link') return <a href={url} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-2 mt-3 text-indigo-600 font-bold bg-indigo-50 px-4 py-2 rounded-xl hover:bg-indigo-100 transition shadow-sm">🔗 فتح الرابط التعليمي</a>;
    return <a href={url} download={name} className="inline-flex items-center gap-2 mt-3 text-emerald-600 font-bold bg-emerald-50 px-4 py-2 rounded-xl hover:bg-emerald-100 transition shadow-sm">📄 تحميل الملف المرفق</a>;
  };

  // واجهة إدارة الحسابات
  if (view === 'users') {
    return (
      <div className="space-y-8 animate-fadeIn">
        <div className="flex justify-between items-center bg-white p-6 rounded-3xl shadow-lg border-b-8 border-amber-500">
          <div>
            <h2 className="text-3xl font-black text-slate-800">إدارة حسابات المعلمين</h2>
            <p className="text-slate-500 font-bold mt-1">عرض بيانات الدخول وإعادة تعيين كلمات المرور</p>
          </div>
          <button 
            onClick={() => setView('lessons')} 
            className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-black shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition active:scale-95 flex items-center gap-2"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
            العودة لمراجعة الدروس
          </button>
        </div>

        <div className="bg-white rounded-[2rem] shadow-2xl overflow-hidden border border-slate-100">
          <table className="w-full text-right border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b-2 border-slate-100">
                <th className="p-6 font-black text-slate-700 text-lg">اسم المعلمة</th>
                <th className="p-6 font-black text-slate-700 text-center text-lg">رقم التعريف (Username)</th>
                <th className="p-6 font-black text-slate-700 text-center text-lg">كلمة المرور الحالية</th>
                <th className="p-6 font-black text-slate-700 text-center text-lg">الإجراءات</th>
              </tr>
            </thead>
            <tbody>
              {teachers.length === 0 ? (
                <tr>
                  <td colSpan={4} className="p-20 text-center">
                    <div className="text-slate-300 mb-4 flex justify-center">
                      <svg className="w-16 h-16" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197M13 7a4 4 0 11-8 0 4 4 0 018 0z" /></svg>
                    </div>
                    <p className="text-slate-400 font-black text-xl">لا يوجد معلمات مسجلات في النظام حالياً</p>
                  </td>
                </tr>
              ) : (
                teachers.map(t => (
                  <tr key={t.id} className="border-b border-slate-50 hover:bg-slate-50/50 transition-colors">
                    <td className="p-6">
                      <div className="flex items-center gap-3">
                        <div className="w-10 h-10 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 font-black">
                          {t.name.charAt(0)}
                        </div>
                        <span className="font-black text-slate-800 text-lg">{t.name}</span>
                      </div>
                    </td>
                    <td className="p-6 text-center">
                      <code className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-xl font-mono font-black text-lg border border-indigo-100">
                        {t.code}
                      </code>
                    </td>
                    <td className="p-6 text-center">
                      <code className="bg-amber-50 text-amber-700 px-4 py-2 rounded-xl font-mono font-black text-lg border border-amber-100">
                        {customPasswords[t.id] || `pass${t.id}`}
                      </code>
                    </td>
                    <td className="p-6 text-center">
                      <button 
                        onClick={() => {
                          const newPass = onResetPassword(t.id);
                          alert(`تمت إعادة تعيين كلمة المرور بنجاح للمعلّمة: ${t.name}\nكلمة المرور الجديدة هي: ${newPass}`);
                        }}
                        className="bg-amber-500 text-white px-6 py-3 rounded-2xl font-black shadow-lg shadow-amber-100 hover:bg-amber-600 transition active:scale-95 flex items-center gap-2 mx-auto"
                      >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
                        إعادة إنشاء كلمة المرور
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
      {/* القائمة الجانبية */}
      <div className="lg:col-span-1 bg-white rounded-3xl shadow-xl p-6 space-y-6 border border-slate-100 flex flex-col h-[calc(100vh-12rem)] sticky top-28">
        <div>
          <h2 className="text-xl font-black text-slate-800 mb-4 border-r-4 border-indigo-600 pr-3">سجل المعلمات</h2>
          <button 
            onClick={() => setView('users')} 
            className="w-full bg-amber-500 text-white py-4 rounded-2xl font-black shadow-lg shadow-amber-100 hover:bg-amber-600 transition mb-4 flex items-center justify-center gap-2"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
            إدارة الحسابات
          </button>
        </div>

        <div className="space-y-3 overflow-y-auto flex-1 pr-1 custom-scrollbar">
          {teachers.map((teacher) => (
            <button
              key={teacher.id}
