import React, { useState } from 'react';
import { UserRole, User } from '../types';

interface LoginFormProps {
  onLogin: (user: User) => void;
  customPasswords?: Record<string, string>;
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin, customPasswords = {} }) => {
  const [code, setCode] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanCode = code.trim();
    const cleanPass = password.trim();

    if (!cleanCode || !cleanPass) {
      setError('يرجى إدخال رقم التعريف وكلمة المرور');
      return;
    }

    const isSupervisor = cleanCode.toUpperCase().startsWith('S') || cleanCode.startsWith('99');

    // منطق كلمة المرور للمشرف: الرقم الوظيفي + "مشرف"
    // منطق كلمة المرور للمعلم: كلمة مرور مخصصة أو الافتراضية (pass + الرقم)
    const teacherCustomPass = customPasswords[cleanCode];
    const defaultTeacherPass = `pass${cleanCode}`;
    const supervisorPass = `${cleanCode}مشرف`;

    const expectedPassword = isSupervisor ? supervisorPass : (teacherCustomPass || defaultTeacherPass);

    if (cleanPass !== expectedPassword) {
      setError('كلمة المرور غير صحيحة');
      return;
    }

    let role = isSupervisor ? UserRole.SUPERVISOR : UserRole.TEACHER;
    let name = isSupervisor ? `مشرف (${cleanCode})` : `معلم (${cleanCode})`;

    onLogin({
      id: cleanCode,
      name: name,
      role,
      code: cleanCode
    });
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 px-4 font-['Tajawal']">
      <div className="max-w-md w-full bg-white rounded-3xl shadow-xl p-10 space-y-8 border border-slate-100">
        <div className="text-center">
          <div className="w-20 h-20 bg-indigo-600 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg rotate-3 group-hover:rotate-0 transition-transform">
             <svg className="w-10 h-10 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332.477 4.5 1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.747 0 3.332.477 4.5 1.253v13C19.832 18.477 18.247 18 16.5 18c-1.746 0-3.332.477-4.5 1.253" />
             </svg>
          </div>
          <h1 className="text-3xl font-black text-slate-900 mb-2">منصة المجال الأول</h1>
          <p className="text-slate-500 font-medium">تسجيل الدخول للنظام</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-bold text-slate-700 mr-1 mb-1">رقم التعريف الوظيفي</label>
            <input
              type="text"
              required
              value={code}
              onChange={(e) => { setCode(e.target.value); setError(''); }}
              className="w-full px-6 py-3 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-center font-bold"
              placeholder="Username"
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-700 mr-1 mb-1">كلمة المرور</label>
            <input
              type="password"
              required
              value={password}
              onChange={(e) => { setPassword(e.target.value); setError(''); }}
              className="w-full px-6 py-3 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-center font-bold"
              placeholder="••••••••"
            />
          </div>

          {error && <p className="text-red-500 text-xs font-bold text-center bg-red-50 py-2 rounded-lg border border-red-100 animate-pulse">{error}</p>}

          <button
            type="submit"
            className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black text-xl hover:bg-indigo-700 transition shadow-xl mt-4 active:scale-95"
          >
            دخول للنظام
          </button>
        </form>

        <div className="space-y-2">
          <div className="bg-amber-50 rounded-2xl p-4 border border-amber-100 text-[10px] text-amber-800 font-bold leading-relaxed">
            <p>💡 ملاحظة الدخول:</p>
            <ul className="list-disc list-inside mt-1 space-y-1">
              <li>المشرف: الرقم الوظيفي متبوعاً بكلمة "مشرف" (مثال: S123مشرف).</li>
              <li>المعلم: كلمة pass متبوعة بالرقم الوظيفي (مثال: pass12345).</li>
            </ul>
          </div>
        </div>
      </div>
    </div>
  );
};

