import React, { useState, useRef } from 'react';
import { User, Lesson, Strategy, AttachmentType } from '../types';
import { suggestStrategies } from '../services/geminiService';

interface TeacherDashboardProps {
  user: User;
  addLesson: (lesson: Lesson) => void;
  deleteLesson: (id: string) => void;
  updateLesson: (lesson: Lesson) => void;
  lessons: Lesson[];
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ user, addLesson, deleteLesson, updateLesson, lessons }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const formRef = useRef<HTMLDivElement>(null);

  const [title, setTitle] = useState('');
  const [strategies, setStrategies] = useState<Strategy[]>([{ text: '' }]);
  const [selfLearning, setSelfLearning] = useState({
    thinking: false,
    collaboration: false,
    criticalThinking: false,
    higherOrderThinking: false,
  });
  const [deployment, setDeployment] = useState('');
  const [evaluations, setEvaluations] = useState('');
  const [values, setValues] = useState('');

  const handleAddStrategy = () => {
    if (strategies.length < 10) {
      setStrategies([...strategies, { text: '' }]);
    }
  };

  const handleRemoveStrategy = (index: number) => {
    const newStrats = strategies.filter((_, i) => i !== index);
    setStrategies(newStrats);
  };

  const updateStrategyText = (index: number, val: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], text: val };
    setStrategies(newStrats);
  };

  const setStrategyAttachment = (index: number, type: AttachmentType, url: string, name?: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], attachment: { type, url, name: name || 'مرفق تعليمي' } };
    setStrategies(newStrats);
  };

  const removeAttachment = (index: number) => {
    const newStrats = [...strategies];
    delete newStrats[index].attachment;
    setStrategies(newStrats);
  };

  const handleFileChange = (index: number, type: AttachmentType, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setStrategyAttachment(index, type, reader.result as string, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddLink = (index: number) => {
    const url = prompt('يرجى إدخال عنوان الرابط (URL) الخاص بالاستراتيجية:');
    if (url && url.trim()) {
      let formattedUrl = url.trim();
      if (!formattedUrl.startsWith('http')) {
        formattedUrl = 'https://' + formattedUrl;
      }
      setStrategyAttachment(index, 'link', formattedUrl, 'رابط إلكتروني');
    }
  };

  const handleSuggest = async () => {
    if (!title) return alert('يرجى كتابة عنوان الدرس أولاً');
    setLoadingSuggestions(true);
    const suggested = await suggestStrategies(title);
    setStrategies(suggested.slice(0, 10).map(s => ({ text: s })));
    setLoadingSuggestions(false);
  };

  const handleEdit = (lesson: Lesson) => {
    setEditingId(lesson.id);
    setTitle(lesson.title);
    setStrategies(lesson.strategies.length > 0 ? lesson.strategies : [{ text: '' }]);
    setSelfLearning(lesson.selfLearningSkills);
    setDeployment(lesson.effectiveStrategiesDeployment);
    setEvaluations(lesson.evaluationMethods);
    setValues(lesson.valuesAndCitizenship);
    setShowForm(true);
    setTimeout(() => {
      formRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, 100);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalStrategies = strategies.filter(s => s.text.trim() !== '');

    const lessonData: Lesson = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      teacherId: user.id,
      teacherName: user.name,
      title,
      strategiesCount: finalStrategies.length,
      strategies: finalStrategies,
      selfLearningSkills: selfLearning,
      effectiveStrategiesDeployment: deployment,
      evaluationMethods: evaluations,
      valuesAndCitizenship: values,
      createdAt: editingId ? (lessons.find(l => l.id === editingId)?.createdAt || new Date().toLocaleDateString('ar-SA')) : new Date().toLocaleDateString('ar-SA'),
      status: editingId ? lessons.find(l => l.id === editingId)?.status : 'pending',
      supervisorNotes: editingId ? lessons.find(l => l.id === editingId)?.supervisorNotes : undefined,
      observationalNotes: editingId ? lessons.find(l => l.id === editingId)?.observationalNotes : undefined
    };

    if (editingId) {
      updateLesson(lessonData);
    } else {
      addLesson(lessonData);
    }

    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setEditingId(null);
    setTitle('');
    setStrategies([{ text: '' }]);
    setSelfLearning({
      thinking: false,
      collaboration: false,
      criticalThinking: false,
      higherOrderThinking: false,
    });
    setDeployment('');
    setEvaluations('');
    setValues('');
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-black text-slate-800">سجل الدروس الموثقة</h2>
          <p className="text-slate-500 font-bold">متابعة الزيارات الإشرافية وحالة الاعتماد</p>
        </div>
        <button
          onClick={() => { if (showForm) resetForm(); setShowForm(!showForm); }}
          className={`${showForm ? 'bg-slate-500' : 'bg-indigo-600'} text-white px-8 py-3 rounded-2xl font-black shadow-lg transition-all active:scale-95 flex items-center gap-2`}
        >
          {showForm ? 'إلغاء' : <><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg> إضافة درس جديد</>}
        </button>
      </div>

      {showForm && (
        <div ref={formRef} className="bg-white rounded-3xl shadow-2xl p-8 border-t-8 border-indigo-600 animate-fadeIn relative">
          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="space-y-6">
                <div>
                  <label className="block text-sm font-black text-slate-700 mb-2">عنوان الدرس / الموضوع</label>
                  <input type="text" required value={title} onChange={(e) => setTitle(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none font-black text-lg shadow-inner" placeholder="اكتب عنوان الدرس هنا..." />
                </div>
                <div>
                  <div className="flex justify-between items-center mb-3">
                    <label className="text-sm font-black text-slate-700">الاستراتيجيات (الحد الأقصى 10)</label>
                    <button type="button" onClick={handleSuggest} className="text-xs font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl hover:bg-indigo-100 transition border border-indigo-100">🤖 اقتراحات ذكية</button>
                  </div>
                  <div className="space-y-4 bg-slate-50 p-5 rounded-2xl border-2 border-slate-100 max-h-[500px] overflow-y-auto custom-scrollbar">
                    {strategies.map((strat, idx) => (
                      <div key={idx} className="bg-white p-4 rounded-xl shadow-sm border space-y-3 relative group border-indigo-50">
                        <div className="flex gap-2">
                          <input type="text" value={strat.text} onChange={(e) => updateStrategyText(idx, e.target.value)} className="flex-1 text-sm border-0 bg-slate-50 rounded-xl p-3 focus:ring-2 focus:ring-indigo-100 outline-none font-bold" placeholder={`الاستراتيجية رقم ${idx+1}`} />
                          <button type="button" onClick={() => handleRemoveStrategy(idx)} className="text-red-400 hover:text-red-600 px-2 transition-colors">×</button>
                        </div>
                        <div className="flex flex-wrap gap-2">
                           {!strat.attachment ? (
                             <>
                               <label className="cursor-pointer bg-slate-100 hover:bg-indigo-50 px-3 py-2 rounded-xl text-[10px] font-black transition-colors border border-slate-200">🖼️ صورة<input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileChange(idx, 'image', e)} /></label>
                               <label className="cursor-pointer bg-slate-100 hover:bg-indigo-50 px-3 py-2 rounded-xl text-[10px] font-black transition-colors border border-slate-200">🎥 فيديو<input type="file" accept="video/*" className="hidden" onChange={(e) => handleFileChange(idx, 'video', e)} /></label>
                               <label className="cursor-pointer bg-slate-100 hover:bg-indigo-50 px-3 py-2 rounded-xl text-[10px] font-black transition-colors border border-slate-200">📄 ملف<input type="file" className="hidden" onChange={(e) => handleFileChange(idx, 'file', e)} /></label>
                               <button type="button" onClick={() => handleAddLink(idx)} className="bg-slate-100 hover:bg-indigo-50 px-3 py-2 rounded-xl text-[10px] font-black transition-colors border border-slate-200">🔗 رابط URL</button>
                             </>
                           ) : (
                             <div className="flex items-center gap-2 bg-indigo-50 text-indigo-700 px-3 py-2 rounded-xl text-[10px] font-black border border-indigo-200 w-full justify-between">
                                <span className="truncate">{strat.attachment.type === 'link' ? '🔗 URL: ' : '📎 '}{strat.attachment.name || strat.attachment.url}</span>
                                <button type="button" onClick={() => removeAttachment(idx)} className="text-red-500 font-black px-2 hover:scale-125 transition-transform">حذف</button>
                             </div>
                           )}
                        </div>
                      </div>
                    ))}
                    {strategies.length < 10 && <button type="button" onClick={handleAddStrategy} className="text-sm font-black text-indigo-600 hover:underline w-full text-center py-3 border-2 border-dashed border-indigo-100 rounded-xl bg-white">+ إضافة استراتيجية أخرى</button>}
                  </div>
                </div>
              </div>
              <div className="space-y-8">
                <div>
                  <label className="block text-sm font-black text-slate-700 mb-4">مهارات التعلم الذاتي</label>
                  <div className="grid grid-cols-2 gap-4">
                    {Object.keys(selfLearning).map((key) => (
                      <label key={key} className={`flex items-center gap-3 p-4 border-2 rounded-2xl cursor-pointer transition-all ${selfLearning[key as keyof typeof selfLearning] ? 'bg-indigo-50 border-indigo-300' : 'bg-white border-slate-100 hover:border-slate-200'}`}>
                        <input type="checkbox" checked={selfLearning[key as keyof typeof selfLearning]} onChange={(e) => setSelfLearning({ ...selfLearning, [key]: e.target.checked })} className="w-5 h-5 text-indigo-600 rounded" />
                        <span className="text-sm font-black text-slate-700">{key === 'thinking' ? 'تفكير' : key === 'collaboration' ? 'تعاون' : key === 'criticalThinking' ? 'نقد' : 'تفكير عليا'}</span>
                      </label>
                    ))}
                  </div>
                </div>
                <div>
                  <label className="block text-sm font-black text-slate-700 mb-3">آلية توظيف الاستراتيجيات</label>
                  <textarea rows={4} value={deployment} onChange={(e) => setDeployment(e.target.value)} className="w-full p-5 bg-slate-50 border-2 border-slate-100 rounded-3xl outline-none focus:border-indigo-300 text-sm font-bold shadow-inner" placeholder="اشرح كيف ستطبق الاستراتيجيات المذكورة..." />
                </div>
              </div>
            </div>
            <div className="flex justify-end pt-8 border-t gap-4">
              <button type="button" onClick={() => { setShowForm(false); resetForm(); }} className="bg-slate-200 text-slate-600 px-10 py-4 rounded-2xl font-black transition-colors hover:bg-slate-300">إلغاء</button>
              <button type="submit" className="bg-indigo-600 text-white px-12 py-4 rounded-2xl font-black shadow-xl shadow-indigo-100 transition hover:bg-indigo-700 active:scale-95">حفظ ونشر التوثيق ✓</button>
            </div>
          </form>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {lessons.length === 0 ? (
          <div className="col-span-full py-20 text-center bg-white rounded-3xl border-4 border-dashed border-slate-100">
            <p className="text-slate-400 font-black text-xl">لا توجد دروس موثقة حتى الآن</p>
          </div>
        ) : (
          lessons.map((lesson) => (
            <div key={lesson.id} className="bg-white rounded-3xl shadow-xl border border-slate-100 hover:shadow-2xl transition-all flex flex-col overflow-hidden relative group">
              <div className={`p-5 text-white font-black flex justify-between items-center ${lesson.status === 'confirmed' ? 'bg-green-600' : 'bg-amber-500'}`}>
                <span className="text-sm font-black tracking-tight">{lesson.status === 'confirmed' ? 'تم الاعتماد ✓' : 'بانتظار المراجعة...'}</span>
                <div className="flex gap-3">
                  <button onClick={() => handleEdit(lesson)} className="hover:scale-110 transition-transform bg-white/20 p-1.5 rounded-lg" title="تعديل">✎</button>
                  <button onClick={() => deleteLesson(lesson.id)} className="hover:scale-110 transition-transform bg-white/20 p-1.5 rounded-lg" title="حذف">×</button>
                </div>
              </div>
              <div className="p-7 flex-1 space-y-6">
                <div>
                  <h3 className="text-2xl font-black text-slate-900 mb-1 leading-tight line-clamp-2">{lesson.title}</h3>
                  <p className="text-[11px] font-black text-slate-400">التاريخ: {lesson.createdAt}</p>
                </div>

                {(lesson.observationalNotes || lesson.supervisorNotes) && (
                  <div className="space-y-3">
                    {lesson.observationalNotes && (
                      <div className="bg-indigo-50 p-4 rounded-2xl border-2 border-indigo-100 relative">
                        <div className="absolute -top-3 -right-3 bg-indigo-600 text-white p-1 rounded-lg text-[9px] font-black shadow-sm">🔎 ملحوظة مشاهدة</div>
                        <p className="text-xs text-slate-700 italic font-black leading-relaxed mt-1">{lesson.observationalNotes}</p>
                      </div>
                    )}
                    {lesson.supervisorNotes && (
                      <div className="bg-amber-50 p-4 rounded-2xl border-2 border-amber-100 relative">
                        <div className="absolute -top-3 -right-3 bg-amber-600 text-white p-1 rounded-lg text-[9px] font-black shadow-sm">📢 توجيه إشرافي</div>
                        <p className="text-xs text-slate-700 italic font-black leading-relaxed mt-1">{lesson.supervisorNotes}</p>
                      </div>
                    )}
                  </div>
                )}

                <div className="flex flex-wrap gap-2 pt-2 border-t border-slate-50">
                  <span className="bg-slate-100 text-slate-700 px-3 py-1.5 rounded-xl text-[10px] font-black border">⚡ {lesson.strategiesCount} استراتيجيات</span>
                  {Object.entries(lesson.selfLearningSkills).filter(([_,v])=>v).map(([k]) => (
                     <span key={k} className="bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-xl text-[10px] font-black border border-indigo-100">
                       {k === 'thinking' ? 'تفكير' : k === 'collaboration' ? 'تعاون' : 'نقد'}
                     </span>
                  ))}
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default TeacherDashboard;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
  updateLesson: (lesson: Lesson) => void;
  customPasswords: Record<string, string>;
  onResetPassword: (teacherId: string) => string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ lessons, updateLesson, customPasswords, onResetPassword }) => {
  const [view, setView] = useState<'lessons' | 'users'>('lessons');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);
  const [obsNote, setObsNote] = useState('');

  const teachers = useMemo(() => {
    const map = new Map<string, { id: string; name: string; lessonCount: number; code: string }>();
    lessons.forEach(l => {
      if (!map.has(l.teacherId)) {
        map.set(l.teacherId, { id: l.teacherId, name: l.teacherName, lessonCount: 0, code: l.teacherId });
      }
      map.get(l.teacherId)!.lessonCount++;
    });
    return Array.from(map.values());
  }, [lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const handleConfirmVisit = () => {
    if (activeLesson) {
      updateLesson({ ...activeLesson, status: 'confirmed' });
      alert('تم اعتماد توثيق الزيارة بنجاح');
    }
  };

  const handleSaveObsNote = () => {
    if (activeLesson && obsNote.trim()) {
      updateLesson({ ...activeLesson, observationalNotes: obsNote });
      setObsNote('');
      alert('تم حفظ ملحوظة المشاهدة الإشرافية');
    }
  };

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return <p className="text-[10px] text-slate-400 mt-2 italic">لا يوجد مرفقات تعليمية</p>;
    const { type, url, name } = strategy.attachment;

    switch(type) {
      case 'image':
        return (
          <div className="mt-3">
            <img 
              src={url} 
              alt={name} 
              className="max-h-60 rounded-xl border-2 border-slate-100 shadow-md hover:scale-[1.02] transition-transform cursor-zoom-in" 
              onClick={() => window.open(url)} 
            />
            <p className="text-[10px] text-slate-400 mt-2 font-bold flex items-center gap-1">🖼️ صورة توضيحية: {name}</p>
          </div>
        );
      case 'video':
        return (
          <div className="mt-3">
            <video src={url} controls className="max-h-60 w-full rounded-xl shadow-lg bg-black border-2 border-slate-100" />
            <p className="text-[10px] text-slate-400 mt-2 font-bold">🎥 مقطع فيديو توثيقي</p>
          </div>
        );
      case 'link':
        return (
          <div className="mt-3 space-y-2">
            <div className="p-4 bg-indigo-50 border-2 border-indigo-100 rounded-2xl flex flex-col gap-2">
              <span className="text-xs font-black text-indigo-700">🔗 رابط الاستراتيجية (URL):</span>
              <a 
                href={url} 
                target="_blank" 
                rel="noopener noreferrer" 
                className="text-sm text-white bg-indigo-600 px-6 py-3 rounded-xl font-black text-center hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 active:scale-95 inline-block"
              >
                فتح الرابط التعليمي
              </a>
              <code className="text-[10px] text-indigo-400 break-all font-mono bg-white p-2 rounded-lg border border-indigo-50">{url}</code>
            </div>
          </div>
        );
      case 'file':
        return (
          <div className="mt-3">
            <a 
              href={url} 
              download={name} 
              className="inline-flex items-center gap-3 bg-emerald-50 text-emerald-700 px-6 py-4 rounded-2xl font-black hover:bg-emerald-100 transition border-2 border-emerald-100 shadow-sm w-full md:w-auto"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
              تحميل الملف المرفق ({name})
            </a>
          </div>
        );
      default:
        return null;
    }
  };

  if (view === 'users') {
    return (
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        <div className="lg:col-span-1 bg-white rounded-3xl shadow-xl p-6 border border-slate-100 flex flex-col h-[calc(100vh-12rem)] sticky top-28">
           <h2 className="text-xl font-black text-slate-800 mb-6 border-r-4 border-amber-500 pr-3">إدارة الحسابات</h2>
           <button 
             onClick={() => setView('lessons')} 
             className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg mb-6 flex items-center justify-center gap-2 hover:bg-indigo-700 transition"
           >
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
             عرض الدروس الموثقة
           </button>
           <div className="flex-1 bg-slate-50 p-4 rounded-2xl border border-slate-100 text-sm font-bold text-slate-500 italic">
             يمكنك من هنا مراجعة بيانات دخول المعلمات وإعادة تعيين كلمات مرورهم في حال نسيانها.
           </div>
        </div>

        <div className="lg:col-span-3 space-y-8 animate-fadeIn">
          <div className="bg-white rounded-[2rem] shadow-2xl overflow-hidden border border-slate-100">
            <table className="w-full text-right border-collapse">
              <thead>
                <tr className="bg-slate-50 border-b-2 border-slate-100">
                  <th className="p-6 font-black text-slate-700 text-lg">المعلمة</th>
                  <th className="p-6 font-black text-slate-700 text-center text-lg">Username</th>
                  <th className="p-6 font-black text-slate-700 text-center text-lg">Password الحالية</th>
                  <th className="p-6 font-black text-slate-700 text-center text-lg">الإجراء</th>
                </tr>
              </thead>
              <tbody>
                {teachers.length === 0 ? (
                  <tr><td colSpan={4} className="p-20 text-center text-slate-400 font-bold">لا توجد معلمات مسجلات في النظام</td></tr>
                ) : (
                  teachers.map(t => (
                    <tr key={t.id} className="border-b border-slate-50 hover:bg-slate-50 transition-colors">
                      <td className="p-6 font-black text-slate-800 text-lg">{t.name}</td>
                      <td className="p-6 text-center"><code className="bg-indigo-50 text-indigo-700 px-3 py-1.5 rounded-xl font-mono font-black">{t.code}</code></td>
                      <td className="p-6 text-center"><code className="bg-amber-50 text-amber-700 px-3 py-1.5 rounded-xl font-mono font-black">{customPasswords[t.id] || `pass${t.id}`}</code></td>
                      <td className="p-6 text-center">
                        <button 
                          onClick={() => {
                            const newPass = onResetPassword(t.id);
                            alert(`كلمة المرور الجديدة لـ ${t.name}: ${newPass}`);
                          }}
                          className="bg-amber-500 text-white px-5 py-2.5 rounded-xl font-black shadow-lg hover:bg-amber-600 transition active:scale-95 text-xs"
                        >
                          إعادة إنشاء 🔄
                        </button>
                      </td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
      {/* القائمة الجانبية (Sidebar) */}
      <div className="lg:col-span-1 bg-white rounded-3xl shadow-xl p-6 space-y-6 border border-slate-100 flex flex-col h-[calc(100vh-12rem)] sticky top-28">
        <div>
          <h2 className="text-xl font-black text-slate-800 mb-6 border-r-4 border-indigo-600 pr-3">قائمة المعلمات</h2>
          <button 
            onClick={() => setView('users')} 
            className="w-full bg-amber-500 text-white py-4 rounded-2xl font-black shadow-lg shadow-amber-100 hover:bg-amber-600 transition mb-6 flex items-center justify-center gap-2"
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
            إدارة الحسابات
          </button>
        </div>

        <div className="space-y-3 overflow-y-auto flex-1 pr-1 custom-scrollbar">
          {teachers.map((teacher) => (
            <button
              key={teacher.id}
              onClick={() => { setSelectedTeacherId(teacher.id); setSelectedLessonId(null); }}
              className={`w-full text-right p-5 rounded-2xl transition-all border-2 flex flex-col gap-1 ${
                selectedTeacherId === teacher.id 
                  ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-[1.02]' 
                  : 'bg-white border-slate-50 text-slate-700 hover:border-indigo-100 hover:bg-indigo-50/30'
              }`}
            >
              <span className="font-black text-lg leading-tight">{teacher.name}</span>
              <span className={`text-xs font-bold ${selectedTeacherId === teacher.id ? 'text-indigo-100' : 'text-slate-400'}`}>
                {teacher.lessonCount} دروس موثقة
              </span>
            </button>
          ))}
        </div>
      </div>

      {/* منطقة العرض الرئيسية */}
      <div className="lg:col-span-3 space-y-8">
        {!selectedTeacherId ? (
          <div className="bg-white rounded-[2.5rem] shadow-2xl p-24 text-center border-2 border-dashed border-slate-200 animate-fadeIn flex flex-col items-center justify-center">
            <h3 className="text-3xl font-black text-slate-800">مرحباً بك في لوحة الإشراف</h3>
            <p className="text-slate-500 mt-2 font-bold text-lg max-w-sm mx-auto">اختر إحدى المعلمات لاستعراض دروسها وتفاصيل استراتيجياتها الموثقة.</p>
          </div>
        ) : (
          <div className="space-y-8 animate-fadeIn">
            {/* عرض شبكة الدروس (المربعات) */}
            {!selectedLessonId ? (
              <>
                <div className="bg-white p-6 rounded-3xl shadow-xl border-r-8 border-indigo-600 flex justify-between items-center">
                  <h2 className="text-2xl font-black text-slate-900">توثيقات المعلمة: {teachers.find(t => t.id === selectedTeacherId)?.name}</h2>
                  <button onClick={() => setSelectedTeacherId(null)} className="text-indigo-600 font-black hover:underline">إغلاق</button>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                  {teacherLessons.map(lesson => (
                    <div key={lesson.id} className="bg-white rounded-[2rem] border-2 border-slate-50 shadow-md p-6 flex flex-col h-full hover:shadow-xl transition-all hover:border-indigo-100">
                      <div className="flex justify-between items-start mb-4">
                        <div className={`px-3 py-1 rounded-full text-[10px] font-black ${lesson.status === 'confirmed' ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'}`}>
                          {lesson.status === 'confirmed' ? '✓ معتمد' : '● بانتظار المراجعة'}
                        </div>
                        <span className="text-[10px] text-slate-400 font-bold">{lesson.createdAt}</span>
                      </div>
                      <h4 className="font-black text-slate-900 text-xl leading-snug line-clamp-2 mb-6 flex-1">{lesson.title}</h4>
                      <button 
                        onClick={() => setSelectedLessonId(lesson.id)} 
                        className="w-full bg-indigo-50 text-indigo-700 py-3 rounded-2xl font-black text-sm hover:bg-indigo-600 hover:text-white transition shadow-sm active:scale-95"
                      >
                        عرض التفاصيل
                      </button>
                    </div>
                  ))}
                </div>
              </>
            ) : (
              /* عرض تفاصيل الدرس المختار */
              <div className="bg-white rounded-[2.5rem] shadow-2xl p-10 animate-slideUp border border-slate-100 space-y-10 relative overflow-hidden">
                <button 
                  onClick={() => setSelectedLessonId(null)} 
                  className="absolute top-8 left-8 bg-slate-100 text-slate-600 p-3 rounded-2xl hover:bg-slate-200 transition"
                  title="العودة لشبكة الدروس"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
                </button>

                <div className="border-b-2 border-slate-50 pb-8 pt-4">
                  <h3 className="text-4xl font-black text-indigo-950 leading-tight mb-4">{activeLesson?.title}</h3>
                  <div className="flex flex-wrap gap-4">
                    <span className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-xl text-xs font-black">👤 {activeLesson?.teacherName}</span>
                    <span className="bg-slate-50 text-slate-500 px-4 py-2 rounded-xl text-xs font-black">📅 {activeLesson?.createdAt}</span>
                    <span className="bg-amber-50 text-amber-700 px-4 py-2 rounded-xl text-xs font-black">⚡ {activeLesson?.strategiesCount} استراتيجيات</span>
                  </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
                  <div className="space-y-10">
                    {/* ملحوظات المشاهدة */}
                    <div className="bg-white p-8 rounded-[2rem] border-4 border-indigo-50 shadow-xl relative">
                      <h4 className="font-black text-indigo-950 mb-6 text-xl flex items-center gap-2">
                        <svg className="w-6 h-6 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" /></svg>
                        ملحوظات المشاهدة الإشرافية
                      </h4>
                      <textarea 
                        value={obsNote || activeLesson?.observationalNotes || ''} 
                        onChange={(e) => setObsNote(e.target.value)}
                        placeholder="أدخل ملحوظاتك الفنية التي تمت مشاهدتها خلال الزيارة الصفية..."
                        className="w-full p-6 rounded-2xl border-2 border-slate-100 bg-slate-50 outline-none focus:border-indigo-400 focus:bg-white text-base font-bold text-slate-700 min-h-[160px] shadow-inner transition-all mb-4"
                      />
                      <button onClick={handleSaveObsNote} className="w-full bg-indigo-500 text-white px-8 py-4 rounded-2xl font-black hover:bg-indigo-600 transition shadow-lg">حفظ الملحوظة</button>
                    </div>

                    <div className="space-y-6">
                      <h4 className="font-black text-slate-800 text-xl border-r-4 border-amber-400 pr-3">خطة الاستراتيجيات المرفقة</h4>
                      <div className="space-y-6">
                        {activeLesson?.strategies.map((s, i) => (
                          <div key={i} className="bg-slate-50 p-6 rounded-[2rem] border-2 border-white shadow-sm hover:border-indigo-100 transition-colors">
                            <div className="font-black text-slate-900 text-lg flex gap-3 mb-4">
                              <span className="bg-white w-8 h-8 rounded-full flex items-center justify-center text-indigo-500 shadow-sm border text-sm">{i+1}</span>
                              {s.text}
                            </div>
                            <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-inner">
                              {renderAttachment(s)}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>

                  <div className="space-y-8">
                    <div className="bg-white p-8 rounded-[2rem] border-2 border-slate-50 shadow-xl">
                      <h4 className="font-black text-indigo-950 mb-4 text-lg">آلية توظيف الاستراتيجيات:</h4>
                      <p className="text-slate-700 leading-relaxed font-bold bg-slate-50 p-6 rounded-2xl text-lg italic border border-slate-100">{activeLesson?.effectiveStrategiesDeployment || 'لم يتم ذكر التفاصيل.'}</p>
                    </div>

                    <div className="bg-white p-8 rounded-[2rem] border-2 border-slate-50 shadow-xl">
                      <h4 className="font-black text-emerald-900 mb-4 text-lg">أساليب التقويم والقياس:</h4>
                      <p className="text-slate-700 leading-relaxed font-bold bg-slate-50 p-6 rounded-2xl text-lg border border-slate-100">{activeLesson?.evaluationMethods || 'لا يوجد بيانات.'}</p>
                    </div>

                    {activeLesson?.supervisorNotes && (
                      <div className="bg-amber-50 p-8 rounded-[2rem] border-2 border-amber-200 shadow-lg">
                        <h4 className="font-black text-amber-900 mb-3 text-lg">التوجيه الإشرافي السابق:</h4>
                        <p className="text-amber-800 font-black italic leading-relaxed bg-white/60 p-5 rounded-2xl">{activeLesson?.supervisorNotes}</p>
                      </div>
                    )}
                  </div>
                </div>

                <div className="pt-10 border-t-2 border-slate-50 flex flex-wrap justify-end gap-5">
                  <button 
                    onClick={() => {
                      const directive = prompt('أدخل التوجيه الفني المباشر للمعلمة:', activeLesson?.supervisorNotes || '');
                      if (directive !== null && activeLesson) updateLesson({ ...activeLesson, supervisorNotes: directive });
                    }} 
                    className="bg-slate-800 text-white px-10 py-5 rounded-[1.5rem] font-black flex items-center gap-3 shadow-2xl hover:bg-black transition active:scale-95"
                  >
                    إرسال توجيهات فنية 📢
                  </button>
                  {activeLesson?.status !== 'confirmed' && (
                    <button 
                      onClick={handleConfirmVisit} 
                      className="bg-indigo-600 text-white px-12 py-5 rounded-[1.5rem] font-black shadow-2xl shadow-indigo-200 hover:bg-indigo-700 transition active:scale-95 flex items-center gap-3"
                    >
                      اعتماد توثيق الزيارة ✓
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default SupervisorDashboard;

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Lesson } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [lessons, setLessons] = useState<Lesson[]>(() => {
    const saved = localStorage.getItem('app_lessons');
    return saved ? JSON.parse(saved) : [];
  });

  const [customPasswords, setCustomPasswords] = useState<Record<string, string>>(() => {
    const saved = localStorage.getItem('app_passwords');
    return saved ? JSON.parse(saved) : {};
  });

  useEffect(() => {
    localStorage.setItem('app_lessons', JSON.stringify(lessons));
  }, [lessons]);

  useEffect(() => {
    localStorage.setItem('app_passwords', JSON.stringify(customPasswords));
  }, [customPasswords]);

  const handleLogin = (user: User) => {
    setAuth({ user, isAuthenticated: true });
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
  };

  const addLesson = (newLesson: Lesson) => {
    setLessons(prev => [{ ...newLesson, status: 'pending' }, ...prev]);
  };

  const deleteLesson = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الدرس؟')) {
      setLessons(prev => prev.filter(l => l.id !== id));
    }
  };

  const updateLesson = (updatedLesson: Lesson) => {
    setLessons(prev => prev.map(l => (l.id === updatedLesson.id ? updatedLesson : l)));
  };

  const resetTeacherPassword = (teacherId: string) => {
    const newPass = Math.random().toString(36).slice(-8);
    setCustomPasswords(prev => ({ ...prev, [teacherId]: newPass }));
    return newPass;
  };

  if (!auth.isAuthenticated) {
    return <LoginForm onLogin={handleLogin} customPasswords={customPasswords} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 font-['Tajawal']">
      <nav className="bg-white text-slate-900 shadow-md sticky top-0 z-50 border-b border-slate-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-24 items-center">
            <div className="flex items-center gap-4">
              <div className="bg-indigo-50 p-1.5 rounded-2xl border border-indigo-100">
                <img 
                  src="https://raw.githubusercontent.com/google/material-design-icons/master/png/action/school/materialicons/48dp/1x/baseline_school_black_48dp.png" 
                  alt="لوجو المدرسة" 
                  className="w-12 h-12 object-contain rounded-xl"
                  onError={(e) => {
                    // Fallback to the uploaded logo image context if available, 
                    // otherwise keeping the placeholder logic simple
                    (e.target as HTMLImageElement).src = 'https://raw.githubusercontent.com/google/material-design-icons/master/png/action/account_balance/materialicons/48dp/1x/baseline_account_balance_black_48dp.png';
                  }}
                />
              </div>
              <div className="flex flex-col">
                <span className="text-lg font-black tracking-tight text-indigo-950">مدرسة الخضراء للتعليم الأساسي</span>
                <span className="text-xs font-bold text-slate-500">الزيارات الإشرافية - أسرة المجال الأول</span>
              </div>
            </div>
            <div className="flex items-center gap-6">
              <div className="hidden md:flex flex-col items-end">
                <span className="text-[10px] font-black text-indigo-600 uppercase bg-indigo-50 px-2 py-0.5 rounded-md mb-1">المستخدم الحالي</span>
                <span className="text-sm font-black text-slate-800">{auth.user?.name}</span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-red-50 text-red-600 hover:bg-red-100 px-6 py-3 rounded-2xl text-sm font-black transition-all active:scale-95 flex items-center gap-2 border border-red-100 shadow-sm"
              >
                <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h7a3 3 0 013 3v1" />
                </svg>
                خروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-10 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            addLesson={addLesson} 
            deleteLesson={deleteLesson}
            updateLesson={updateLesson}
            lessons={lessons.filter(l => l.teacherId === auth.user?.id)} 
          />
        ) : (
          <SupervisorDashboard 
            lessons={lessons} 
            updateLesson={updateLesson} 
            customPasswords={customPasswords}
            onResetPassword={resetTeacherPassword}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { UserRole, User } from '../types';

interface LoginFormProps {
  onLogin: (user: User) => void;
  customPasswords?: Record<string, string>;
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin, customPasswords = {} }) => {
  const [code, setCode] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanCode = code.trim();
    const cleanPass = password.trim();

    if (!cleanCode || !cleanPass) {
      setError('يرجى إدخال رقم التعريف وكلمة المرور');
      return;
    }

    const isSupervisor = cleanCode.toUpperCase().startsWith('S') || cleanCode.startsWith('99');

    const teacherCustomPass = customPasswords[cleanCode];
    const defaultTeacherPass = `pass${cleanCode}`;
    const supervisorPass = `${cleanCode}مشرف`;

    const expectedPassword = isSupervisor ? supervisorPass : (teacherCustomPass || defaultTeacherPass);

    if (cleanPass !== expectedPassword) {
      setError('كلمة المرور غير صحيحة');
      return;
    }

    let role = isSupervisor ? UserRole.SUPERVISOR : UserRole.TEACHER;
    let name = isSupervisor ? `مشرف (${cleanCode})` : `معلم (${cleanCode})`;

    onLogin({
      id: cleanCode,
      name: name,
      role,
      code: cleanCode
    });
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#fdfcf9] px-4 font-['Tajawal']">
      <div className="max-w-md w-full bg-white rounded-[2.5rem] shadow-2xl p-10 space-y-8 border border-slate-100 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-50/50 rounded-bl-full -z-0"></div>

        <div className="text-center relative z-10">
          <div className="mb-6 inline-block bg-white p-2 rounded-3xl shadow-lg border border-slate-50">
             <img 
               src="https://raw.githubusercontent.com/google/material-design-icons/master/png/action/school/materialicons/48dp/2x/baseline_school_black_48dp.png" 
               alt="لوجو مدرسة الخضراء" 
               className="w-32 h-32 object-contain rounded-2xl"
             />
          </div>
          <h1 className="text-3xl font-black text-slate-900 mb-2">منصة المجال الأول</h1>
          <p className="text-slate-500 font-black text-sm">مدرسة الخضراء للتعليم الأساسي</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5 relative z-10">
          <div>
            <label className="block text-sm font-black text-slate-700 mr-2 mb-2">رقم التعريف الوظيفي</label>
            <input
              type="text"
              required
              value={code}
              onChange={(e) => { setCode(e.target.value); setError(''); }}
              className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-center font-black text-lg transition-all"
              placeholder="Username"
            />
          </div>

          <div>
            <label className="block text-sm font-black text-slate-700 mr-2 mb-2">كلمة المرور</label>
            <input
              type="password"
              required
              value={password}
              onChange={(e) => { setPassword(e.target.value); setError(''); }}
              className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-center font-black text-lg transition-all"
              placeholder="••••••••"
            />
          </div>

          {error && (
            <div className="bg-red-50 text-red-600 text-xs font-black p-4 rounded-2xl border border-red-100 text-center animate-shake">
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black text-xl hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 mt-4 active:scale-95"
          >
            دخول للنظام
          </button>
        </form>

        <div className="bg-amber-50 rounded-2xl p-5 border border-amber-100 text-[11px] text-amber-800 font-black leading-relaxed relative z-10">
          <p className="flex items-center gap-2 mb-2">
            <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clipRule="evenodd"></path></svg>
            توجيهات الدخول:
          </p>
          <ul className="list-disc list-inside space-y-1 opacity-90">
            <li>المشرف: الرقم الوظيفي + "مشرف" (S123مشرف)</li>
            <li>المعلم: pass + الرقم الوظيفي (pass123)</li>
          </ul>
        </div>
      </div>
    </div>
  );
};

export default LoginForm;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
  updateLesson: (lesson: Lesson) => void;
  customPasswords: Record<string, string>;
  onResetPassword: (teacherId: string) => string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ lessons, updateLesson, customPasswords, onResetPassword }) => {
  const [view, setView] = useState<'lessons' | 'users'>('lessons');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);
  const [obsNote, setObsNote] = useState('');
  const [isNotesExpanded, setIsNotesExpanded] = useState(true);

  const teachers = useMemo(() => {
    const map = new Map<string, { id: string; name: string; lessonCount: number; code: string }>();
    lessons.forEach(l => {
      if (!map.has(l.teacherId)) {
        map.set(l.teacherId, { id: l.teacherId, name: l.teacherName, lessonCount: 0, code: l.teacherId });
      }
      map.get(l.teacherId)!.lessonCount++;
    });
    return Array.from(map.values());
  }, [lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const handleConfirmVisit = () => {
    if (activeLesson) {
      updateLesson({ ...activeLesson, status: 'confirmed' });
      alert('تم اعتماد توثيق الزيارة بنجاح');
    }
  };

  const handleSaveObsNote = () => {
    if (activeLesson && obsNote.trim()) {
      updateLesson({ ...activeLesson, observationalNotes: obsNote });
      setObsNote('');
      alert('تم حفظ ملحوظة المشاهدة الإشرافية');
    }
  };

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return <p className="text-[10px] text-slate-400 mt-2 italic">لا يوجد مرفقات تعليمية</p>;
    const { type, url, name } = strategy.attachment;

    switch(type) {
      case 'image':
        return (
          <div className="mt-3">
            <img 
              src={url} 
              alt={name} 
              className="max-h-60 rounded-xl border-2 border-slate-100 shadow-md hover:scale-[1.02] transition-transform cursor-zoom-in" 
              onClick={() => window.open(url)} 
            />
            <p className="text-[10px] text-slate-400 mt-2 font-bold flex items-center gap-1">🖼️ صورة توضيحية: {name}</p>
          </div>
        );
      case 'video':
        return (
          <div className="mt-3">
            <video src={url} controls className="max-h-60 w-full rounded-xl shadow-lg bg-black border-2 border-slate-100" />
            <p className="text-[10px] text-slate-400 mt-2 font-bold">🎥 مقطع فيديو توثيقي</p>
          </div>
        );
      case 'link':
        return (
          <div className="mt-3 space-y-2">
            <div className="p-4 bg-indigo-50 border-2 border-indigo-100 rounded-2xl flex flex-col gap-2">
              <span className="text-xs font-black text-indigo-700">🔗 رابط الاستراتيجية (URL):</span>
              <a 
                href={url} 
                target="_blank" 
                rel="noopener noreferrer" 
                className="text-sm text-white bg-indigo-600 px-6 py-3 rounded-xl font-black text-center hover:bg-indigo-700 transition shadow-lg shadow-indigo-100 active:scale-95 inline-block"
              >
                فتح الرابط التعليمي
              </a>
              <code className="text-[10px] text-indigo-400 break-all font-mono bg-white p-2 rounded-lg border border-indigo-50">{url}</code>
            </div>
          </div>
        );
      case 'file':
        return (
          <div className="mt-3">
            <a 
              href={url} 
              download={name} 
              className="inline-flex items-center gap-3 bg-emerald-50 text-emerald-700 px-6 py-4 rounded-2xl font-black hover:bg-emerald-100 transition border-2 border-emerald-100 shadow-sm w-full md:w-auto"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a2 2 0 002 2h12a2 2 0 002-2v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
              تحميل الملف المرفق ({name})
            </a>
          </div>
        );
      default:
        return null;
    }
  };

  if (view === 'users') {
    return (
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        <div className="lg:col-span-1 bg-white rounded-3xl shadow-xl p-6 border border-slate-100 flex flex-col h-[calc(100vh-12rem)] sticky top-28">
           <h2 className="text-xl font-black text-slate-800 mb-6 border-r-4 border-amber-500 pr-3">إدارة الحسابات</h2>
           <button 
             onClick={() => setView('lessons')} 
             className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg mb-6 flex items-center justify-center gap-2 hover:bg-indigo-700 transition"
           >
             <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
             عرض الدروس الموثقة
           </button>
           <div className="flex-1 bg-slate-50 p-4 rounded-2xl border border-slate-100 text-sm font-bold text-slate-500 italic">
             يمكنك من هنا مراجعة بيانات دخول المعلمات وإعادة تعيين كلمات مرورهم في حال نسيانها.
           </div>
        </div>

        <div className="lg:col-span-3 space-y-8 animate-fadeIn">
          <div className="bg-white rounded-[2rem] shadow-2xl overflow-hidden border border-slate-100">
            <table className="w-full text-right border-collapse">
              <thead>
