export default SupervisorDashboard;

export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  code: string;
  password?: string;
  mustChangePassword?: boolean;
}

export type AttachmentType = 'link' | 'image' | 'video' | 'file';

export interface Strategy {
  text: string;
  attachment?: {
    type: AttachmentType;
    url: string;
    name?: string;
  };
}

export interface Lesson {
  id: string;
  teacherId: string;
  teacherName: string;
  title: string;
  strategiesCount: number;
  strategies: Strategy[];
  selfLearningSkills: {
    thinking: boolean;
    collaboration: boolean;
    criticalThinking: boolean;
    higherOrderThinking: boolean;
  };
  effectiveStrategiesDeployment: string;
  evaluationMethods: string;
  valuesAndCitizenship: string;
  createdAt: string;
  status?: 'pending' | 'confirmed';
  supervisorNotes?: string;
  observationalNotes?: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Lesson } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';
import ChangePasswordForm from './components/ChangePasswordForm';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [lessons, setLessons] = useState<Lesson[]>(() => {
    const saved = localStorage.getItem('app_lessons');
    return saved ? JSON.parse(saved) : [];
  });

  const [teachers, setTeachers] = useState<User[]>(() => {
    const saved = localStorage.getItem('app_teachers_list');
    return saved ? JSON.parse(saved) : [];
  });

  const [showChangePassword, setShowChangePassword] = useState(false);

  useEffect(() => {
    localStorage.setItem('app_lessons', JSON.stringify(lessons));
  }, [lessons]);

  useEffect(() => {
    localStorage.setItem('app_teachers_list', JSON.stringify(teachers));
  }, [teachers]);

  const handleLogin = (user: User) => {
    if (user.role === UserRole.TEACHER && user.mustChangePassword) {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(true);
    } else {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(false);
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setShowChangePassword(false);
  };

  const addLesson = (newLesson: Lesson) => {
    setLessons(prev => [{ ...newLesson, status: 'pending' }, ...prev]);
  };

  const deleteLesson = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الدرس؟')) {
      setLessons(prev => prev.filter(l => l.id !== id));
    }
  };

  const updateLesson = (updatedLesson: Lesson) => {
    setLessons(prev => prev.map(l => (l.id === updatedLesson.id ? updatedLesson : l)));
  };

  const handleAddTeacher = (id: string, name: string) => {
    const exists = teachers.find(t => t.id === id);
    if (exists) return alert('هذا الرقم الوظيفي موجود مسبقاً');

    const newTeacher: User = {
      id,
      code: id,
      name,
      role: UserRole.TEACHER,
      password: `pass${id}`,
      mustChangePassword: true
    };
    setTeachers(prev => [...prev, newTeacher]);
  };

  const handleResetTeacherPassword = (teacherId: string) => {
    const defaultPass = `pass${teacherId}`;
    setTeachers(prev => prev.map(t => 
      t.id === teacherId ? { ...t, password: defaultPass, mustChangePassword: true } : t
    ));
    return defaultPass;
  };

  const handlePasswordChanged = (newPassword: string) => {
    if (auth.user) {
      setTeachers(prev => prev.map(t => 
        t.id === auth.user!.id ? { ...t, password: newPassword, mustChangePassword: false } : t
      ));
      setAuth(prev => ({ 
        ...prev, 
        user: prev.user ? { ...prev.user, mustChangePassword: false } : null 
      }));
      setShowChangePassword(false);
      alert('تم تحديث كلمة المرور بنجاح');
    }
  };

  if (!auth.isAuthenticated) {
    return <LoginForm onLogin={handleLogin} teachers={teachers} />;
  }

  if (showChangePassword) {
    return <ChangePasswordForm onPasswordChanged={handlePasswordChanged} onLogout={handleLogout} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 font-['Tajawal']">
      <nav className="bg-white text-slate-900 shadow-md sticky top-0 z-50 border-b border-slate-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-24 items-center">
            <div className="flex items-center gap-4">
              <div className="bg-indigo-50 p-1.5 rounded-2xl border border-indigo-100">
                <img 
                  src="https://raw.githubusercontent.com/google/material-design-icons/master/png/action/school/materialicons/48dp/1x/baseline_school_black_48dp.png" 
                  alt="لوجو المدرسة" 
                  className="w-12 h-12 object-contain rounded-xl"
                />
              </div>
              <div className="flex flex-col">
                <span className="text-lg font-black tracking-tight text-indigo-950">مدرسة الخضراء للتعليم الأساسي</span>
                <span className="text-xs font-bold text-slate-500">الزيارات الإشرافية - أسرة المجال الأول</span>
              </div>
            </div>
            <div className="flex items-center gap-6">
              <div className="hidden md:flex flex-col items-end">
                <span className="text-[10px] font-black text-indigo-600 uppercase bg-indigo-50 px-2 py-0.5 rounded-md mb-1">المستخدم الحالي</span>
                <span className="text-sm font-black text-slate-800">{auth.user?.name}</span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-red-50 text-red-600 hover:bg-red-100 px-6 py-3 rounded-2xl text-sm font-black transition-all active:scale-95 flex items-center gap-2 border border-red-100 shadow-sm"
              >
                خروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-10 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            addLesson={addLesson} 
            deleteLesson={deleteLesson}
            updateLesson={updateLesson}
            lessons={lessons.filter(l => l.teacherId === auth.user?.id)} 
          />
        ) : (
          <SupervisorDashboard 
            lessons={lessons} 
            updateLesson={updateLesson} 
            teachers={teachers}
            onAddTeacher={handleAddTeacher}
            onResetPassword={handleResetTeacherPassword}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy, User } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
  updateLesson: (lesson: Lesson) => void;
  teachers: User[];
  onAddTeacher: (id: string, name: string) => void;
  onResetPassword: (teacherId: string) => string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ lessons, updateLesson, teachers, onAddTeacher, onResetPassword }) => {
  const [activeTab, setActiveTab] = useState<'lessons' | 'accounts'>('lessons');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);
  const [obsNote, setObsNote] = useState('');
  const [isNotesExpanded, setIsNotesExpanded] = useState(true);

  // New teacher form state
  const [newTeacherName, setNewTeacherName] = useState('');
  const [newTeacherId, setNewTeacherId] = useState('');
  const [showAddForm, setShowAddForm] = useState(false);

  const teacherStats = useMemo(() => {
    return teachers.map(t => {
      const count = lessons.filter(l => l.teacherId === t.id).length;
      return { ...t, lessonCount: count };
    });
  }, [teachers, lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const handleConfirmVisit = () => {
    if (activeLesson) {
      updateLesson({ ...activeLesson, status: 'confirmed' });
      alert('تم اعتماد توثيق الزيارة بنجاح');
    }
  };

  const handleSaveObsNote = () => {
    if (activeLesson && obsNote.trim()) {
      updateLesson({ ...activeLesson, observationalNotes: obsNote });
      setObsNote('');
      alert('تم حفظ ملحوظة المشاهدة الإشرافية');
    }
  };

  const handleAddNewTeacher = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTeacherName || !newTeacherId) return alert('يرجى ملء كافة الحقول');
    onAddTeacher(newTeacherId, newTeacherName);
    setNewTeacherId('');
    setNewTeacherName('');
    setShowAddForm(false);
    alert('تم إضافة المعلمة بنجاح، كلمة المرور الافتراضية: pass + الرقم الوظيفي');
  };

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return <p className="text-[10px] text-slate-400 mt-2 italic">لا يوجد مرفقات تعليمية</p>;
    const { type, url, name } = strategy.attachment;

    switch(type) {
      case 'image':
        return (
          <div className="mt-3">
            <img src={url} alt={name} className="max-h-60 rounded-xl border-2 border-slate-100 shadow-md" />
            <p className="text-[10px] text-slate-400 mt-2 font-bold">🖼️ {name}</p>
          </div>
        );
      case 'video':
        return (
          <div className="mt-3">
            <video src={url} controls className="max-h-60 w-full rounded-xl shadow-lg bg-black" />
          </div>
        );
      case 'link':
        return (
          <div className="mt-3">
            <a href={url} target="_blank" rel="noopener noreferrer" className="text-sm text-white bg-indigo-600 px-6 py-3 rounded-xl font-black text-center block">فتح الرابط: {url}</a>
          </div>
        );
      case 'file':
        return (
          <div className="mt-3">
            <a href={url} download={name} className="inline-flex items-center gap-3 bg-emerald-50 text-emerald-700 px-6 py-4 rounded-2xl font-black border-2 border-emerald-100">تحميل: {name}</a>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* اختيار الواجهة - Tabs */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2">
          <button 
            onClick={() => { setActiveTab('lessons'); setSelectedTeacherId(null); setSelectedLessonId(null); }}
            className={`px-10 py-4 rounded-[1.5rem] font-black transition-all ${activeTab === 'lessons' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-indigo-50'}`}
          >
            📋 عرض الدروس والزيارات
          </button>
          <button 
            onClick={() => setActiveTab('accounts')}
            className={`px-10 py-4 rounded-[1.5rem] font-black transition-all ${activeTab === 'accounts' ? 'bg-amber-500 text-white shadow-lg' : 'text-slate-500 hover:bg-amber-50'}`}
          >
            👥 إدارة حسابات المعلمات
          </button>
        </div>
      </div>

      {activeTab === 'accounts' ? (
        <div className="space-y-8">
          <div className="flex justify-between items-center bg-white p-8 rounded-[2.5rem] shadow-xl border border-slate-100">
             <div>
               <h2 className="text-2xl font-black text-slate-900">إدارة حسابات الهيئة التدريسية</h2>
               <p className="text-slate-500 font-bold">إضافة معلمات جدد وإعادة تعيين كلمات المرور</p>
             </div>
             <button 
               onClick={() => setShowAddForm(!showAddForm)}
               className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black shadow-lg hover:bg-indigo-700 active:scale-95 transition-all"
             >
               {showAddForm ? 'إغلاق النموذج' : '+ إضافة معلمة جديدة'}
             </button>
          </div>

          {showAddForm && (
            <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl border-4 border-indigo-50 animate-slideDown">
               <form onSubmit={handleAddNewTeacher} className="grid grid-cols-1 md:grid-cols-3 gap-6 items-end">
                  <div>
                    <label className="block text-sm font-black text-slate-700 mb-2">اسم المعلمة</label>
                    <input type="text" value={newTeacherName} onChange={(e) => setNewTeacherName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-400 outline-none font-bold" placeholder="مثال: أمل محمد" />
                  </div>
                  <div>
                    <label className="block text-sm font-black text-slate-700 mb-2">الرقم الوظيفي</label>
                    <input type="text" value={newTeacherId} onChange={(e) => setNewTeacherId(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-400 outline-none font-bold text-center" placeholder="12345" />
                  </div>
                  <button type="submit" className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black shadow-lg hover:bg-emerald-700 transition">تأكيد الإضافة ✓</button>
               </form>
            </div>
          )}

          <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-100">
             <table className="w-full text-right">
                <thead className="bg-slate-50 border-b-2 border-slate-100">
                   <tr>
                     <th className="p-8 font-black text-slate-700">المعلمة</th>
                     <th className="p-8 font-black text-slate-700 text-center">الرقم الوظيفي</th>
                     <th className="p-8 font-black text-slate-700 text-center">حالة الحساب</th>
                     <th className="p-8 font-black text-slate-700 text-center">الإجراء</th>
                   </tr>
                </thead>
                <tbody>
                   {teacherStats.map(t => (
                     <tr key={t.id} className="border-b border-slate-50 hover:bg-slate-50 transition-colors">
                        <td className="p-8 font-black text-slate-800 text-xl">{t.name}</td>
                        <td className="p-8 text-center"><code className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-xl font-mono font-black">{t.id}</code></td>
                        <td className="p-8 text-center">
                          {t.mustChangePassword ? (
                            <span className="bg-amber-50 text-amber-600 px-4 py-1.5 rounded-full text-xs font-black">يجب تغيير كلمة المرور</span>
                          ) : (
                            <span className="bg-green-50 text-green-600 px-4 py-1.5 rounded-full text-xs font-black">نشط</span>
                          )}
                        </td>
                        <td className="p-8 text-center">
                          <button 
                            onClick={() => {
                              const p = onResetPassword(t.id);
                              alert(`تم تصفير كلمة المرور لـ ${t.name}\nكلمة المرور المؤقتة: ${p}`);
                            }}
                            className="bg-amber-500 text-white px-6 py-2.5 rounded-xl font-black hover:bg-amber-600 active:scale-95 transition"
                          >
                            تصفير الباسورد 🔄
                          </button>
                        </td>
                     </tr>
                   ))}
                </tbody>
             </table>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Sidebar for teachers when in Lessons mode */}
          <div className="lg:col-span-1 bg-white rounded-3xl shadow-xl p-6 space-y-4 border border-slate-100 sticky top-28 h-[calc(100vh-16rem)] overflow-y-auto custom-scrollbar">
            <h3 className="text-lg font-black text-slate-800 mb-4 pr-3 border-r-4 border-indigo-600">اختيار المعلمة</h3>
            {teacherStats.map(t => (
               <button
                 key={t.id}
                 onClick={() => { setSelectedTeacherId(t.id); setSelectedLessonId(null); }}
                 className={`w-full text-right p-5 rounded-2xl transition-all border-2 flex flex-col gap-1 ${
                   selectedTeacherId === t.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-[1.02]' : 'bg-white border-slate-50 text-slate-700 hover:border-indigo-100'
                 }`}
               >
                 <span className="font-black text-lg">{t.name}</span>
                 <span className={`text-xs font-bold ${selectedTeacherId === t.id ? 'text-indigo-100' : 'text-slate-400'}`}>{t.lessonCount} دروس</span>
               </button>
            ))}
          </div>

          <div className="lg:col-span-3 space-y-8">
            {!selectedTeacherId ? (
              <div className="bg-white rounded-[2.5rem] shadow-2xl p-24 text-center border-2 border-dashed border-slate-200">
                 <h3 className="text-2xl font-black text-slate-800">يرجى اختيار معلمة لعرض سجلها</h3>
              </div>
            ) : !selectedLessonId ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                {teacherLessons.map(lesson => (
                  <div key={lesson.id} className="bg-white rounded-[2.5rem] shadow-lg p-8 border border-slate-100 flex flex-col group hover:shadow-2xl transition-all">
                    <h4 className="font-black text-slate-800 text-xl leading-snug mb-6 flex-1">{lesson.title}</h4>
                    <button 
                      onClick={() => setSelectedLessonId(lesson.id)} 
                      className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black hover:bg-indigo-600 transition"
                    >
                      عرض التفاصيل
                    </button>
                  </div>
                ))}
              </div>
            ) : (
              /* Detail View */
              <div className="bg-white rounded-[3rem] shadow-2xl p-10 space-y-10 animate-slideUp">
                <button onClick={() => setSelectedLessonId(null)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 mb-4">← عودة</button>
                <h3 className="text-3xl font-black text-indigo-950">{activeLesson?.title}</h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                   <div className="space-y-6">
                      <div className="bg-indigo-50/30 p-8 rounded-[2rem] border-2 border-indigo-100">
                         <button 
                           onClick={() => setIsNotesExpanded(!isNotesExpanded)}
                           className="w-full flex justify-between items-center font-black text-xl text-indigo-950 mb-4"
                         >
                           <span>ملحوظات المشاهدة</span>
                           <span>{isNotesExpanded ? '▲' : '▼'}</span>
                         </button>
                         {isNotesExpanded && (
                           <div className="space-y-4 animate-fadeIn">
                             <textarea 
                               value={obsNote || activeLesson?.observationalNotes || ''} 
                               onChange={(e) => setObsNote(e.target.value)}
                               className="w-full p-5 rounded-2xl border-2 border-white bg-white/50 min-h-[150px] font-bold"
                               placeholder="اكتب ملحوظاتك الفنية هنا..."
                             />
                             <button onClick={handleSaveSaveObsNote} className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg">حفظ الملحوظة</button>
                           </div>
                         )}
                      </div>

                      <div className="space-y-6">
                        {activeLesson?.strategies.map((s, i) => (
                          <div key={i} className="bg-slate-50 p-6 rounded-3xl border border-white shadow-sm">
                            <div className="font-black text-slate-800 mb-4">{i+1}. {s.text}</div>
                            {renderAttachment(s)}
                          </div>
                        ))}
                      </div>
                   </div>

                   <div className="space-y-8">
                      <div className="bg-white p-8 rounded-3xl border-2 shadow-sm">
                         <h4 className="font-black mb-4">آلية التوظيف:</h4>
                         <p className="font-bold text-slate-600 italic">{activeLesson?.effectiveStrategiesDeployment}</p>
                      </div>
                      <div className="bg-white p-8 rounded-3xl border-2 shadow-sm">
                         <h4 className="font-black mb-4">التقويم والقياس:</h4>
                         <p className="font-bold text-slate-600">{activeLesson?.evaluationMethods}</p>
                      </div>
                   </div>
                </div>

                <div className="pt-8 border-t flex justify-end gap-4">
                  <button 
                    onClick={() => {
                      const d = prompt('أدخل التوجيه الفني:', activeLesson?.supervisorNotes || '');
                      if (d !== null && activeLesson) updateLesson({ ...activeLesson, supervisorNotes: d });
                    }}
                    className="bg-slate-800 text-white px-10 py-5 rounded-2xl font-black"
                  >
                    إرسال توجيه فني 📢
                  </button>
                  {activeLesson?.status !== 'confirmed' && (
                    <button onClick={handleConfirmVisit} className="bg-indigo-600 text-white px-10 py-5 rounded-2xl font-black">اعتماد الزيارة ✓</button>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default SupervisorDashboard;

import React, { useState } from 'react';
import { UserRole, User } from '../types';

interface LoginFormProps {
  onLogin: (user: User) => void;
  teachers: User[];
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin, teachers }) => {
  const [code, setCode] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanCode = code.trim();
    const cleanPass = password.trim();

    if (!cleanCode || !cleanPass) {
      setError('يرجى إدخال رقم التعريف وكلمة المرور');
      return;
    }

    const isSupervisor = cleanCode.toUpperCase().startsWith('S') || cleanCode.startsWith('99');

    if (isSupervisor) {
      const supervisorPass = `${cleanCode}مشرف`;
      if (cleanPass === supervisorPass) {
        onLogin({ id: cleanCode, name: `مشرفة (${cleanCode})`, role: UserRole.SUPERVISOR, code: cleanCode });
      } else {
        setError('كلمة مرور المشرف غير صحيحة');
      }
      return;
    }

    // Teacher check
    const teacher = teachers.find(t => t.id === cleanCode);
    if (!teacher) {
      setError('المعلمة غير مسجلة في النظام');
      return;
    }

    if (cleanPass === teacher.password) {
      onLogin(teacher);
    } else {
      setError('كلمة المرور غير صحيحة');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#fdfcf9] px-4 font-['Tajawal']">
      <div className="max-w-md w-full bg-white rounded-[2.5rem] shadow-2xl p-10 space-y-8 border border-slate-100 relative overflow-hidden">
        <div className="text-center relative z-10">
          <div className="mb-6 inline-block bg-white p-2 rounded-3xl shadow-lg border border-slate-50">
             <img src="https://raw.githubusercontent.com/google/material-design-icons/master/png/action/school/materialicons/48dp/2x/baseline_school_black_48dp.png" alt="لوجو" className="w-32 h-32 object-contain" />
          </div>
          <h1 className="text-3xl font-black text-slate-900 mb-2">منصة المجال الأول</h1>
          <p className="text-slate-500 font-black text-sm">مدرسة الخضراء للتعليم الأساسي</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5 relative z-10">
          <input type="text" required value={code} onChange={(e) => setCode(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-center font-black text-lg" placeholder="Username / الرقم الوظيفي" />
          <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-center font-black text-lg" placeholder="كلمة المرور" />
          {error && <div className="bg-red-50 text-red-600 text-xs font-black p-4 rounded-2xl text-center">{error}</div>}
          <button type="submit" className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black text-xl hover:bg-indigo-700 shadow-xl active:scale-95 transition-all">دخول للنظام</button>
        </form>
      </div>
    </div>
  );
};

export default LoginForm;

import React, { useState } from 'react';

interface ChangePasswordFormProps {
  onPasswordChanged: (newPassword: string) => void;
  onLogout: () => void;
}

const ChangePasswordForm: React.FC<ChangePasswordFormProps> = ({ onPasswordChanged, onLogout }) => {
  const [newPass, setNewPass] = useState('');
  const [confirmPass, setConfirmPass] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newPass.length < 4) return setError('كلمة المرور قصيرة جداً');
    if (newPass !== confirmPass) return setError('كلمات المرور غير متطابقة');

    onPasswordChanged(newPass);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-100 px-4 font-['Tajawal']">
      <div className="max-w-md w-full bg-white rounded-[2.5rem] shadow-2xl p-10 space-y-8 border-t-8 border-amber-500">
        <div className="text-center">
          <h2 className="text-3xl font-black text-slate-900 mb-4">تحديث كلمة المرور</h2>
          <p className="text-slate-500 font-bold leading-relaxed">
            لقد تم تصفير حسابك من قبل المشرفة، يرجى تعيين كلمة مرور شخصية جديدة للاستمرار في استخدام المنصة.
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-sm font-black text-slate-700 mb-2">كلمة المرور الجديدة</label>
            <input 
              type="password" 
              required 
              value={newPass} 
              onChange={(e) => setNewPass(e.target.value)} 
              className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-amber-500 outline-none text-center font-black"
              placeholder="••••••••"
            />
          </div>
          <div>
            <label className="block text-sm font-black text-slate-700 mb-2">تأكيد كلمة المرور</label>
            <input 
              type="password" 
              required 
              value={confirmPass} 
              onChange={(e) => setConfirmPass(e.target.value)} 
              className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-amber-500 outline-none text-center font-black"
              placeholder="••••••••"
            />
          </div>

          {error && <div className="bg-red-50 text-red-600 p-4 rounded-2xl text-center font-black text-xs">{error}</div>}

          <div className="flex flex-col gap-4">
            <button type="submit" className="w-full bg-amber-500 text-white py-5 rounded-2xl font-black text-xl hover:bg-amber-600 shadow-xl transition-all active:scale-95">حفظ وتحديث</button>
            <button type="button" onClick={onLogout} className="text-slate-400 font-bold hover:underline">تسجيل الخروج والعودة لاحقاً</button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default ChangePasswordForm;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy, User } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
  updateLesson: (lesson: Lesson) => void;
  teachers: User[];
  onAddTeacher: (id: string, name: string) => void;
  onResetPassword: (teacherId: string) => string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ lessons, updateLesson, teachers, onAddTeacher, onResetPassword }) => {
  const [activeTab, setActiveTab] = useState<'lessons' | 'accounts'>('lessons');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);
  const [obsNote, setObsNote] = useState('');
  const [isNotesExpanded, setIsNotesExpanded] = useState(true);

  // New teacher form state
  const [newTeacherName, setNewTeacherName] = useState('');
  const [newTeacherId, setNewTeacherId] = useState('');
  const [showAddForm, setShowAddForm] = useState(false);

  const teacherStats = useMemo(() => {
    return teachers.map(t => {
      const count = lessons.filter(l => l.teacherId === t.id).length;
      return { ...t, lessonCount: count };
    });
  }, [teachers, lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const handleConfirmVisit = () => {
    if (activeLesson) {
      updateLesson({ ...activeLesson, status: 'confirmed' });
      alert('تم اعتماد توثيق الزيارة بنجاح');
    }
  };

  const handleSaveObsNote = () => {
    if (activeLesson && obsNote.trim()) {
      updateLesson({ ...activeLesson, observationalNotes: obsNote });
      setObsNote('');
      alert('تم حفظ ملحوظة المشاهدة الإشرافية');
    }
  };

  const handleAddNewTeacher = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTeacherName || !newTeacherId) return alert('يرجى ملء كافة الحقول');
    onAddTeacher(newTeacherId, newTeacherName);
    setNewTeacherId('');
    setNewTeacherName('');
    setShowAddForm(false);
    alert('تم إضافة المعلمة بنجاح، كلمة المرور الافتراضية: pass + الرقم الوظيفي');
  };

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return <p className="text-[10px] text-slate-400 mt-2 italic">لا يوجد مرفقات تعليمية</p>;
    const { type, url, name } = strategy.attachment;

    switch(type) {
      case 'image':
        return (
          <div className="mt-3">
            <img src={url} alt={name} className="max-h-60 rounded-xl border-2 border-slate-100 shadow-md" />
            <p className="text-[10px] text-slate-400 mt-2 font-bold">🖼️ {name}</p>
          </div>
        );
      case 'video':
        return (
          <div className="mt-3">
            <video src={url} controls className="max-h-60 w-full rounded-xl shadow-lg bg-black" />
          </div>
        );
      case 'link':
        return (
          <div className="mt-3">
            <a href={url} target="_blank" rel="noopener noreferrer" className="text-sm text-white bg-indigo-600 px-6 py-3 rounded-xl font-black text-center block">فتح الرابط: {url}</a>
          </div>
        );
      case 'file':
        return (
          <div className="mt-3">
            <a href={url} download={name} className="inline-flex items-center gap-3 bg-emerald-50 text-emerald-700 px-6 py-4 rounded-2xl font-black border-2 border-emerald-100">تحميل: {name}</a>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* اختيار الواجهة - Tabs */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2">
          <button 
            onClick={() => { setActiveTab('lessons'); setSelectedTeacherId(null); setSelectedLessonId(null); }}
            className={`px-10 py-4 rounded-[1.5rem] font-black transition-all ${activeTab === 'lessons' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-indigo-50'}`}
          >
            📋 عرض الدروس والزيارات
          </button>
          <button 
            onClick={() => setActiveTab('accounts')}
            className={`px-10 py-4 rounded-[1.5rem] font-black transition-all ${activeTab === 'accounts' ? 'bg-amber-500 text-white shadow-lg' : 'text-slate-500 hover:bg-amber-50'}`}
          >
            👥 إدارة حسابات المعلمات
          </button>
        </div>
      </div>

      {activeTab === 'accounts' ? (
        <div className="space-y-8">
          <div className="flex justify-between items-center bg-white p-8 rounded-[2.5rem] shadow-xl border border-slate-100">
             <div>
               <h2 className="text-2xl font-black text-slate-900">إدارة حسابات الهيئة التدريسية</h2>
               <p className="text-slate-500 font-bold">إضافة معلمات جدد وإعادة تعيين كلمات المرور</p>
             </div>
             <button 
               onClick={() => setShowAddForm(!showAddForm)}
               className="bg-indigo-600 text-white px-8 py-4 rounded-2xl font-black shadow-lg hover:bg-indigo-700 active:scale-95 transition-all"
             >
               {showAddForm ? 'إغلاق النموذج' : '+ إضافة معلمة جديدة'}
             </button>
          </div>

          {showAddForm && (
            <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl border-4 border-indigo-50 animate-slideDown">
               <form onSubmit={handleAddNewTeacher} className="grid grid-cols-1 md:grid-cols-3 gap-6 items-end">
                  <div>
                    <label className="block text-sm font-black text-slate-700 mb-2">اسم المعلمة</label>
                    <input type="text" value={newTeacherName} onChange={(e) => setNewTeacherName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-400 outline-none font-bold" placeholder="مثال: أمل محمد" />
                  </div>
                  <div>
                    <label className="block text-sm font-black text-slate-700 mb-2">الرقم الوظيفي</label>
                    <input type="text" value={newTeacherId} onChange={(e) => setNewTeacherId(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-400 outline-none font-bold text-center" placeholder="12345" />
                  </div>
                  <button type="submit" className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black shadow-lg hover:bg-emerald-700 transition">تأكيد الإضافة ✓</button>
               </form>
            </div>
          )}

          <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-100">
             <table className="w-full text-right">
                <thead className="bg-slate-50 border-b-2 border-slate-100">
                   <tr>
                     <th className="p-8 font-black text-slate-700">المعلمة</th>
                     <th className="p-8 font-black text-slate-700 text-center">الرقم الوظيفي</th>
                     <th className="p-8 font-black text-slate-700 text-center">حالة الحساب</th>
                     <th className="p-8 font-black text-slate-700 text-center">الإجراء</th>
                   </tr>
                </thead>
                <tbody>
                   {teacherStats.map(t => (
                     <tr key={t.id} className="border-b border-slate-50 hover:bg-slate-50 transition-colors">
                        <td className="p-8 font-black text-slate-800 text-xl">{t.name}</td>
                        <td className="p-8 text-center"><code className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-xl font-mono font-black">{t.id}</code></td>
                        <td className="p-8 text-center">
                          {t.mustChangePassword ? (
                            <span className="bg-amber-50 text-amber-600 px-4 py-1.5 rounded-full text-xs font-black">يجب تغيير كلمة المرور</span>
                          ) : (
                            <span className="bg-green-50 text-green-600 px-4 py-1.5 rounded-full text-xs font-black">نشط</span>
                          )}
                        </td>
                        <td className="p-8 text-center">
                          <button 
                            onClick={() => {
                              const p = onResetPassword(t.id);
                              alert(`تم تصفير كلمة المرور لـ ${t.name}\nكلمة المرور المؤقتة: ${p}`);
                            }}
                            className="bg-amber-500 text-white px-6 py-2.5 rounded-xl font-black hover:bg-amber-600 active:scale-95 transition"
                          >
                            تصفير الباسورد 🔄
                          </button>
                        </td>
                     </tr>
                   ))}
                </tbody>
             </table>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Sidebar for teachers when in Lessons mode */}
          <div className="lg:col-span-1 bg-white rounded-3xl shadow-xl p-6 space-y-4 border border-slate-100 sticky top-28 h-[calc(100vh-16rem)] overflow-y-auto custom-scrollbar">
            <h3 className="text-lg font-black text-slate-800 mb-4 pr-3 border-r-4 border-indigo-600">اختيار المعلمة</h3>
            {teacherStats.map(t => (
               <button
                 key={t.id}
                 onClick={() => { setSelectedTeacherId(t.id); setSelectedLessonId(null); }}
                 className={`w-full text-right p-5 rounded-2xl transition-all border-2 flex flex-col gap-1 ${
                   selectedTeacherId === t.id ? 'bg-indigo-600 border-indigo-600 text-white shadow-xl scale-[1.02]' : 'bg-white border-slate-50 text-slate-700 hover:border-indigo-100'
                 }`}
               >
                 <span className="font-black text-lg">{t.name}</span>
                 <span className={`text-xs font-bold ${selectedTeacherId === t.id ? 'text-indigo-100' : 'text-slate-400'}`}>{t.lessonCount} دروس</span>
               </button>
            ))}
          </div>

          <div className="lg:col-span-3 space-y-8">
            {!selectedTeacherId ? (
              <div className="bg-white rounded-[2.5rem] shadow-2xl p-24 text-center border-2 border-dashed border-slate-200">
                 <h3 className="text-2xl font-black text-slate-800">يرجى اختيار معلمة لعرض سجلها</h3>
              </div>
            ) : !selectedLessonId ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
                {teacherLessons.map(lesson => (
                  <div key={lesson.id} className="bg-white rounded-[2.5rem] shadow-lg p-8 border border-slate-100 flex flex-col group hover:shadow-2xl transition-all">
                    <h4 className="font-black text-slate-800 text-xl leading-snug mb-6 flex-1">{lesson.title}</h4>
                    <button 
                      onClick={() => setSelectedLessonId(lesson.id)} 
                      className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black hover:bg-indigo-600 transition"
                    >
                      عرض التفاصيل
                    </button>
                  </div>
                ))}
              </div>
            ) : (
              /* Detail View */
              <div className="bg-white rounded-[3rem] shadow-2xl p-10 space-y-10 animate-slideUp">
                <button onClick={() => setSelectedLessonId(null)} className="bg-slate-100 p-3 rounded-2xl hover:bg-slate-200 mb-4">← عودة</button>
                <h3 className="text-3xl font-black text-indigo-950">{activeLesson?.title}</h3>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                   <div className="space-y-6">
                      <div className="bg-indigo-50/30 p-8 rounded-[2rem] border-2 border-indigo-100">
                         <button 
                           onClick={() => setIsNotesExpanded(!isNotesExpanded)}
                           className="w-full flex justify-between items-center font-black text-xl text-indigo-950 mb-4"
                         >
                           <span>ملحوظات المشاهدة</span>
                           <span>{isNotesExpanded ? '▲' : '▼'}</span>
                         </button>
                         {isNotesExpanded && (
                           <div className="space-y-4 animate-fadeIn">
                             <textarea 
                               value={obsNote || activeLesson?.observationalNotes || ''} 
                               onChange={(e) => setObsNote(e.target.value)}
