import { GoogleGenAI, Type } from "@google/genai";

// Always use named parameter and process.env.API_KEY directly as per guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const suggestStrategies = async (lessonTitle: string): Promise<string[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `بصفتك خبير تربوي، اقترح 5 استراتيجيات تدريس حديثة ومناسبة لدرس بعنوان "${lessonTitle}". أجب بصيغة قائمة بسيطة باللغة العربية.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: { type: Type.STRING }
        }
      }
    });

    // Extracting text output from GenerateContentResponse using .text property
    const text = response.text;
    if (text) {
      return JSON.parse(text);
    }
    return [];
  } catch (error) {
    console.error("Gemini Suggestion Error:", error);
    return ["العصف الذهني", "التعلم باللعب", "خرائط المفاهيم", "الكرسي الساخن", "فكر - زاوج - شارك"];
  }
};

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Lesson } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';
import ChangePasswordForm from './components/ChangePasswordForm';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [lessons, setLessons] = useState<Lesson[]>(() => {
    const saved = localStorage.getItem('app_lessons');
    return saved ? JSON.parse(saved) : [];
  });

  const [teachers, setTeachers] = useState<User[]>(() => {
    const saved = localStorage.getItem('app_teachers_list');
    return saved ? JSON.parse(saved) : [];
  });

  const [showChangePassword, setShowChangePassword] = useState(false);

  useEffect(() => {
    localStorage.setItem('app_lessons', JSON.stringify(lessons));
  }, [lessons]);

  useEffect(() => {
    localStorage.setItem('app_teachers_list', JSON.stringify(teachers));
  }, [teachers]);

  const handleLogin = (user: User) => {
    if (user.role === UserRole.TEACHER && user.mustChangePassword) {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(true);
    } else {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(false);
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setShowChangePassword(false);
  };

  const addLesson = (newLesson: Lesson) => {
    setLessons(prev => [{ ...newLesson, status: 'pending' }, ...prev]);
  };

  const deleteLesson = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الدرس؟')) {
      setLessons(prev => prev.filter(l => l.id !== id));
    }
  };

  const updateLesson = (updatedLesson: Lesson) => {
    setLessons(prev => prev.map(l => (l.id === updatedLesson.id ? updatedLesson : l)));
  };

  const handleAddTeacher = (id: string, name: string) => {
    const exists = teachers.find(t => t.id === id);
    if (exists) return alert('هذا الرقم الوظيفي موجود مسبقاً');

    const newTeacher: User = {
      id,
      code: id,
      name,
      role: UserRole.TEACHER,
      password: `pass${id}`,
      mustChangePassword: true
    };
    setTeachers(prev => [...prev, newTeacher]);
  };

  const handleDeleteTeacher = (teacherId: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذه المعلمة وجميع دروسها الموثقة؟')) {
      setTeachers(prev => prev.filter(t => t.id !== teacherId));
      setLessons(prev => prev.filter(l => l.teacherId !== teacherId));
    }
  };

  const handleResetTeacherPassword = (teacherId: string) => {
    const defaultPass = `pass${teacherId}`;
    setTeachers(prev => prev.map(t => 
      t.id === teacherId ? { ...t, password: defaultPass, mustChangePassword: true } : t
    ));
    return defaultPass;
  };

  const handlePasswordChanged = (newPassword: string) => {
    if (auth.user) {
      setTeachers(prev => prev.map(t => 
        t.id === auth.user!.id ? { ...t, password: newPassword, mustChangePassword: false } : t
      ));
      setAuth(prev => ({ 
        ...prev, 
        user: prev.user ? { ...prev.user, mustChangePassword: false } : null 
      }));
      setShowChangePassword(false);
      alert('تم تحديث كلمة المرور بنجاح');
    }
  };

  if (!auth.isAuthenticated) {
    return <LoginForm onLogin={handleLogin} teachers={teachers} />;
  }

  if (showChangePassword) {
    return <ChangePasswordForm onPasswordChanged={handlePasswordChanged} onLogout={handleLogout} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 font-['Tajawal']">
      <nav className="bg-white text-slate-900 shadow-md sticky top-0 z-50 border-b border-slate-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-24 items-center">
            <div className="flex items-center gap-4">
              <div className="bg-indigo-50 p-1.5 rounded-2xl border border-indigo-100">
                <img 
                  src="https://raw.githubusercontent.com/google/material-design-icons/master/png/action/school/materialicons/48dp/1x/baseline_school_black_48dp.png" 
                  alt="لوجو المدرسة" 
                  className="w-12 h-12 object-contain rounded-xl"
                />
              </div>
              <div className="flex flex-col">
                <span className="text-lg font-black tracking-tight text-indigo-950">مدرسة الخضراء للتعليم الأساسي</span>
                <span className="text-xs font-bold text-slate-500">الزيارات الإشرافية - أسرة المجال الأول</span>
              </div>
            </div>
            <div className="flex items-center gap-6">
              <div className="hidden md:flex flex-col items-end">
                <span className="text-[10px] font-black text-indigo-600 uppercase bg-indigo-50 px-2 py-0.5 rounded-md mb-1">المستخدم الحالي</span>
                <span className="text-sm font-black text-slate-800">{auth.user?.name}</span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-red-50 text-red-600 hover:bg-red-100 px-6 py-3 rounded-2xl text-sm font-black transition-all active:scale-95 flex items-center gap-2 border border-red-100 shadow-sm"
              >
                خروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-10 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            addLesson={addLesson} 
            deleteLesson={deleteLesson}
            updateLesson={updateLesson}
            lessons={lessons.filter(l => l.teacherId === auth.user?.id)} 
          />
        ) : (
          <SupervisorDashboard 
            lessons={lessons} 
            updateLesson={updateLesson} 
            teachers={teachers}
            onAddTeacher={handleAddTeacher}
            onDeleteTeacher={handleDeleteTeacher}
            onResetPassword={handleResetTeacherPassword}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy, User } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
  updateLesson: (lesson: Lesson) => void;
  teachers: User[];
  onAddTeacher: (id: string, name: string) => void;
  onDeleteTeacher: (id: string) => void;
  onResetPassword: (teacherId: string) => string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ lessons, updateLesson, teachers, onAddTeacher, onDeleteTeacher, onResetPassword }) => {
  const [activeTab, setActiveTab] = useState<'lessons' | 'accounts'>('lessons');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);
  const [obsNote, setObsNote] = useState('');
  const [isNotesExpanded, setIsNotesExpanded] = useState(true);

  // New teacher form state
  const [newTeacherName, setNewTeacherName] = useState('');
  const [newTeacherId, setNewTeacherId] = useState('');
  const [showAddForm, setShowAddForm] = useState(false);

  const teacherStats = useMemo(() => {
    return teachers.map(t => {
      const count = lessons.filter(l => l.teacherId === t.id).length;
      return { ...t, lessonCount: count };
    });
  }, [teachers, lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const handleConfirmVisit = () => {
    if (activeLesson) {
      updateLesson({ ...activeLesson, status: 'confirmed' });
      alert('تم اعتماد توثيق الزيارة بنجاح');
    }
  };

  const handleSaveObsNote = () => {
    if (activeLesson && obsNote.trim()) {
      updateLesson({ ...activeLesson, observationalNotes: obsNote });
      setObsNote('');
      alert('تم حفظ ملحوظة المشاهدة الإشرافية');
    }
  };

  const handleAddNewTeacher = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTeacherName || !newTeacherId) return alert('يرجى ملء كافة الحقول');
    onAddTeacher(newTeacherId, newTeacherName);
    setNewTeacherId('');
    setNewTeacherName('');
    setShowAddForm(false);
  };

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return <p className="text-[10px] text-slate-400 mt-2 italic">لا يوجد مرفقات تعليمية</p>;
    const { type, url, name } = strategy.attachment;

    switch(type) {
      case 'image':
        return (
          <div className="mt-3">
            <img src={url} alt={name} className="max-h-60 rounded-xl border-2 border-slate-100 shadow-md" />
            <p className="text-[10px] text-slate-400 mt-2 font-bold">🖼️ {name}</p>
          </div>
        );
      case 'video':
        return (
          <div className="mt-3">
            <video src={url} controls className="max-h-60 w-full rounded-xl shadow-lg bg-black" />
          </div>
        );
      case 'link':
        return (
          <div className="mt-3">
            <a href={url} target="_blank" rel="noopener noreferrer" className="text-sm text-white bg-indigo-600 px-6 py-3 rounded-xl font-black text-center block">فتح الرابط: {url}</a>
          </div>
        );
      case 'file':
        return (
          <div className="mt-3">
            <a href={url} download={name} className="inline-flex items-center gap-3 bg-emerald-50 text-emerald-700 px-6 py-4 rounded-2xl font-black border-2 border-emerald-100">تحميل: {name}</a>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="space-y-8 animate-fadeIn">
      {/* التبويبات العلوية */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-2xl">
          <button 
            onClick={() => { setActiveTab('lessons'); setSelectedTeacherId(null); setSelectedLessonId(null); }}
            className={`flex-1 px-4 py-4 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 ${activeTab === 'lessons' ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-indigo-50'}`}
          >
            <span className="text-xl">📋</span>
            <span>عرض الدروس</span>
          </button>
          <button 
            onClick={() => setActiveTab('accounts')}
            className={`flex-1 px-4 py-4 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 ${activeTab === 'accounts' ? 'bg-amber-500 text-white shadow-lg' : 'text-slate-500 hover:bg-amber-50'}`}
          >
            <span className="text-xl">👥</span>
            <span>إدارة الحسابات</span>
          </button>
        </div>
      </div>

      {activeTab === 'accounts' ? (
        <div className="space-y-8 animate-fadeIn">
          <div className="flex flex-col md:flex-row justify-between items-center bg-white p-8 rounded-[2.5rem] shadow-xl border border-slate-100 gap-6">
             <div>
               <h2 className="text-2xl font-black text-slate-900">سجل الهيئة التدريسية</h2>
               <p className="text-slate-500 font-bold">يمكنك إضافة معلمات جدد، حذف حسابات، أو تصفير كلمات المرور</p>
             </div>
             <button 
               onClick={() => setShowAddForm(!showAddForm)}
               className={`${showAddForm ? 'bg-slate-500' : 'bg-indigo-600'} text-white px-8 py-4 rounded-2xl font-black shadow-lg hover:opacity-90 active:scale-95 transition-all flex items-center gap-2`}
             >
               {showAddForm ? 'إلغاء الإضافة' : '+ إضافة معلمة جديدة'}
             </button>
          </div>

          {showAddForm && (
            <div className="bg-white p-10 rounded-[2.5rem] shadow-2xl border-4 border-indigo-50 animate-slideDown">
               <h3 className="text-lg font-black text-indigo-950 mb-6 flex items-center gap-2">
                 <span className="bg-indigo-100 p-2 rounded-lg text-indigo-600">👤</span> بيانات المعلمة الجديدة
               </h3>
               <form onSubmit={handleAddNewTeacher} className="grid grid-cols-1 md:grid-cols-3 gap-6 items-end">
                  <div>
                    <label className="block text-sm font-black text-slate-700 mb-2">الاسم الكامل</label>
                    <input type="text" value={newTeacherName} onChange={(e) => setNewTeacherName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-400 outline-none font-bold" placeholder="أدخل اسم المعلمة" />
                  </div>
                  <div>
                    <label className="block text-sm font-black text-slate-700 mb-2">الرقم الوظيفي (Username)</label>
                    <input type="text" value={newTeacherId} onChange={(e) => setNewTeacherId(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-400 outline-none font-bold text-center" placeholder="مثلاً: 12345" />
