                         >
                           <span className="flex items-center gap-2">📝 ملحوظات المشاهدة الفنية</span>
                           <span className="bg-white w-8 h-8 rounded-full flex items-center justify-center text-sm shadow-sm">{isNotesExpanded ? '▲' : '▼'}</span>
