                         <div className={`transition-all duration-300 overflow-hidden ${isNotesExpanded ? 'max-h-[500px] opacity-100' : 'max-h-0 opacity-0'}`}>
                           <div className="space-y-4 py-2">
                             <textarea 
                               value={obsNote || activeLesson?.observationalNotes || ''} 
                               onChange={(e) => setObsNote(e.target.value)}
                               className="w-full p-6 rounded-3xl border-2 border-white bg-white/80 min-h-[180px] font-bold text-slate-700 outline-none focus:border-indigo-300 shadow-inner"
                               placeholder="اكتب مرئياتك حول توظيف المادة العلمية ومستوى تفاعل الطالبات..."
