                      </div>
                   </div>

                   <div className="space-y-10">
                      <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl relative overflow-hidden group">
                         <div className="absolute top-0 right-0 w-2 h-full bg-indigo-600"></div>
