                         <p className="font-bold text-slate-600 leading-relaxed italic bg-slate-50 p-6 rounded-3xl">{activeLesson?.effectiveStrategiesDeployment || 'لا توجد تفاصيل.'}</p>
                      </div>

                      <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl relative overflow-hidden">
                         <div className="absolute top-0 right-0 w-2 h-full bg-emerald-500"></div>
                         <h4 className="font-black text-xl text-emerald-900 mb-6 flex items-center gap-2">📊 التقويم والقياس</h4>
                         <p className="font-bold text-slate-600 leading-relaxed bg-emerald-50/20 p-6 rounded-3xl">{activeLesson?.evaluationMethods || 'لا توجد تفاصيل.'}</p>
                      </div>

                      <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-xl relative overflow-hidden">
                         <div className="absolute top-0 right-0 w-2 h-full bg-amber-500"></div>
                         <h4 className="font-black text-xl text-amber-950 mb-6 flex items-center gap-2">📢 التوجيه الإشرافي</h4>
                         <p className="font-black text-amber-800 leading-relaxed bg-amber-50/50 p-6 rounded-3xl min-h-[100px] italic">
                            {activeLesson?.supervisorNotes || 'لم يتم إرسال توجيه فني بعد.'}
                         </p>
                      </div>
                   </div>
                </div>

                <div className="pt-10 border-t flex flex-wrap justify-end gap-6">
                  <button 
                    onClick={() => {
                      const d = prompt('أدخل التوجيه الفني الموجه للمعلمة:', activeLesson?.supervisorNotes || '');
                      if (d !== null && activeLesson) updateLesson({ ...activeLesson, supervisorNotes: d });
                    }}
                    className="bg-slate-900 text-white px-10 py-5 rounded-[2rem] font-black shadow-xl hover:bg-black transition-all active:scale-95 flex items-center gap-2"
                  >
                    <span>إرسال توجيه فني</span>
                    <span className="text-lg">📢</span>
                  </button>
                  {activeLesson?.status !== 'confirmed' && (
                    <button 
                      onClick={handleConfirmVisit} 
                      className="bg-indigo-600 text-white px-14 py-5 rounded-[2rem] font-black shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95 flex items-center gap-2"
