                      <span>اعتماد الزيارة</span>
                      <span className="text-lg">✓</span>
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default SupervisorDashboard;

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Lesson } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';
import ChangePasswordForm from './components/ChangePasswordForm';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [lessons, setLessons] = useState<Lesson[]>(() => {
    const saved = localStorage.getItem('app_lessons');
    return saved ? JSON.parse(saved) : [];
  });

  const [teachers, setTeachers] = useState<User[]>(() => {
    const saved = localStorage.getItem('app_teachers_list');
    return saved ? JSON.parse(saved) : [];
  });

  const [showChangePassword, setShowChangePassword] = useState(false);

  useEffect(() => {
    localStorage.setItem('app_lessons', JSON.stringify(lessons));
  }, [lessons]);

  useEffect(() => {
    localStorage.setItem('app_teachers_list', JSON.stringify(teachers));
  }, [teachers]);

  const handleLogin = (user: User) => {
    if (user.role === UserRole.TEACHER && user.mustChangePassword) {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(true);
    } else {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(false);
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setShowChangePassword(false);
  };

  const addLesson = (newLesson: Lesson) => {
    setLessons(prev => [{ ...newLesson, status: 'pending' }, ...prev]);
  };

  const deleteLesson = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الدرس؟')) {
      setLessons(prev => prev.filter(l => l.id !== id));
    }
  };

  const updateLesson = (updatedLesson: Lesson) => {
    setLessons(prev => prev.map(l => (l.id === updatedLesson.id ? updatedLesson : l)));
  };

  const handleAddTeacher = (id: string, name: string) => {
    const exists = teachers.find(t => t.id === id);
    if (exists) return alert('هذا الرقم الوظيفي موجود مسبقاً');

    const newTeacher: User = {
      id,
      code: id,
      name,
      role: UserRole.TEACHER,
      password: `pass${id}`,
      mustChangePassword: true
    };
    setTeachers(prev => [...prev, newTeacher]);
  };

  const handleDeleteTeacher = (teacherId: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذه المعلمة وجميع دروسها الموثقة؟')) {
      setTeachers(prev => prev.filter(t => t.id !== teacherId));
      setLessons(prev => prev.filter(l => l.teacherId !== teacherId));
    }
  };

  const handleResetTeacherPassword = (teacherId: string) => {
    const defaultPass = `pass${teacherId}`;
    setTeachers(prev => prev.map(t => 
      t.id === teacherId ? { ...t, password: defaultPass, mustChangePassword: true } : t
    ));
    return defaultPass;
  };

  const handlePasswordChanged = (newPassword: string) => {
    if (auth.user) {
      setTeachers(prev => prev.map(t => 
        t.id === auth.user!.id ? { ...t, password: newPassword, mustChangePassword: false } : t
      ));
      setAuth(prev => ({ 
        ...prev, 
        user: prev.user ? { ...prev.user, mustChangePassword: false } : null 
      }));
      setShowChangePassword(false);
      alert('تم تحديث كلمة المرور بنجاح');
    }
  };

  if (!auth.isAuthenticated) {
    return <LoginForm onLogin={handleLogin} teachers={teachers} />;
  }

  if (showChangePassword) {
    return <ChangePasswordForm onPasswordChanged={handlePasswordChanged} onLogout={handleLogout} />;
  }

  return (
    <div className="min-h-screen bg-[#fcfdfd] font-['Tajawal'] antialiased">
      {/* Navbar with higher z-index to prevent being covered */}
      <nav className="bg-white/90 backdrop-blur-md text-slate-900 shadow-sm sticky top-0 z-[100] border-b border-slate-100 h-24 flex items-center">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-4">
              <div className="bg-indigo-600 p-2 rounded-2xl shadow-indigo-100 shadow-lg">
                <img 
                  src="https://raw.githubusercontent.com/google/material-design-icons/master/png/action/school/materialicons/48dp/1x/baseline_school_white_48dp.png" 
                  alt="لوجو" 
                  className="w-10 h-10 object-contain"
                />
              </div>
              <div className="flex flex-col">
                <span className="text-xl font-black tracking-tight text-slate-900 leading-none mb-1">منصة المجال الأول</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">مدرسة الخضراء للتعليم الأساسي</span>
              </div>
            </div>
            <div className="flex items-center gap-4 md:gap-8">
              <div className="hidden md:flex flex-col items-end">
                <span className="text-sm font-black text-slate-800">{auth.user?.name}</span>
                <span className="text-[10px] font-bold text-indigo-500 uppercase">{auth.user?.role === UserRole.SUPERVISOR ? 'مشرفة تربوية' : 'معلمة المجال'}</span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-slate-50 text-slate-600 hover:bg-red-50 hover:text-red-600 px-5 py-2.5 rounded-2xl text-sm font-black transition-all active:scale-95 border border-slate-100"
              >
                خروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            addLesson={addLesson} 
            deleteLesson={deleteLesson}
            updateLesson={updateLesson}
            lessons={lessons.filter(l => l.teacherId === auth.user?.id)} 
          />
        ) : (
          <SupervisorDashboard 
            lessons={lessons} 
            updateLesson={updateLesson} 
            teachers={teachers}
            onAddTeacher={handleAddTeacher}
            onDeleteTeacher={handleDeleteTeacher}
            onResetPassword={handleResetTeacherPassword}
          />
        )}
      </main>

      <footer className="py-10 text-center text-slate-400 text-xs font-bold border-t border-slate-50 mt-10">
        جميع الحقوق محفوظة - مدرسة الخضراء للتعليم الأساسي © {new Date().getFullYear()}
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { User, Lesson, Strategy, AttachmentType } from '../types';
import { suggestStrategies } from '../services/geminiService';

interface TeacherDashboardProps {
  user: User;
  addLesson: (lesson: Lesson) => void;
  deleteLesson: (id: string) => void;
  updateLesson: (lesson: Lesson) => void;
  lessons: Lesson[];
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ user, addLesson, deleteLesson, updateLesson, lessons }) => {
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [loadingSuggestions, setLoadingSuggestions] = useState(false);
  const formRef = useRef<HTMLDivElement>(null);

  const [title, setTitle] = useState('');
  const [strategies, setStrategies] = useState<Strategy[]>([{ text: '' }]);
  const [selfLearning, setSelfLearning] = useState({
    thinking: false,
    collaboration: false,
    criticalThinking: false,
    higherOrderThinking: false,
  });
  const [deployment, setDeployment] = useState('');
  const [evaluations, setEvaluations] = useState('');
  const [values, setValues] = useState('');

  const handleAddStrategy = () => {
    if (strategies.length < 10) {
      setStrategies([...strategies, { text: '' }]);
    }
  };

  const handleRemoveStrategy = (index: number) => {
    const newStrats = strategies.filter((_, i) => i !== index);
    setStrategies(newStrats);
  };

  const updateStrategyText = (index: number, val: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], text: val };
    setStrategies(newStrats);
  };

  const setStrategyAttachment = (index: number, type: AttachmentType, url: string, name?: string) => {
    const newStrats = [...strategies];
    newStrats[index] = { ...newStrats[index], attachment: { type, url, name: name || 'مرفق تعليمي' } };
    setStrategies(newStrats);
  };

  const removeAttachment = (index: number) => {
    const newStrats = [...strategies];
    delete newStrats[index].attachment;
    setStrategies(newStrats);
  };

  const handleFileChange = (index: number, type: AttachmentType, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setStrategyAttachment(index, type, reader.result as string, file.name);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddLink = (index: number) => {
    const url = prompt('يرجى إدخال عنوان الرابط (URL) الخاص بالاستراتيجية:');
    if (url && url.trim()) {
      let formattedUrl = url.trim();
      if (!formattedUrl.startsWith('http')) {
        formattedUrl = 'https://' + formattedUrl;
      }
      setStrategyAttachment(index, 'link', formattedUrl, 'رابط إلكتروني');
    }
  };

  const handleSuggest = async () => {
    if (!title) return alert('يرجى كتابة عنوان الدرس أولاً');
    setLoadingSuggestions(true);
    const suggested = await suggestStrategies(title);
    setStrategies(suggested.slice(0, 10).map(s => ({ text: s })));
    setLoadingSuggestions(false);
  };

  const handleEdit = (lesson: Lesson) => {
    setEditingId(lesson.id);
    setTitle(lesson.title);
    setStrategies(lesson.strategies.length > 0 ? lesson.strategies : [{ text: '' }]);
    setSelfLearning(lesson.selfLearningSkills);
    setDeployment(lesson.effectiveStrategiesDeployment);
    setEvaluations(lesson.evaluationMethods);
    setValues(lesson.valuesAndCitizenship);
    setShowForm(true);
    setTimeout(() => {
      formRef.current?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }, 100);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const finalStrategies = strategies.filter(s => s.text.trim() !== '');

    const lessonData: Lesson = {
      id: editingId || Math.random().toString(36).substr(2, 9),
      teacherId: user.id,
      teacherName: user.name,
      title,
      strategiesCount: finalStrategies.length,
      strategies: finalStrategies,
      selfLearningSkills: selfLearning,
      effectiveStrategiesDeployment: deployment,
      evaluationMethods: evaluations,
      valuesAndCitizenship: values,
      createdAt: editingId ? (lessons.find(l => l.id === editingId)?.createdAt || new Date().toLocaleDateString('ar-SA')) : new Date().toLocaleDateString('ar-SA'),
      status: editingId ? lessons.find(l => l.id === editingId)?.status : 'pending',
      supervisorNotes: editingId ? lessons.find(l => l.id === editingId)?.supervisorNotes : undefined,
      observationalNotes: editingId ? lessons.find(l => l.id === editingId)?.observationalNotes : undefined
    };

    if (editingId) {
      updateLesson(lessonData);
    } else {
      addLesson(lessonData);
    }

    resetForm();
    setShowForm(false);
  };

  const resetForm = () => {
    setEditingId(null);
    setTitle('');
    setStrategies([{ text: '' }]);
    setSelfLearning({
      thinking: false,
      collaboration: false,
      criticalThinking: false,
      higherOrderThinking: false,
    });
    setDeployment('');
    setEvaluations('');
    setValues('');
  };

  return (
    <div className="space-y-12 animate-fadeIn">
      {/* Header Section */}
      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center gap-5">
           <div className="w-16 h-16 bg-indigo-50 rounded-2xl flex items-center justify-center text-3xl shadow-inner">
             👩‍🏫
           </div>
           <div>
             <h2 className="text-2xl font-black text-slate-800">أهلاً بك، {user.name}</h2>
             <p className="text-slate-400 font-bold text-sm">هنا يمكنك توثيق دروسك ومتابعة تقييمات المشرفين.</p>
           </div>
        </div>
        <button
          onClick={() => { if (showForm) resetForm(); setShowForm(!showForm); }}
          className={`${showForm ? 'bg-slate-100 text-slate-600' : 'bg-indigo-600 text-white shadow-xl shadow-indigo-100'} px-10 py-4 rounded-[2rem] font-black transition-all active:scale-95 flex items-center gap-3 hover:opacity-90`}
        >
          {showForm ? 'إلغاء التوثيق' : <><span className="text-xl">+</span> إضافة درس جديد</>}
        </button>
      </div>

      {showForm && (
        <div ref={formRef} className="bg-white rounded-[3rem] shadow-2xl p-10 border-t-[12px] border-indigo-600 animate-slideDown relative">
          <div className="mb-10">
            <h3 className="text-2xl font-black text-slate-900 mb-2">نموذج توثيق الزيارة الإشرافية</h3>
            <div className="w-20 h-1.5 bg-indigo-100 rounded-full"></div>
          </div>

          <form onSubmit={handleSubmit} className="space-y-10">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-12">
              <div className="space-y-8">
                <div>
                  <label className="block text-sm font-black text-slate-600 mb-3 pr-2">عنوان الدرس / الموضوع التعليمي</label>
                  <input type="text" required value={title} onChange={(e) => setTitle(e.target.value)} className="w-full px-8 py-5 rounded-3xl bg-slate-50 border-2 border-slate-50 focus:border-indigo-500 focus:bg-white transition-all outline-none font-black text-lg shadow-sm" placeholder="أدخل اسم الدرس..." />
                </div>

                <div>
                  <div className="flex justify-between items-center mb-4 pr-2">
                    <label className="text-sm font-black text-slate-600">استراتيجيات التدريس (الحد الأقصى 10)</label>
                    <button type="button" onClick={handleSuggest} disabled={loadingSuggestions} className={`text-xs font-black px-4 py-2 rounded-xl transition-all border ${loadingSuggestions ? 'bg-slate-50 text-slate-300' : 'text-indigo-600 bg-indigo-50 hover:bg-indigo-100 border-indigo-100'}`}>
                      {loadingSuggestions ? 'جاري التحليل... ⌛' : '🤖 اقتراحات ذكية'}
                    </button>
                  </div>
                  <div className="space-y-4 bg-slate-50 p-6 rounded-[2.5rem] border-2 border-slate-50 max-h-[500px] overflow-y-auto custom-scrollbar shadow-inner">
                    {strategies.map((strat, idx) => (
                      <div key={idx} className="bg-white p-5 rounded-2xl shadow-sm border border-slate-100 space-y-4 animate-fadeIn">
                        <div className="flex gap-3">
                          <span className="bg-indigo-600 text-white w-10 h-10 rounded-xl flex items-center justify-center font-black text-sm shrink-0">{idx+1}</span>
                          <input type="text" value={strat.text} onChange={(e) => updateStrategyText(idx, e.target.value)} className="flex-1 text-sm bg-slate-50 border-0 rounded-xl px-5 py-3 focus:ring-2 focus:ring-indigo-100 outline-none font-bold text-slate-800" placeholder="اسم الاستراتيجية" />
                          <button type="button" onClick={() => handleRemoveStrategy(idx)} className="text-slate-300 hover:text-red-500 transition-colors text-xl font-bold">×</button>
                        </div>
                        <div className="flex flex-wrap gap-2 pr-12">
                           {!strat.attachment ? (
                             <div className="flex flex-wrap gap-2">
                               <label className="cursor-pointer bg-white hover:bg-indigo-50 px-4 py-2 rounded-xl text-[10px] font-black transition-all border border-slate-100 flex items-center gap-2">🖼️ صورة <input type="file" accept="image/*" className="hidden" onChange={(e) => handleFileChange(idx, 'image', e)} /></label>
                               <label className="cursor-pointer bg-white hover:bg-indigo-50 px-4 py-2 rounded-xl text-[10px] font-black transition-all border border-slate-100 flex items-center gap-2">🎥 فيديو <input type="file" accept="video/*" className="hidden" onChange={(e) => handleFileChange(idx, 'video', e)} /></label>
                               <label className="cursor-pointer bg-white hover:bg-indigo-50 px-4 py-2 rounded-xl text-[10px] font-black transition-all border border-slate-100 flex items-center gap-2">📄 ملف <input type="file" className="hidden" onChange={(e) => handleFileChange(idx, 'file', e)} /></label>
                               <button type="button" onClick={() => handleAddLink(idx)} className="bg-white hover:bg-indigo-50 px-4 py-2 rounded-xl text-[10px] font-black transition-all border border-slate-100 flex items-center gap-2">🔗 رابط URL</button>
                             </div>
                           ) : (
                             <div className="flex items-center gap-3 bg-emerald-50 text-emerald-700 px-4 py-2 rounded-xl text-[10px] font-black border border-emerald-100 w-full justify-between">
                                <span className="truncate flex items-center gap-2">
                                  {strat.attachment.type === 'link' ? '🔗 رابط: ' : '📎 مرفق: '}
                                  <span className="opacity-70">{strat.attachment.name || strat.attachment.url.substring(0, 20)}...</span>
                                </span>
                                <button type="button" onClick={() => removeAttachment(idx)} className="text-red-500 hover:scale-110 transition-transform font-black">حذف</button>
                             </div>
                           )}
                        </div>
                      </div>
                    ))}
                    {strategies.length < 10 && (
                      <button type="button" onClick={handleAddStrategy} className="w-full py-4 bg-white border-2 border-dashed border-indigo-200 rounded-2xl text-indigo-600 font-black text-sm hover:bg-indigo-50 transition-all">
                        + إضافة استراتيجية جديدة
                      </button>
                    )}
                  </div>
                </div>
              </div>

              <div className="space-y-10">
                <div className="bg-white rounded-3xl p-6 border-2 border-slate-50 shadow-sm">
                  <label className="block text-sm font-black text-slate-600 mb-6 pr-2">مهارات التعلم الذاتي الموظفة</label>
                  <div className="grid grid-cols-2 gap-4">
                    {Object.keys(selfLearning).map((key) => (
                      <label key={key} className={`flex items-center gap-4 p-5 rounded-2xl cursor-pointer transition-all border-2 ${selfLearning[key as keyof typeof selfLearning] ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-slate-50 border-slate-50 text-slate-500 hover:border-indigo-100'}`}>
                        <input type="checkbox" checked={selfLearning[key as keyof typeof selfLearning]} onChange={(e) => setSelfLearning({ ...selfLearning, [key]: e.target.checked })} className="w-5 h-5 rounded border-0" />
                        <span className="text-sm font-black">{key === 'thinking' ? 'التفكير الإبداعي' : key === 'collaboration' ? 'التعلم التعاوني' : key === 'criticalThinking' ? 'التفكير الناقد' : 'مهارات التفكير العليا'}</span>
                      </label>
                    ))}
                  </div>
                </div>

                <div className="space-y-6">
                  <div>
                    <label className="block text-sm font-black text-slate-600 mb-3 pr-2">آلية توظيف الاستراتيجيات فنيًا</label>
                    <textarea rows={5} value={deployment} onChange={(e) => setDeployment(e.target.value)} className="w-full p-6 bg-slate-50 border-2 border-slate-50 rounded-[2rem] outline-none focus:border-indigo-500 focus:bg-white font-bold text-sm shadow-inner transition-all" placeholder="صفي كيف تم دمج الاستراتيجيات المختارة في سير الحصة..." />
                  </div>
                  <div>
                    <label className="block text-sm font-black text-slate-600 mb-3 pr-2">أساليب التقويم والقياس</label>
                    <textarea rows={3} value={evaluations} onChange={(e) => setEvaluations(e.target.value)} className="w-full p-6 bg-slate-50 border-2 border-slate-50 rounded-[2rem] outline-none focus:border-indigo-500 focus:bg-white font-bold text-sm shadow-inner transition-all" placeholder="ما هي الأدوات التي استخدمتِها لقياس أثر التعلم؟" />
                  </div>
                </div>
              </div>
            </div>

            <div className="flex flex-col md:flex-row justify-end pt-10 border-t border-slate-50 gap-4">
              <button type="button" onClick={() => { setShowForm(false); resetForm(); }} className="px-10 py-5 rounded-2xl font-black bg-slate-100 text-slate-500 hover:bg-slate-200 transition-all">إلغاء الحفظ</button>
              <button type="submit" className="px-16 py-5 rounded-2xl font-black bg-indigo-600 text-white shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95 flex items-center justify-center gap-3">
                نشر التوثيق واعتماده ✓
              </button>
            </div>
          </form>
        </div>
      )}

      {/* Instructional Courses Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10 pb-20">
        {lessons.length === 0 ? (
          <div className="col-span-full py-32 text-center bg-white rounded-[3rem] border-4 border-dashed border-slate-100 flex flex-col items-center">
            <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center text-4xl mb-6">📂</div>
            <p className="text-slate-400 font-black text-xl mb-2">سجل الدروس فارغ حالياً</p>
            <p className="text-slate-300 font-bold text-sm">ابدئي بإضافة أول درس موثق لك من الزر أعلاه</p>
          </div>
        ) : (
          lessons.map((lesson) => (
            <div key={lesson.id} className="bg-white rounded-[2.5rem] shadow-sm hover:shadow-2xl transition-all duration-500 flex flex-col overflow-hidden relative group border border-slate-100 transform hover:-translate-y-2">
              <div className={`p-6 text-white font-black flex justify-between items-center ${lesson.status === 'confirmed' ? 'bg-emerald-600' : 'bg-amber-500'}`}>
                <div className="flex items-center gap-2">
                   <div className="w-2 h-2 rounded-full bg-white animate-pulse"></div>
                   <span className="text-[10px] uppercase tracking-widest">{lesson.status === 'confirmed' ? 'تم الاعتماد النهائي' : 'بانتظار مراجعة المشرفة'}</span>
                </div>
                <div className="flex gap-2 relative z-20">
                  <button onClick={() => handleEdit(lesson)} className="hover:bg-white/20 p-2 rounded-xl transition-colors">✎</button>
                  <button onClick={() => deleteLesson(lesson.id)} className="hover:bg-white/20 p-2 rounded-xl transition-colors">🗑️</button>
                </div>
              </div>

              <div className="p-8 flex-1 flex flex-col space-y-6">
                <div className="mb-2">
                  <div className="flex items-center gap-2 text-indigo-500 font-bold text-[10px] mb-2 uppercase">
                     <span>📅 {lesson.createdAt}</span>
                  </div>
                  <h3 className="text-xl font-black text-slate-800 leading-tight mb-2 group-hover:text-indigo-600 transition-colors line-clamp-2">{lesson.title}</h3>
                </div>

                <div className="space-y-4">
                  {lesson.observationalNotes && (
                    <div className="bg-indigo-50/50 p-5 rounded-2xl border-2 border-indigo-100 relative group/note">
                      <div className="text-[9px] font-black text-indigo-600 mb-1 flex items-center gap-1">
                        <span>🔎 ملحوظة مشاهدة إشرافية</span>
                      </div>
                      <p className="text-xs text-slate-700 font-bold leading-relaxed line-clamp-3">{lesson.observationalNotes}</p>
                    </div>
                  )}
                  {lesson.supervisorNotes && (
                    <div className="bg-amber-50/50 p-5 rounded-2xl border-2 border-amber-100 relative group/note">
                      <div className="text-[9px] font-black text-amber-600 mb-1 flex items-center gap-1">
                        <span>📢 توجيهات فنية للتطوير</span>
                      </div>
                      <p className="text-xs text-slate-700 font-bold leading-relaxed line-clamp-3">{lesson.supervisorNotes}</p>
                    </div>
                  )}
                </div>

                <div className="pt-6 border-t border-slate-50 flex items-center justify-between mt-auto">
                   <div className="flex gap-1.5 overflow-hidden">
                      <span className="bg-slate-50 text-slate-500 px-3 py-1.5 rounded-lg text-[9px] font-black shrink-0 border border-slate-100">⚡ {lesson.strategiesCount} استراتيجيات</span>
                      {lesson.selfLearningSkills.thinking && <span className="bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-lg text-[9px] font-black shrink-0 border border-indigo-100">تفكير</span>}
                   </div>
                   <div className="text-[9px] font-black text-slate-300 italic">ID: {lesson.id.slice(0, 5)}</div>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

