            <div className="bg-white rounded-[2.5rem] shadow-sm p-6 border border-slate-100 sticky top-32 max-h-[calc(100vh-10rem)] overflow-y-auto custom-scrollbar z-30">
              <h3 className="text-lg font-black text-slate-800 mb-6 pr-3 border-r-4 border-indigo-600">سجلات المعلمات</h3>
              <div className="space-y-3">
                {teacherStats.map(t => (
                  <button
