                    <span className="font-black text-lg leading-tight">{t.name}</span>
                    <span className={`text-[10px] font-bold ${selectedTeacherId === t.id ? 'text-indigo-100' : 'text-slate-400'}`}>{t.lessonCount} دروس موثقة</span>
                  </button>
                ))}
              </div>
            </div>
          </div>

          <div className="lg:col-span-3 space-y-8 min-h-[600px]">
            {!selectedTeacherId ? (
              <div className="bg-white rounded-[3rem] shadow-sm p-32 text-center border-2 border-dashed border-slate-100 flex flex-col items-center justify-center">
                 <div className="bg-indigo-50 w-24 h-24 rounded-full flex items-center justify-center text-4xl mb-8 shadow-inner">👋</div>
                 <h3 className="text-2xl font-black text-slate-800">أهلاً بك مشرفة المجال الأول</h3>
                 <p className="text-slate-400 font-bold mt-3">يرجى اختيار معلمة من القائمة لاستعراض دروسها الموثقة وتقييم أدائها الفني.</p>
              </div>
            ) : !selectedLessonId ? (
              <div className="space-y-8 animate-fadeIn">
                <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border-r-[12px] border-indigo-600 flex justify-between items-center">
                  <div>
                    <h2 className="text-2xl font-black text-slate-900">سجل: {teachers.find(t => t.id === selectedTeacherId)?.name}</h2>
                    <p className="text-slate-400 text-xs font-bold">عرض كافة الدروس الموثقة ضمن زيارات المجال</p>
                  </div>
                  <button onClick={() => setSelectedTeacherId(null)} className="text-indigo-600 font-black hover:underline text-sm">عودة للقائمة</button>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-8">
                  {teacherLessons.length === 0 ? (
                    <div className="col-span-full py-20 bg-white rounded-[2.5rem] text-center border-2 border-dashed border-slate-100 text-slate-300 font-black">لا توجد دروس موثقة لهذه المعلمة</div>
                  ) : (
                    teacherLessons.map(lesson => (
                      <div key={lesson.id} className="bg-white rounded-[2.5rem] shadow-sm hover:shadow-xl p-8 border border-slate-100 flex flex-col transition-all group">
                        <div className="flex justify-between items-start mb-8">
                           <span className={`px-4 py-2 rounded-xl text-[10px] font-black ${lesson.status === 'confirmed' ? 'bg-emerald-50 text-emerald-600' : 'bg-amber-50 text-amber-600'}`}>
                             {lesson.status === 'confirmed' ? '✓ معتمد' : '● بانتظار الاعتماد'}
                           </span>
                           <span className="text-[10px] text-slate-300 font-bold tracking-widest">{lesson.createdAt}</span>
                        </div>
                        <h4 className="font-black text-slate-800 text-xl leading-snug mb-10 flex-1 group-hover:text-indigo-600 transition-colors">{lesson.title}</h4>
                        <button 
                          onClick={() => setSelectedLessonId(lesson.id)} 
                          className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black hover:bg-indigo-600 transition-all shadow-lg active:scale-95"
                        >
                          عرض تفاصيل الزيارة
                        </button>
                      </div>
                    ))
                  )}
                </div>
              </div>
            ) : (
              /* Detail View with polished instructional layout */
              <div className="bg-white rounded-[3rem] shadow-2xl p-10 space-y-12 animate-slideUp border border-slate-50 relative">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center border-b border-slate-50 pb-8 gap-6">
                  <div className="flex items-center gap-4">
                    <button onClick={() => setSelectedLessonId(null)} className="bg-slate-100 text-slate-600 p-3 rounded-2xl hover:bg-slate-200 transition">←</button>
                    <div>
                      <h3 className="text-3xl font-black text-slate-900 leading-tight">{activeLesson?.title}</h3>
                      <div className="flex gap-4 mt-2">
                        <span className="text-indigo-500 font-black text-[10px]">👤 {activeLesson?.teacherName}</span>
                        <span className="text-slate-400 font-bold text-[10px]">📅 {activeLesson?.createdAt}</span>
                      </div>
                    </div>
                  </div>
                  <div className={`px-8 py-4 rounded-[1.5rem] font-black text-xs ${activeLesson?.status === 'confirmed' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'}`}>
                    {activeLesson?.status === 'confirmed' ? 'الزيارة معتمدة' : 'الحالة: قيد التقييم'}
                  </div>
                </div>

                <div className="grid grid-cols-1 xl:grid-cols-2 gap-12">
                   <div className="space-y-12">
                      <div className="bg-slate-50/50 p-8 rounded-[2.5rem] border-2 border-white shadow-xl">
                         <button 
                           onClick={() => setIsNotesExpanded(!isNotesExpanded)}
                           className="w-full flex justify-between items-center font-black text-xl text-slate-900 mb-6"
                         >
                           <span className="flex items-center gap-3">
                             <span className="bg-indigo-600 w-2 h-8 rounded-full"></span>
                             ملحوظات المشاهدة الفنية
                           </span>
                           <span className="bg-white w-10 h-10 rounded-full flex items-center justify-center text-xs shadow-sm">{isNotesExpanded ? '▲' : '▼'}</span>
                         </button>
                         <div className={`transition-all duration-500 overflow-hidden ${isNotesExpanded ? 'max-h-[1000px] opacity-100' : 'max-h-0 opacity-0'}`}>
                           <div className="space-y-6">
                             <textarea 
                               value={obsNote || activeLesson?.observationalNotes || ''} 
                               onChange={(e) => setObsNote(e.target.value)}
                               className="w-full p-8 rounded-[2rem] border-2 border-white bg-white/80 min-h-[220px] font-bold text-slate-700 outline-none focus:border-indigo-300 shadow-inner"
                               placeholder="اكتب مرئياتك حول توظيف المادة العلمية ومستوى تفاعل الطالبات..."
                             />
                             <button onClick={handleSaveObsNote} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-2xl shadow-indigo-100 active:scale-95 transition-all">حفظ ملحوظات الزيارة</button>
                           </div>
                         </div>
                      </div>

                      <div className="space-y-8">
                        <h4 className="text-2xl font-black text-slate-800 pr-4">توثيق الاستراتيجيات</h4>
                        <div className="grid grid-cols-1 gap-6">
                          {activeLesson?.strategies.map((s, i) => (
                            <div key={i} className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
                              <div className="font-black text-slate-800 text-lg mb-6 flex gap-4">
                                <span className="bg-indigo-50 text-indigo-600 w-10 h-10 rounded-xl flex items-center justify-center text-sm shrink-0 border border-indigo-100">{i+1}</span>
                                <span className="pt-2">{s.text}</span>
                              </div>
                              <div className="bg-slate-50 p-4 rounded-2xl border border-dashed">
                                {renderAttachment(s)}
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                   </div>

                   <div className="space-y-12">
                      <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm relative overflow-hidden group">
                         <h4 className="font-black text-lg text-slate-900 mb-6 flex items-center gap-3">
                           <span className="bg-indigo-50 p-2 rounded-lg text-indigo-600">⚙️</span> 
                           آلية التوظيف والممارسة
                         </h4>
                         <p className="font-bold text-slate-500 leading-relaxed italic bg-slate-50/50 p-8 rounded-3xl border border-white shadow-inner">{activeLesson?.effectiveStrategiesDeployment || 'لا توجد تفاصيل.'}</p>
                      </div>

                      <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm">
                         <h4 className="font-black text-lg text-slate-900 mb-6 flex items-center gap-3">
                           <span className="bg-emerald-50 p-2 rounded-lg text-emerald-600">📊</span>
                           التقويم والقياس القبلي/البعدي
                         </h4>
                         <p className="font-bold text-slate-500 leading-relaxed bg-emerald-50/20 p-8 rounded-3xl border border-white shadow-inner">{activeLesson?.evaluationMethods || 'لا توجد تفاصيل.'}</p>
                      </div>

                      <div className="bg-gradient-to-br from-amber-50 to-amber-100/50 p-10 rounded-[3rem] border border-amber-200 shadow-sm relative">
                         <h4 className="font-black text-lg text-amber-900 mb-6 flex items-center gap-3">
                           <span className="bg-amber-600 text-white p-2 rounded-lg text-sm shadow-sm">📢</span>
                           التوجيه الإشرافي للتطوير
                         </h4>
                         <div className="font-black text-amber-800 leading-relaxed bg-white/60 p-8 rounded-3xl min-h-[120px] italic border border-amber-100">
                            {activeLesson?.supervisorNotes || 'بانتظار إضافة التوجيه الفني من قبلك...'}
                         </div>
                      </div>
                   </div>
                </div>

                <div className="pt-12 border-t border-slate-50 flex flex-col md:flex-row justify-end gap-6">
                  <button 
                    onClick={() => {
                      const d = prompt('أدخل التوجيه الفني المطور للمعلمة:', activeLesson?.supervisorNotes || '');
                      if (d !== null && activeLesson) updateLesson({ ...activeLesson, supervisorNotes: d });
                    }}
                    className="bg-slate-900 text-white px-10 py-5 rounded-[2rem] font-black shadow-xl hover:bg-black transition-all active:scale-95 flex items-center justify-center gap-3"
                  >
                    <span>تعديل التوجيه الفني</span>
                    <span className="text-xl">📢</span>
                  </button>
                  {activeLesson?.status !== 'confirmed' && (
                    <button 
                      onClick={handleConfirmVisit} 
                      className="bg-indigo-600 text-white px-16 py-5 rounded-[2rem] font-black shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95 flex items-center justify-center gap-4"
                    >
                      <span>اعتماد وتوثيق الزيارة</span>
                      <span className="text-xl">✓</span>
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default SupervisorDashboard;

export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  code: string;
  password?: string;
  mustChangePassword?: boolean;
}

export type AttachmentType = 'link' | 'image' | 'video' | 'file';

export interface Strategy {
  text: string;
  attachment?: {
    type: AttachmentType;
    url: string;
    name?: string;
  };
}

export interface ProjectEvaluation {
  teacherId: string;
  performanceScore: number; // 1-10
  engagementScore: number; // 1-10
  feedback: string;
  updatedAt: string;
}

export interface Project {
  id: string;
  name: string;
  description: string;
  createdAt: string;
  evaluations: Record<string, ProjectEvaluation>; // teacherId -> Evaluation
}

export interface Lesson {
  id: string;
  teacherId: string;
  teacherName: string;
  title: string;
  strategiesCount: number;
  strategies: Strategy[];
  selfLearningSkills: {
    thinking: boolean;
    collaboration: boolean;
    criticalThinking: boolean;
    higherOrderThinking: boolean;
  };
  effectiveStrategiesDeployment: string;
  evaluationMethods: string;
  valuesAndCitizenship: string;
  createdAt: string;
  status?: 'pending' | 'confirmed';
  supervisorNotes?: string;
  observationalNotes?: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Lesson, Project, ProjectEvaluation } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';
import ChangePasswordForm from './components/ChangePasswordForm';

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [lessons, setLessons] = useState<Lesson[]>(() => {
    const saved = localStorage.getItem('app_lessons');
    return saved ? JSON.parse(saved) : [];
  });

  const [teachers, setTeachers] = useState<User[]>(() => {
    const saved = localStorage.getItem('app_teachers_list');
    return saved ? JSON.parse(saved) : [];
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('app_projects');
    return saved ? JSON.parse(saved) : [];
  });

  const [showChangePassword, setShowChangePassword] = useState(false);

  useEffect(() => {
    localStorage.setItem('app_lessons', JSON.stringify(lessons));
  }, [lessons]);

  useEffect(() => {
    localStorage.setItem('app_teachers_list', JSON.stringify(teachers));
  }, [teachers]);

  useEffect(() => {
    localStorage.setItem('app_projects', JSON.stringify(projects));
  }, [projects]);

  const handleLogin = (user: User) => {
    if (user.role === UserRole.TEACHER && user.mustChangePassword) {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(true);
    } else {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(false);
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setShowChangePassword(false);
  };

  const addLesson = (newLesson: Lesson) => {
    setLessons(prev => [{ ...newLesson, status: 'pending' }, ...prev]);
  };

  const deleteLesson = (id: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا الدرس؟')) {
      setLessons(prev => prev.filter(l => l.id !== id));
    }
  };

  const updateLesson = (updatedLesson: Lesson) => {
    setLessons(prev => prev.map(l => (l.id === updatedLesson.id ? updatedLesson : l)));
  };

  const handleAddTeacher = (id: string, name: string) => {
    const exists = teachers.find(t => t.id === id);
    if (exists) return alert('هذا الرقم الوظيفي موجود مسبقاً');

    const newTeacher: User = {
      id,
      code: id,
      name,
      role: UserRole.TEACHER,
      password: `pass${id}`,
      mustChangePassword: true
    };
    setTeachers(prev => [...prev, newTeacher]);
  };

  const handleDeleteTeacher = (teacherId: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذه المعلمة وجميع دروسها الموثقة؟')) {
      setTeachers(prev => prev.filter(t => t.id !== teacherId));
      setLessons(prev => prev.filter(l => l.teacherId !== teacherId));
    }
  };

  const handleResetTeacherPassword = (teacherId: string) => {
    const defaultPass = `pass${teacherId}`;
    setTeachers(prev => prev.map(t => 
      t.id === teacherId ? { ...t, password: defaultPass, mustChangePassword: true } : t
    ));
    return defaultPass;
  };

  const handleAddProject = (name: string, description: string) => {
    const newProject: Project = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      description,
      createdAt: new Date().toLocaleDateString('ar-SA'),
      evaluations: {}
    };
    setProjects(prev => [newProject, ...prev]);
  };

  const handleDeleteProject = (projectId: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا المشروع نهائياً؟')) {
      setProjects(prev => prev.filter(p => p.id !== projectId));
    }
  };

  const handleUpdateEvaluation = (projectId: string, evalData: ProjectEvaluation) => {
    setProjects(prev => prev.map(p => {
      if (p.id === projectId) {
        return {
          ...p,
          evaluations: {
            ...p.evaluations,
            [evalData.teacherId]: evalData
          }
        };
      }
      return p;
    }));
  };

  const handlePasswordChanged = (newPassword: string) => {
    if (auth.user) {
      setTeachers(prev => prev.map(t => 
        t.id === auth.user!.id ? { ...t, password: newPassword, mustChangePassword: false } : t
      ));
      setAuth(prev => ({ 
        ...prev, 
        user: prev.user ? { ...prev.user, mustChangePassword: false } : null 
      }));
      setShowChangePassword(false);
      alert('تم تحديث كلمة المرور بنجاح');
    }
  };

  if (!auth.isAuthenticated) {
    return <LoginForm onLogin={handleLogin} teachers={teachers} />;
  }

  if (showChangePassword) {
    return <ChangePasswordForm onPasswordChanged={handlePasswordChanged} onLogout={handleLogout} />;
  }

  return (
    <div className="min-h-screen bg-[#fcfdfd] font-['Tajawal'] antialiased">
      <nav className="bg-white/90 backdrop-blur-md text-slate-900 shadow-sm sticky top-0 z-[100] border-b border-slate-100 h-24 flex items-center">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-4">
              <div className="bg-indigo-600 p-2 rounded-2xl shadow-indigo-100 shadow-lg">
                <img 
                  src="https://raw.githubusercontent.com/google/material-design-icons/master/png/action/school/materialicons/48dp/1x/baseline_school_white_48dp.png" 
                  alt="لوجو" 
                  className="w-10 h-10 object-contain"
                />
              </div>
              <div className="flex flex-col">
                <span className="text-xl font-black tracking-tight text-slate-900 leading-none mb-1">منصة المجال الأول</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">مدرسة الخضراء للتعليم الأساسي</span>
              </div>
            </div>
            <div className="flex items-center gap-4 md:gap-8">
              <div className="hidden md:flex flex-col items-end">
                <span className="text-sm font-black text-slate-800">{auth.user?.name}</span>
                <span className="text-[10px] font-bold text-indigo-500 uppercase">{auth.user?.role === UserRole.SUPERVISOR ? 'مشرفة تربوية' : 'معلمة المجال'}</span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-slate-50 text-slate-600 hover:bg-red-50 hover:text-red-600 px-5 py-2.5 rounded-2xl text-sm font-black transition-all active:scale-95 border border-slate-100"
              >
                خروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            addLesson={addLesson} 
            deleteLesson={deleteLesson}
            updateLesson={updateLesson}
            lessons={lessons.filter(l => l.teacherId === auth.user?.id)} 
            projects={projects}
          />
        ) : (
          <SupervisorDashboard 
            lessons={lessons} 
            updateLesson={updateLesson} 
            teachers={teachers}
            projects={projects}
            onAddTeacher={handleAddTeacher}
            onDeleteTeacher={handleDeleteTeacher}
            onResetPassword={handleResetTeacherPassword}
            onAddProject={handleAddProject}
            onDeleteProject={handleDeleteProject}
            onUpdateEvaluation={handleUpdateEvaluation}
          />
        )}
      </main>

      <footer className="py-10 text-center text-slate-400 text-xs font-bold border-t border-slate-50 mt-10">
        جميع الحقوق محفوظة - مدرسة الخضراء للتعليم الأساسي © {new Date().getFullYear()}
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy, User, Project, ProjectEvaluation } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
  updateLesson: (lesson: Lesson) => void;
  teachers: User[];
  projects: Project[];
  onAddTeacher: (id: string, name: string) => void;
  onDeleteTeacher: (id: string) => void;
  onResetPassword: (teacherId: string) => string;
  onAddProject: (name: string, description: string) => void;
  onDeleteProject: (projectId: string) => void;
  onUpdateEvaluation: (projectId: string, evalData: ProjectEvaluation) => void;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ 
  lessons, updateLesson, teachers, projects, 
  onAddTeacher, onDeleteTeacher, onResetPassword,
  onAddProject, onDeleteProject, onUpdateEvaluation
}) => {
  const [activeTab, setActiveTab] = useState<'lessons' | 'accounts' | 'projects'>('lessons');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);
  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(null);
  const [obsNote, setObsNote] = useState('');
  const [isNotesExpanded, setIsNotesExpanded] = useState(true);

  // Forms state
  const [newTeacherName, setNewTeacherName] = useState('');
  const [newTeacherId, setNewTeacherId] = useState('');
  const [showAddForm, setShowAddForm] = useState(false);

  const [newProjectName, setNewProjectName] = useState('');
  const [newProjectDesc, setNewProjectDesc] = useState('');
  const [showProjectForm, setShowProjectForm] = useState(false);

  // Evaluation form state for a specific teacher in a project
  const [editingEval, setEditingEval] = useState<{ teacherId: string; performance: number; engagement: number; feedback: string } | null>(null);

  const teacherStats = useMemo(() => {
    return teachers.map(t => {
      const count = lessons.filter(l => l.teacherId === t.id).length;
      return { ...t, lessonCount: count };
    });
  }, [teachers, lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const activeProject = useMemo(() => {
    return projects.find(p => p.id === selectedProjectId);
  }, [projects, selectedProjectId]);

  const handleConfirmVisit = () => {
    if (activeLesson) {
      updateLesson({ ...activeLesson, status: 'confirmed' });
      alert('تم اعتماد توثيق الزيارة بنجاح');
    }
  };

  const handleSaveObsNote = () => {
    if (activeLesson && obsNote.trim()) {
      updateLesson({ ...activeLesson, observationalNotes: obsNote });
      setObsNote('');
      alert('تم حفظ ملحوظة المشاهدة الإشرافية');
    }
  };

  const handleAddNewTeacher = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTeacherName || !newTeacherId) return alert('يرجى ملء كافة الحقول');
    onAddTeacher(newTeacherId, newTeacherName);
    setNewTeacherId('');
    setNewTeacherName('');
    setShowAddForm(false);
  };

  const handleAddNewProject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProjectName) return alert('يرجى إدخال اسم المشروع');
    onAddProject(newProjectName, newProjectDesc);
    setNewProjectName('');
    setNewProjectDesc('');
    setShowProjectForm(false);
  };

  const saveEvaluation = () => {
    if (selectedProjectId && editingEval) {
      onUpdateEvaluation(selectedProjectId, {
        teacherId: editingEval.teacherId,
        performanceScore: editingEval.performance,
        engagementScore: editingEval.engagement,
        feedback: editingEval.feedback,
        updatedAt: new Date().toLocaleDateString('ar-SA')
      });
      setEditingEval(null);
    }
  };

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return <p className="text-[10px] text-slate-400 mt-2 italic">لا يوجد مرفقات تعليمية</p>;
    const { type, url, name } = strategy.attachment;

    switch(type) {
      case 'image':
        return (
          <div className="mt-3">
            <img src={url} alt={name} className="max-h-60 rounded-xl border-2 border-slate-100 shadow-md" />
            <p className="text-[10px] text-slate-400 mt-2 font-bold">🖼️ {name}</p>
          </div>
        );
      case 'video':
        return (
          <div className="mt-3">
            <video src={url} controls className="max-h-60 w-full rounded-xl shadow-lg bg-black" />
          </div>
        );
      case 'link':
        return (
          <div className="mt-3">
            <a href={url} target="_blank" rel="noopener noreferrer" className="text-sm text-white bg-indigo-600 px-6 py-3 rounded-xl font-black text-center block">فتح الرابط: {url}</a>
          </div>
        );
      case 'file':
        return (
          <div className="mt-3">
            <a href={url} download={name} className="inline-flex items-center gap-3 bg-emerald-50 text-emerald-700 px-6 py-4 rounded-2xl font-black border-2 border-emerald-100">تحميل: {name}</a>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="space-y-10 animate-fadeIn pb-20">
      {/* Tab Switcher - Expanded for Projects */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2.5rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-2xl">
          <button 
            onClick={() => { setActiveTab('lessons'); setSelectedTeacherId(null); setSelectedLessonId(null); }}
            className={`flex-1 px-4 py-4 rounded-[2rem] font-black transition-all flex items-center justify-center gap-3 ${activeTab === 'lessons' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100' : 'text-slate-500 hover:bg-indigo-50'}`}
          >
            📋 الدروس
          </button>
          <button 
            onClick={() => { setActiveTab('projects'); setSelectedProjectId(null); setEditingEval(null); }}
            className={`flex-1 px-4 py-4 rounded-[2rem] font-black transition-all flex items-center justify-center gap-3 ${activeTab === 'projects' ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-100' : 'text-slate-500 hover:bg-emerald-50'}`}
          >
            🚀 المشاريع
          </button>
          <button 
            onClick={() => setActiveTab('accounts')}
            className={`flex-1 px-4 py-4 rounded-[2rem] font-black transition-all flex items-center justify-center gap-3 ${activeTab === 'accounts' ? 'bg-amber-500 text-white shadow-xl shadow-amber-100' : 'text-slate-500 hover:bg-amber-50'}`}
          >
            👥 الحسابات
          </button>
        </div>
      </div>

      {activeTab === 'accounts' ? (
        <div className="space-y-8 animate-fadeIn">
          <div className="flex flex-col md:flex-row justify-between items-center bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 gap-6">
             <div>
               <h2 className="text-2xl font-black text-slate-900">سجل الهيئة التدريسية</h2>
               <p className="text-slate-400 font-bold text-sm">إدارة صلاحيات المعلمات ومتابعة وصولهم للنظام</p>
             </div>
             <button 
               onClick={() => setShowAddForm(!showAddForm)}
               className={`${showAddForm ? 'bg-slate-100 text-slate-600' : 'bg-indigo-600 text-white shadow-lg'} px-8 py-4 rounded-2xl font-black transition-all flex items-center gap-3 active:scale-95`}
             >
               {showAddForm ? 'إلغاء' : '+ إضافة معلمة'}
             </button>
          </div>

          {showAddForm && (
            <div className="bg-white p-10 rounded-[3rem] shadow-2xl border-4 border-indigo-50 animate-slideDown">
               <h3 className="text-lg font-black text-slate-800 mb-8 border-r-4 border-indigo-600 pr-4">تسجيل معلمة جديدة</h3>
               <form onSubmit={handleAddNewTeacher} className="grid grid-cols-1 md:grid-cols-3 gap-8 items-end">
                  <div>
                    <label className="block text-xs font-black text-slate-500 mb-3 pr-2">الاسم الكامل للمعلمة</label>
                    <input type="text" value={newTeacherName} onChange={(e) => setNewTeacherName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-400 focus:bg-white outline-none font-bold transition-all" placeholder="أدخل الاسم..." />
                  </div>
                  <div>
                    <label className="block text-xs font-black text-slate-500 mb-3 pr-2">الرقم الوظيفي</label>
                    <input type="text" value={newTeacherId} onChange={(e) => setNewTeacherId(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-400 focus:bg-white outline-none font-bold text-center transition-all" placeholder="12345" />
                  </div>
                  <button type="submit" className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black shadow-lg hover:bg-emerald-700 transition active:scale-95">تفعيل الحساب الآن ✓</button>
               </form>
            </div>
          )}

          <div className="bg-white rounded-[3rem] shadow-sm overflow-hidden border border-slate-100">
             <div className="overflow-x-auto">
               <table className="w-full text-right">
                  <thead className="bg-slate-50/50 border-b border-slate-100">
                     <tr>
                       <th className="p-8 font-black text-slate-700 text-sm">المعلمة</th>
                       <th className="p-8 font-black text-slate-700 text-center text-sm">الرقم الوظيفي</th>
                       <th className="p-8 font-black text-slate-700 text-center text-sm">حالة الدخول</th>
                       <th className="p-8 font-black text-slate-700 text-center text-sm">خيارات الإدارة</th>
                     </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                     {teacherStats.length === 0 ? (
                       <tr>
                         <td colSpan={4} className="p-24 text-center text-slate-300 font-black text-lg">لا توجد معلمات مسجلات</td>
                       </tr>
                     ) : (
                       teacherStats.map(t => (
                         <tr key={t.id} className="hover:bg-slate-50/50 transition-colors group">
                            <td className="p-8 font-black text-slate-800 text-xl">
                              <div className="flex items-center gap-4">
                                <div className="w-12 h-12 bg-indigo-50 rounded-full flex items-center justify-center text-xl shrink-0">👩</div>
                                <div className="flex flex-col">
                                  <span>{t.name}</span>
                                  <span className="text-[10px] text-slate-400 font-bold">{t.lessonCount} دروس موثقة</span>
                                </div>
                              </div>
                            </td>
                            <td className="p-8 text-center">
                              <span className="bg-indigo-50 text-indigo-700 px-4 py-1.5 rounded-xl font-mono font-black border border-indigo-100">{t.id}</span>
                            </td>
                            <td className="p-8 text-center">
                              {t.mustChangePassword ? (
                                <span className="text-amber-500 bg-amber-50 px-4 py-2 rounded-full text-[10px] font-black border border-amber-100">كلمة مرور مؤقتة</span>
                              ) : (
                                <span className="text-emerald-600 bg-emerald-50 px-4 py-2 rounded-full text-[10px] font-black border border-emerald-100">حساب نشط</span>
                              )}
                            </td>
                            <td className="p-8">
                              <div className="flex items-center justify-center gap-4">
                                <button 
                                  onClick={() => {
                                    const p = onResetPassword(t.id);
                                    alert(`تم تصفير كلمة المرور للمعلمة ${t.name}\nكلمة المرور الجديدة: ${p}`);
                                  }}
                                  className="text-amber-600 font-black hover:underline text-xs"
                                >
                                  إعادة ضبط الباسورد
                                </button>
                                <button 
                                  onClick={() => onDeleteTeacher(t.id)}
                                  className="text-red-400 hover:text-red-600 font-black text-xs bg-red-50 p-2 rounded-lg"
                                >
                                  حذف
                                </button>
                              </div>
                            </td>
                         </tr>
                       ))
                     )}
                  </tbody>
               </table>
             </div>
          </div>
        </div>
      ) : activeTab === 'projects' ? (
        <div className="space-y-10 animate-fadeIn">
          {!selectedProjectId ? (
            <>
              <div className="flex flex-col md:flex-row justify-between items-center bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 gap-6">
                 <div>
                   <h2 className="text-2xl font-black text-slate-900">إدارة المشاريع التربوية</h2>
                   <p className="text-slate-400 font-bold text-sm">إضافة مشاريع جديدة وتقييم أداء المعلمات المشاركات</p>
                 </div>
                 <button 
                   onClick={() => setShowProjectForm(!showProjectForm)}
                   className={`${showProjectForm ? 'bg-slate-100 text-slate-600' : 'bg-emerald-600 text-white shadow-lg'} px-8 py-4 rounded-2xl font-black transition-all flex items-center gap-3 active:scale-95`}
                 >
                   {showProjectForm ? 'إلغاء' : '+ إضافة مشروع جديد'}
                 </button>
              </div>

              {showProjectForm && (
                <div className="bg-white p-10 rounded-[3rem] shadow-2xl border-4 border-emerald-50 animate-slideDown">
                  <form onSubmit={handleAddNewProject} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div>
                        <label className="block text-xs font-black text-slate-500 mb-3 pr-2">اسم المشروع</label>
                        <input type="text" required value={newProjectName} onChange={(e) => setNewProjectName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-emerald-400 outline-none font-bold" placeholder="مثال: مشروع تفعيل الذكاء الاصطناعي" />
                      </div>
                      <div>
                        <label className="block text-xs font-black text-slate-500 mb-3 pr-2">وصف مختصر</label>
                        <input type="text" value={newProjectDesc} onChange={(e) => setNewProjectDesc(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-emerald-400 outline-none font-bold" placeholder="أدخل وصفاً للمشروع..." />
                      </div>
                    </div>
                    <div className="flex justify-end">
                      <button type="submit" className="bg-emerald-600 text-white px-12 py-4 rounded-2xl font-black shadow-lg hover:bg-emerald-700 transition active:scale-95">تأكيد الإضافة ✓</button>
                    </div>
                  </form>
                </div>
              )}

              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                {projects.length === 0 ? (
                  <div className="col-span-full py-24 text-center bg-white rounded-[3rem] border-2 border-dashed border-slate-100 flex flex-col items-center justify-center">
                    <span className="text-5xl mb-4">🚀</span>
                    <h3 className="text-xl font-black text-slate-400">لا توجد مشاريع مضافة حالياً</h3>
                  </div>
                ) : (
                  projects.map(project => (
                    <div key={project.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col group hover:shadow-xl transition-all">
                      <div className="flex justify-between items-start mb-6">
                        <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-lg">مشروع تربوي</span>
                        <button onClick={() => onDeleteProject(project.id)} className="text-slate-300 hover:text-red-500">🗑️</button>
                      </div>
                      <h3 className="text-xl font-black text-slate-800 mb-2 group-hover:text-emerald-600 transition-colors">{project.name}</h3>
                      <p className="text-slate-400 text-xs font-bold line-clamp-2 mb-8 flex-1">{project.description || 'لا يوجد وصف.'}</p>
                      <div className="flex items-center justify-between border-t pt-6">
                         <div className="flex -space-x-3 rtl:space-x-reverse">
                            {Object.keys(project.evaluations).slice(0, 3).map(tid => (
                              <div key={tid} className="w-8 h-8 rounded-full bg-indigo-100 border-2 border-white flex items-center justify-center text-[10px] font-black text-indigo-600">👩</div>
                            ))}
                            {Object.keys(project.evaluations).length > 3 && (
                              <div className="w-8 h-8 rounded-full bg-slate-50 border-2 border-white flex items-center justify-center text-[10px] font-black text-slate-400">+{Object.keys(project.evaluations).length - 3}</div>
                            )}
                         </div>
                         <button onClick={() => setSelectedProjectId(project.id)} className="bg-slate-900 text-white px-6 py-2.5 rounded-xl font-black text-xs hover:bg-emerald-600 transition-colors">تقييم المعلمات</button>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </>
          ) : (
            <div className="bg-white rounded-[3rem] shadow-2xl p-10 space-y-8 animate-slideUp">
               <div className="flex justify-between items-center border-b pb-8">
                  <div className="flex items-center gap-4">
                    <button onClick={() => { setSelectedProjectId(null); setEditingEval(null); }} className="bg-slate-100 text-slate-600 p-3 rounded-2xl hover:bg-slate-200 transition">←</button>
