                                   <div className="flex justify-end gap-6 px-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">
                                     <span className="flex items-center gap-1"><span className="text-indigo-500">{wordCount}</span> كلمات</span>
                                     <span className="flex items-center gap-1"><span className="text-indigo-500">{charCount}</span> حروف</span>
                                   </div>
                                 </div>
                               );
                             })()}
                             <button onClick={handleSaveObsNote} className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black shadow-2xl shadow-indigo-100 active:scale-95 transition-all">حفظ ملحوظات الزيارة</button>
                           </div>
                         </div>
                      </div>

                      <div className="space-y-8">
                        <h4 className="text-2xl font-black text-slate-800 pr-4">توثيق الاستراتيجيات</h4>
                        <div className="grid grid-cols-1 gap-6">
                          {activeLesson?.strategies.map((s, i) => (
                            <div key={i} className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
                              <div className="font-black text-slate-800 text-lg mb-6 flex gap-4">
                                <span className="bg-indigo-50 text-indigo-600 w-10 h-10 rounded-xl flex items-center justify-center text-sm shrink-0 border border-indigo-100">{i+1}</span>
                                <span className="pt-2">{s.text}</span>
                              </div>
                              <div className="bg-slate-50 p-4 rounded-2xl border border-dashed">
                                {renderAttachment(s)}
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>
                   </div>

                   <div className="space-y-12">
                      <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm relative overflow-hidden group">
                         <h4 className="font-black text-lg text-slate-900 mb-6 flex items-center gap-3">
                           <span className="bg-indigo-50 p-2 rounded-lg text-indigo-600">⚙️</span> 
                           آلية التوظيف والممارسة
                         </h4>
                         <p className="font-bold text-slate-500 leading-relaxed italic bg-slate-50/50 p-8 rounded-3xl border border-white shadow-inner">{activeLesson?.effectiveStrategiesDeployment || 'لا توجد تفاصيل.'}</p>
                      </div>

                      <div className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm">
                         <h4 className="font-black text-lg text-slate-900 mb-6 flex items-center gap-3">
                           <span className="bg-emerald-50 p-2 rounded-lg text-emerald-600">📊</span>
                           التقويم والقياس القبلي/البعدي
                         </h4>
                         <p className="font-bold text-slate-500 leading-relaxed bg-emerald-50/20 p-8 rounded-3xl border border-white shadow-inner">{activeLesson?.evaluationMethods || 'لا توجد تفاصيل.'}</p>
                      </div>

                      <div className="bg-gradient-to-br from-amber-50 to-amber-100/50 p-10 rounded-[3rem] border border-amber-200 shadow-sm relative">
                         <h4 className="font-black text-lg text-amber-900 mb-6 flex items-center gap-3">
                           <span className="bg-amber-600 text-white p-2 rounded-lg text-sm shadow-sm">📢</span>
                           التوجيه الإشرافي للتطوير
                         </h4>
                         <div className="font-black text-amber-800 leading-relaxed bg-white/60 p-8 rounded-3xl min-h-[120px] italic border border-amber-100">
                            {activeLesson?.supervisorNotes || 'بانتظار إضافة التوجيه الفني من قبلك...'}
                         </div>
                      </div>
                   </div>
                </div>

                <div className="pt-12 border-t border-slate-50 flex flex-col md:flex-row justify-end gap-6">
                  <button 
                    onClick={() => {
                      const d = prompt('أدخل التوجيه الفني المطور للمعلمة:', activeLesson?.supervisorNotes || '');
                      if (d !== null && activeLesson) updateLesson({ ...activeLesson, supervisorNotes: d });
                    }}
                    className="bg-slate-900 text-white px-10 py-5 rounded-[2rem] font-black shadow-xl hover:bg-black transition-all active:scale-95 flex items-center justify-center gap-3"
                  >
                    <span>تعديل التوجيه الفني</span>
                    <span className="text-xl">📢</span>
                  </button>
                  {activeLesson?.status !== 'confirmed' && (
                    <button 
                      onClick={handleConfirmVisit} 
                      className="bg-indigo-600 text-white px-16 py-5 rounded-[2rem] font-black shadow-2xl shadow-indigo-100 hover:bg-indigo-700 transition-all active:scale-95 flex items-center justify-center gap-4"
                    >
                      <span>اعتماد وتوثيق الزيارة</span>
                      <span className="text-xl">✓</span>
                    </button>
                  )}
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default SupervisorDashboard;

import React, { useState, useMemo } from 'react';
import { Lesson, Strategy, User, Project, ProjectEvaluation } from '../types';

interface SupervisorDashboardProps {
  lessons: Lesson[];
  updateLesson: (lesson: Lesson) => void;
  teachers: User[];
  projects: Project[];
  onAddTeacher: (id: string, name: string) => void;
  onDeleteTeacher: (id: string) => void;
  onResetPassword: (teacherId: string) => string;
  onAddProject: (name: string, description: string) => void;
  onDeleteProject: (projectId: string) => void;
  onUpdateEvaluation: (projectId: string, evalData: ProjectEvaluation) => void;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ 
  lessons, updateLesson, teachers, projects, 
  onAddTeacher, onDeleteTeacher, onResetPassword,
  onAddProject, onDeleteProject, onUpdateEvaluation
}) => {
  const [activeTab, setActiveTab] = useState<'lessons' | 'accounts' | 'projects'>('lessons');
  const [selectedTeacherId, setSelectedTeacherId] = useState<string | null>(null);
  const [selectedLessonId, setSelectedLessonId] = useState<string | null>(null);
  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(null);
  const [obsNote, setObsNote] = useState('');
  const [isNotesExpanded, setIsNotesExpanded] = useState(true);

  // Forms state
  const [newTeacherName, setNewTeacherName] = useState('');
  const [newTeacherId, setNewTeacherId] = useState('');
  const [showAddForm, setShowAddForm] = useState(false);

  const [newProjectName, setNewProjectName] = useState('');
  const [newProjectDesc, setNewProjectDesc] = useState('');
  const [showProjectForm, setShowProjectForm] = useState(false);

  // Evaluation form state for a specific teacher in a project
  const [editingEval, setEditingEval] = useState<{ teacherId: string; performance: number; engagement: number; feedback: string } | null>(null);

  const teacherStats = useMemo(() => {
    return teachers.map(t => {
      const count = lessons.filter(l => l.teacherId === t.id).length;
      return { ...t, lessonCount: count };
    });
  }, [teachers, lessons]);

  const teacherLessons = useMemo(() => {
    return lessons.filter(l => l.teacherId === selectedTeacherId);
  }, [lessons, selectedTeacherId]);

  const activeLesson = useMemo(() => {
    return lessons.find(l => l.id === selectedLessonId);
  }, [lessons, selectedLessonId]);

  const activeProject = useMemo(() => {
    return projects.find(p => p.id === selectedProjectId);
  }, [projects, selectedProjectId]);

  const handleConfirmVisit = () => {
    if (activeLesson) {
      updateLesson({ ...activeLesson, status: 'confirmed' });
      alert('تم اعتماد توثيق الزيارة بنجاح');
    }
  };

  const handleSaveObsNote = () => {
    if (activeLesson && obsNote.trim()) {
      updateLesson({ ...activeLesson, observationalNotes: obsNote });
      setObsNote('');
      alert('تم حفظ ملحوظة المشاهدة الإشرافية');
    }
  };

  const handleAddNewTeacher = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTeacherName || !newTeacherId) return alert('يرجى ملء كافة الحقول');
    onAddTeacher(newTeacherId, newTeacherName);
    setNewTeacherId('');
    setNewTeacherName('');
    setShowAddForm(false);
  };

  const handleAddNewProject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProjectName) return alert('يرجى إدخال اسم المشروع');
    onAddProject(newProjectName, newProjectDesc);
    setNewProjectName('');
    setNewProjectDesc('');
    setShowProjectForm(false);
  };

  const saveEvaluation = () => {
    if (selectedProjectId && editingEval) {
      onUpdateEvaluation(selectedProjectId, {
        teacherId: editingEval.teacherId,
        performanceScore: editingEval.performance,
        engagementScore: editingEval.engagement,
        feedback: editingEval.feedback,
        updatedAt: new Date().toLocaleDateString('ar-SA')
      });
      setEditingEval(null);
    }
  };

  const renderAttachment = (strategy: Strategy) => {
    if (!strategy.attachment) return <p className="text-[10px] text-slate-400 mt-2 italic">لا يوجد مرفقات تعليمية</p>;
    const { type, url, name } = strategy.attachment;

    switch(type) {
      case 'image':
        return (
          <div className="mt-3">
            <img src={url} alt={name} className="max-h-60 rounded-xl border-2 border-slate-100 shadow-md" />
            <p className="text-[10px] text-slate-400 mt-2 font-bold">🖼️ {name}</p>
          </div>
        );
      case 'video':
        return (
          <div className="mt-3">
            <video src={url} controls className="max-h-60 w-full rounded-xl shadow-lg bg-black" />
          </div>
        );
      case 'link':
        return (
          <div className="mt-3">
            <a href={url} target="_blank" rel="noopener noreferrer" className="text-sm text-white bg-indigo-600 px-6 py-3 rounded-xl font-black text-center block">فتح الرابط: {url}</a>
          </div>
        );
      case 'file':
        return (
          <div className="mt-3">
            <a href={url} download={name} className="inline-flex items-center gap-3 bg-emerald-50 text-emerald-700 px-6 py-4 rounded-2xl font-black border-2 border-emerald-100">تحميل: {name}</a>
          </div>
        );
      default:
        return null;
    }
  };

  // Helper to calculate word count
  const getWordCount = (text: string) => {
    const trimmed = text.trim();
    return trimmed ? trimmed.split(/\s+/).length : 0;
  };

  return (
    <div className="space-y-10 animate-fadeIn pb-20">
      {/* Tab Switcher - Expanded for Projects */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2.5rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-2xl">
          <button 
            onClick={() => { setActiveTab('lessons'); setSelectedTeacherId(null); setSelectedLessonId(null); }}
            className={`flex-1 px-4 py-4 rounded-[2rem] font-black transition-all flex items-center justify-center gap-3 ${activeTab === 'lessons' ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-100' : 'text-slate-500 hover:bg-indigo-50'}`}
          >
            📋 الدروس
          </button>
          <button 
            onClick={() => { setActiveTab('projects'); setSelectedProjectId(null); setEditingEval(null); }}
            className={`flex-1 px-4 py-4 rounded-[2rem] font-black transition-all flex items-center justify-center gap-3 ${activeTab === 'projects' ? 'bg-emerald-600 text-white shadow-xl shadow-emerald-100' : 'text-slate-500 hover:bg-emerald-50'}`}
          >
            🚀 المشاريع
          </button>
          <button 
            onClick={() => setActiveTab('accounts')}
            className={`flex-1 px-4 py-4 rounded-[2rem] font-black transition-all flex items-center justify-center gap-3 ${activeTab === 'accounts' ? 'bg-amber-500 text-white shadow-xl shadow-amber-100' : 'text-slate-500 hover:bg-amber-50'}`}
          >
            👥 الحسابات
          </button>
        </div>
      </div>

      {activeTab === 'accounts' ? (
        <div className="space-y-8 animate-fadeIn">
          <div className="flex flex-col md:flex-row justify-between items-center bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100 gap-6">
             <div>
               <h2 className="text-2xl font-black text-slate-900">سجل الهيئة التدريسية</h2>
               <p className="text-slate-400 font-bold text-sm">إدارة صلاحيات المعلمات ومتابعة وصولهم للنظام</p>
             </div>
             <button 
               onClick={() => setShowAddForm(!showAddForm)}
               className={`${showAddForm ? 'bg-slate-100 text-slate-600' : 'bg-indigo-600 text-white shadow-lg'} px-8 py-4 rounded-2xl font-black transition-all flex items-center gap-3 active:scale-95`}
             >
               {showAddForm ? 'إلغاء' : '+ إضافة معلمة'}
             </button>
          </div>

          {showAddForm && (
            <div className="bg-white p-10 rounded-[3rem] shadow-2xl border-4 border-indigo-50 animate-slideDown">
               <h3 className="text-lg font-black text-slate-800 mb-8 border-r-4 border-indigo-600 pr-4">تسجيل معلمة جديدة</h3>
               <form onSubmit={handleAddNewTeacher} className="grid grid-cols-1 md:grid-cols-3 gap-8 items-end">
                  <div>
                    <label className="block text-xs font-black text-slate-500 mb-3 pr-2">الاسم الكامل للمعلمة</label>
                    <input type="text" value={newTeacherName} onChange={(e) => setNewTeacherName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-indigo-400 focus:bg-white outline-none font-bold transition-all" placeholder="أدخل الاسم..." />
                  </div>
                  <div>
                    <label className="block text-xs font-black text-slate-500 mb-3 pr-2">الرقم الوظيفي</label>
                    <input type="text" value={newTeacherId} onChange={(e) => setNewTeacherId(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-400 focus:bg-white outline-none font-bold text-center transition-all" placeholder="12345" />
                  </div>
                  <button type="submit" className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black shadow-lg hover:bg-emerald-700 transition active:scale-95">تفعيل الحساب الآن ✓</button>
               </form>
            </div>
          )}

          <div className="bg-white rounded-[3rem] shadow-sm overflow-hidden border border-slate-100">
             <div className="overflow-x-auto">
               <table className="w-full text-right">
                  <thead className="bg-slate-50/50 border-b border-slate-100">
