export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  code: string;
  password?: string;
  mustChangePassword?: boolean;
  isActive: boolean; // For soft delete
  joinedAt: string; // Year
}

export type AttachmentType = 'link' | 'image' | 'video' | 'file';

export interface Attachment {
  type: AttachmentType;
  url: string;
  name: string;
}

export interface Post {
  id: string;
  authorId: string;
  authorName: string;
  title: string;
  content: string;
  attachments: Attachment[];
  isPinned: boolean;
  createdAt: string;
  academicYear: string;
}

export interface ProjectSubmission {
  teacherId: string;
  files: Attachment[];
  notes: string;
  status: 'pending' | 'submitted' | 'approved' | 'needs_work';
  feedback: string;
  badges: string[]; // e.g., '🏆', '🌟', '💎'
  submittedAt?: string;
}

export interface Project {
  id: string;
  name: string;
  description: string; // Goals and description
  tasks: string[];
  assignedTeacherIds: string[]; // Access control
  createdAt: string;
  academicYear: string;
  submissions: Record<string, ProjectSubmission>; // teacherId -> Submission
}

// Legacy support for old data if needed, though we are pivoting to Project-based
export interface Lesson {
  id: string;
  teacherId: string;
  teacherName: string;
  title: string;
  strategiesCount: number;
  strategies: any[];
  selfLearningSkills: any;
  effectiveStrategiesDeployment: string;
  evaluationMethods: string;
  valuesAndCitizenship: string;
  createdAt: string;
