  supervisorNotes?: string;
  observationalNotes?: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Lesson, Project, Post } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';
import ChangePasswordForm from './components/ChangePasswordForm';

const CURRENT_ACADEMIC_YEAR = "2025-2026";

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [lessons, setLessons] = useState<Lesson[]>(() => {
    const saved = localStorage.getItem('app_lessons');
    return saved ? JSON.parse(saved) : [];
  });

  const [teachers, setTeachers] = useState<User[]>(() => {
    const saved = localStorage.getItem('app_teachers_list');
    return saved ? JSON.parse(saved) : [];
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('app_projects');
    return saved ? JSON.parse(saved) : [];
  });

  const [posts, setPosts] = useState<Post[]>(() => {
    const saved = localStorage.getItem('app_posts');
    return saved ? JSON.parse(saved) : [];
  });

  const [showChangePassword, setShowChangePassword] = useState(false);

  useEffect(() => {
    localStorage.setItem('app_lessons', JSON.stringify(lessons));
  }, [lessons]);

  useEffect(() => {
    localStorage.setItem('app_teachers_list', JSON.stringify(teachers));
  }, [teachers]);

  useEffect(() => {
    localStorage.setItem('app_projects', JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    localStorage.setItem('app_posts', JSON.stringify(posts));
  }, [posts]);

  const handleLogin = (user: User) => {
    if (!user.isActive) {
      alert('عذراً، هذا الحساب غير نشط. يرجى مراجعة إدارة المنصة.');
      return;
    }
    if (user.role === UserRole.TEACHER && user.mustChangePassword) {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(true);
    } else {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(false);
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setShowChangePassword(false);
  };

  const addLesson = (newLesson: Lesson) => {
    setLessons(prev => [{ ...newLesson, status: 'pending' }, ...prev]);
  };

  const updateLesson = (updatedLesson: Lesson) => {
    setLessons(prev => prev.map(l => (l.id === updatedLesson.id ? updatedLesson : l)));
  };

  // User Management
  const handleAddTeacher = (id: string, name: string) => {
    const exists = teachers.find(t => t.id === id);
    if (exists) {
      if (!exists.isActive) {
        if (window.confirm('هذا الحساب موجود ولكنه معطل (مؤرشف). هل تريد إعادة تفعيله؟')) {
          setTeachers(prev => prev.map(t => t.id === id ? { ...t, isActive: true, mustChangePassword: true, password: `pass${id}` } : t));
        }
        return;
      }
      return alert('هذا الرقم الوظيفي موجود مسبقاً');
    }

    const newTeacher: User = {
      id,
      code: id,
      name,
      role: UserRole.TEACHER,
      password: `pass${id}`,
      mustChangePassword: true,
      isActive: true,
      joinedAt: CURRENT_ACADEMIC_YEAR
    };
    setTeachers(prev => [...prev, newTeacher]);
  };

  const handleSoftDeleteTeacher = (teacherId: string) => {
    if (window.confirm('هل أنت متأكد من أرشفة حساب المعلمة؟ سيتم تعطيل الدخول ولكن ستبقى البيانات محفوظة في الأرشيف.')) {
      setTeachers(prev => prev.map(t => t.id === teacherId ? { ...t, isActive: false } : t));
    }
  };

  const handleResetTeacherPassword = (teacherId: string) => {
    const defaultPass = `pass${teacherId}`;
    setTeachers(prev => prev.map(t => 
      t.id === teacherId ? { ...t, password: defaultPass, mustChangePassword: true } : t
    ));
    return defaultPass;
  };

  // Posts Management
  const handleAddPost = (post: Post) => {
    setPosts(prev => [post, ...prev]);
  };

  const handleDeletePost = (postId: string) => {
    if (window.confirm('حذف هذا المنشور؟')) {
      setPosts(prev => prev.filter(p => p.id !== postId));
    }
  };

  const handleTogglePinPost = (postId: string) => {
    setPosts(prev => prev.map(p => p.id === postId ? { ...p, isPinned: !p.isPinned } : p));
  };

  // Projects Management
  const handleAddProject = (project: Project) => {
    setProjects(prev => [project, ...prev]);
  };

  const handleDeleteProject = (projectId: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا المشروع نهائياً؟')) {
      setProjects(prev => prev.filter(p => p.id !== projectId));
    }
  };

  const handleUpdateProjectSubmission = (projectId: string, submission: any) => {
    setProjects(prev => prev.map(p => {
      if (p.id === projectId) {
        return {
          ...p,
          submissions: {
            ...p.submissions,
            [submission.teacherId]: submission
          }
        };
      }
      return p;
    }));
  };

  const handlePasswordChanged = (newPassword: string) => {
    if (auth.user) {
      setTeachers(prev => prev.map(t => 
        t.id === auth.user!.id ? { ...t, password: newPassword, mustChangePassword: false } : t
      ));
      setAuth(prev => ({ 
        ...prev, 
        user: prev.user ? { ...prev.user, mustChangePassword: false } : null 
      }));
      setShowChangePassword(false);
      alert('تم تحديث كلمة المرور بنجاح');
    }
  };

  if (!auth.isAuthenticated) {
    return <LoginForm onLogin={handleLogin} teachers={teachers} />;
  }

  if (showChangePassword) {
    return <ChangePasswordForm onPasswordChanged={handlePasswordChanged} onLogout={handleLogout} />;
  }

  return (
    <div className="min-h-screen bg-[#f8fafc] font-['Tajawal'] antialiased">
      <nav className="bg-white/90 backdrop-blur-md text-slate-900 shadow-sm sticky top-0 z-[100] border-b border-slate-100 h-20 flex items-center">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 w-full">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-4">
              <div className="bg-gradient-to-tr from-purple-600 to-indigo-600 p-2.5 rounded-2xl shadow-lg shadow-purple-100">
                <span className="text-2xl">✨</span>
              </div>
              <div className="flex flex-col">
                <span className="text-xl font-black tracking-tight text-slate-900 leading-none mb-1">منصة الإبداع</span>
                <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">إدارة التميز المدرسي {CURRENT_ACADEMIC_YEAR}</span>
              </div>
            </div>
            <div className="flex items-center gap-4 md:gap-6">
              <div className="hidden md:flex flex-col items-end">
                <span className="text-sm font-black text-slate-800">{auth.user?.name}</span>
                <span className="text-[10px] font-bold text-indigo-500 uppercase">{auth.user?.role === UserRole.SUPERVISOR ? 'مشرفة النظام' : 'عضو هيئة التدريس'}</span>
              </div>
              <button 
                onClick={handleLogout}
                className="bg-slate-50 text-slate-600 hover:bg-red-50 hover:text-red-600 px-5 py-2.5 rounded-xl text-xs font-black transition-all active:scale-95 border border-slate-100"
              >
                تسجيل الخروج
              </button>
            </div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto py-8 px-4 sm:px-6 lg:px-8">
        {auth.user?.role === UserRole.TEACHER ? (
          <TeacherDashboard 
            user={auth.user} 
            posts={posts}
            projects={projects}
            updateProjectSubmission={handleUpdateProjectSubmission}
          />
        ) : (
          <SupervisorDashboard 
            teachers={teachers}
            posts={posts}
            projects={projects}
            onAddPost={handleAddPost}
            onDeletePost={handleDeletePost}
            onTogglePinPost={handleTogglePinPost}
            onAddTeacher={handleAddTeacher}
            onSoftDeleteTeacher={handleSoftDeleteTeacher}
            onResetPassword={handleResetTeacherPassword}
            onAddProject={handleAddProject}
            onDeleteProject={handleDeleteProject}
            onUpdateProjectSubmission={handleUpdateProjectSubmission}
            academicYear={CURRENT_ACADEMIC_YEAR}
          />
        )}
      </main>

      <footer className="py-8 text-center text-slate-400 text-[10px] font-bold border-t border-slate-100 mt-12 bg-white/50">
        جميع الحقوق محفوظة - منصة الإبداع © {CURRENT_ACADEMIC_YEAR}
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { UserRole, User } from '../types';

interface LoginFormProps {
  onLogin: (user: User) => void;
  teachers: User[];
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin, teachers }) => {
  const [code, setCode] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanCode = code.trim();
    const cleanPass = password.trim();

    if (!cleanCode || !cleanPass) {
      setError('يرجى إدخال الرقم الوظيفي وكلمة المرور');
      return;
    }

    const isSupervisor = cleanCode.toUpperCase().startsWith('S') || cleanCode.startsWith('99');

    if (isSupervisor) {
      const supervisorPass = `${cleanCode}مشرف`;
      if (cleanPass === supervisorPass) {
        onLogin({ 
          id: cleanCode, 
          name: `المشرفة (${cleanCode})`, 
          role: UserRole.SUPERVISOR, 
          code: cleanCode,
          isActive: true,
          joinedAt: '2026'
        });
      } else {
        setError('كلمة مرور المشرف غير صحيحة');
      }
      return;
    }

    // Teacher check
    const teacher = teachers.find(t => t.id === cleanCode);
    if (!teacher) {
      setError('المعلمة غير مسجلة في النظام');
      return;
    }

    if (cleanPass === teacher.password) {
      onLogin(teacher);
    } else {
      setError('كلمة المرور غير صحيحة');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#f8fafc] px-4 font-['Tajawal'] bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
      <div className="max-w-md w-full bg-white/90 backdrop-blur-xl rounded-[2.5rem] shadow-2xl p-10 space-y-8 border border-white relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-purple-500 via-indigo-500 to-blue-500"></div>
        <div className="text-center">
          <div className="mb-6 inline-flex items-center justify-center w-24 h-24 bg-gradient-to-br from-indigo-50 to-purple-50 rounded-[2rem] shadow-inner">
             <span className="text-5xl">✨</span>
          </div>
          <h1 className="text-3xl font-black text-slate-800 mb-2 tracking-tight">منصة الإبداع</h1>
          <p className="text-slate-500 font-bold text-sm">بوابة الدخول الموحدة للكادر التعليمي والإشرافي</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 pr-2">الرقم الوظيفي</label>
            <input type="text" required value={code} onChange={(e) => setCode(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-right font-black text-lg transition-all focus:bg-white" placeholder="أدخل الرقم الوظيفي..." />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 pr-2">كلمة المرور</label>
            <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-right font-black text-lg transition-all focus:bg-white" placeholder="••••••••" />
          </div>

          {error && <div className="bg-red-50 text-red-600 text-xs font-black p-4 rounded-2xl text-center animate-pulse">{error}</div>}

          <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg hover:bg-indigo-600 shadow-xl shadow-indigo-100 active:scale-95 transition-all mt-4">تسجيل الدخول</button>
        </form>

        <div className="text-center text-[10px] text-slate-300 font-bold pt-4 border-t border-slate-50">
          منصة الإبداع © 2026
        </div>
      </div>
    </div>
  );
};

