import React, { useState, useMemo } from 'react';
import { User, Project, Post, ProjectSubmission, Attachment } from '../types';

interface SupervisorDashboardProps {
  teachers: User[];
  posts: Post[];
  projects: Project[];
  onAddPost: (post: Post) => void;
  onDeletePost: (id: string) => void;
  onTogglePinPost: (id: string) => void;
  onAddTeacher: (id: string, name: string) => void;
  onSoftDeleteTeacher: (id: string) => void;
  onResetPassword: (teacherId: string) => string;
  onAddProject: (project: Project) => void;
  onDeleteProject: (projectId: string) => void;
  onUpdateProjectSubmission: (projectId: string, submission: ProjectSubmission) => void;
  academicYear: string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ 
  teachers, posts, projects, 
  onAddPost, onDeletePost, onTogglePinPost,
  onAddTeacher, onSoftDeleteTeacher, onResetPassword,
  onAddProject, onDeleteProject, onUpdateProjectSubmission,
  academicYear
}) => {
  const [activeTab, setActiveTab] = useState<'feed' | 'projects' | 'teachers' | 'archive'>('feed');

  // Post Form State
  const [postContent, setPostContent] = useState('');
  const [postTitle, setPostTitle] = useState('');
  const [postAttachments, setPostAttachments] = useState<Attachment[]>([]);
  const [isPostPinned, setIsPostPinned] = useState(false);

  // Project Form State
  const [newProjectName, setNewProjectName] = useState('');
  const [newProjectGoals, setNewProjectGoals] = useState('');
  const [newProjectTasks, setNewProjectTasks] = useState('');
  const [selectedTeachers, setSelectedTeachers] = useState<string[]>([]);
  const [showProjectForm, setShowProjectForm] = useState(false);

  // Teacher Form State
  const [newTeacherName, setNewTeacherName] = useState('');
  const [newTeacherId, setNewTeacherId] = useState('');
  const [showTeacherForm, setShowTeacherForm] = useState(false);

  // Selected Project for Review
  const [selectedReviewProjectId, setSelectedReviewProjectId] = useState<string | null>(null);

  // Archive Filter
  const [archiveYear, setArchiveYear] = useState(academicYear);

  const activeTeachers = useMemo(() => teachers.filter(t => t.isActive), [teachers]);
  const archivedTeachers = useMemo(() => teachers.filter(t => !t.isActive), [teachers]);

  const filteredArchiveData = useMemo(() => {
    // In a real app, we would filter by join date or activity date. 
    // Here we just show the soft-deleted teachers and could filter projects by year.
    return {
      teachers: archivedTeachers,
      projects: projects.filter(p => p.academicYear === archiveYear)
    };
  }, [archivedTeachers, projects, archiveYear]);

  // Handlers
  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!postTitle || !postContent) return alert('يرجى كتابة العنوان والمحتوى');

    const newPost: Post = {
      id: Date.now().toString(),
      authorId: 'supervisor',
      authorName: 'الإدارة المدرسية',
      title: postTitle,
      content: postContent,
      attachments: postAttachments,
      isPinned: isPostPinned,
      createdAt: new Date().toLocaleDateString('ar-SA'),
      academicYear
    };
    onAddPost(newPost);
    setPostTitle('');
    setPostContent('');
    setPostAttachments([]);
    setIsPostPinned(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = () => {
        setPostAttachments(prev => [...prev, {
          type: file.type.startsWith('image') ? 'image' : 'file',
          url: reader.result as string,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreateProject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProjectName) return;

    const tasks = newProjectTasks.split('\n').filter(t => t.trim());

    const newProject: Project = {
      id: Date.now().toString(),
      name: newProjectName,
      description: newProjectGoals,
      tasks: tasks,
      assignedTeacherIds: selectedTeachers.length > 0 ? selectedTeachers : activeTeachers.map(t => t.id),
      createdAt: new Date().toLocaleDateString('ar-SA'),
      academicYear,
      submissions: {}
    };
    onAddProject(newProject);
    setNewProjectName('');
    setNewProjectGoals('');
    setNewProjectTasks('');
    setSelectedTeachers([]);
    setShowProjectForm(false);
  };

  const handleAwardBadge = (projectId: string, teacherId: string, badge: string) => {
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const submission = project.submissions[teacherId] || { 
      teacherId, files: [], notes: '', status: 'pending', feedback: '', badges: [] 
    };

    const newBadges = submission.badges.includes(badge) ? submission.badges : [...submission.badges, badge];
    onUpdateProjectSubmission(projectId, { ...submission, badges: newBadges });
  };

  const handleCreateTeacher = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTeacherId && newTeacherName) {
      onAddTeacher(newTeacherId, newTeacherName);
      setNewTeacherId('');
      setNewTeacherName('');
      setShowTeacherForm(false);
    }
  };

  return (
    <div className="space-y-8 pb-20 animate-fadeIn">
      {/* Navigation Tabs */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-3xl overflow-x-auto">
          {[
            { id: 'feed', label: '📢 مركز التواصل', color: 'indigo' },
            { id: 'projects', label: '🚀 إدارة المشاريع', color: 'purple' },
            { id: 'teachers', label: '👥 المعلمات', color: 'emerald' },
            { id: 'archive', label: '📂 الأرشيف', color: 'amber' }
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => { setActiveTab(tab.id as any); setSelectedReviewProjectId(null); }}
              className={`flex-1 min-w-[100px] px-4 py-4 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm ${
                activeTab === tab.id 
                  ? `bg-${tab.color}-600 text-white shadow-lg` 
                  : `text-slate-500 hover:bg-${tab.color}-50`
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* FEED TAB */}
      {activeTab === 'feed' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1">
             <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 sticky top-24">
                <h3 className="text-xl font-black text-slate-800 mb-6 flex items-center gap-2">
                  <span>✍️</span> إنشاء تعميم جديد
                </h3>
                <form onSubmit={handleCreatePost} className="space-y-4">
                  <input 
                    type="text" 
                    placeholder="عنوان التعميم" 
                    value={postTitle}
                    onChange={e => setPostTitle(e.target.value)}
                    className="w-full px-5 py-3 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-indigo-500 outline-none font-bold text-sm"
                  />
                  <textarea 
                    placeholder="نص التعميم..." 
                    value={postContent}
                    onChange={e => setPostContent(e.target.value)}
                    className="w-full px-5 py-3 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-indigo-500 outline-none font-bold text-sm min-h-[120px]"
                  />

                  <div className="flex items-center gap-2">
                     <label className="flex-1 cursor-pointer bg-slate-50 hover:bg-slate-100 px-4 py-3 rounded-xl border border-dashed border-slate-300 text-slate-500 text-xs font-black flex items-center justify-center gap-2 transition-all">
                        <span>📎 إرفاق ملف</span>
                        <input type="file" onChange={handleFileUpload} className="hidden" />
                     </label>
                     <label className={`cursor-pointer px-4 py-3 rounded-xl border-2 text-xs font-black transition-all ${isPostPinned ? 'bg-amber-50 border-amber-400 text-amber-600' : 'bg-white border-slate-100 text-slate-400'}`}>
                        📌 تثبيت
                        <input type="checkbox" checked={isPostPinned} onChange={e => setIsPostPinned(e.target.checked)} className="hidden" />
                     </label>
                  </div>

                  {postAttachments.length > 0 && (
                    <div className="flex gap-2 flex-wrap">
                      {postAttachments.map((att, i) => (
                        <div key={i} className="bg-indigo-50 text-indigo-600 px-3 py-1 rounded-lg text-[10px] font-bold truncate max-w-[150px]">
                          {att.name}
                        </div>
                      ))}
                    </div>
                  )}

                  <button type="submit" className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-indigo-700 transition-all">نشر التعميم</button>
                </form>
             </div>
          </div>

          <div className="lg:col-span-2 space-y-6">
             <h3 className="text-xl font-black text-slate-800 pr-2">📝 آخر المستجدات</h3>
             {posts.length === 0 ? (
               <div className="text-center py-20 bg-white rounded-[2.5rem] border-2 border-dashed border-slate-100 text-slate-300 font-bold">لا توجد تعاميم منشورة</div>
             ) : (
               posts.sort((a, b) => (a.isPinned === b.isPinned ? 0 : a.isPinned ? -1 : 1)).map(post => (
                 <div key={post.id} className={`bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 relative group transition-all hover:shadow-md ${post.isPinned ? 'border-r-8 border-r-amber-400' : ''}`}>
                    <div className="flex justify-between items-start mb-4">
                       <div className="flex items-center gap-3">
                          <div className="w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-lg">🏫</div>
                          <div>
                            <h4 className="font-black text-slate-900">{post.title}</h4>
                            <span className="text-[10px] text-slate-400 font-bold">{post.createdAt}</span>
                          </div>
                       </div>
                       <div className="flex gap-2">
                         <button onClick={() => onTogglePinPost(post.id)} className={`text-xl ${post.isPinned ? 'grayscale-0' : 'grayscale opacity-20'}`}>📌</button>
                         <button onClick={() => onDeletePost(post.id)} className="text-slate-200 hover:text-red-500 font-bold px-2">✕</button>
                       </div>
                    </div>
                    <p className="text-slate-600 font-bold text-sm leading-relaxed whitespace-pre-line mb-6">{post.content}</p>
                    {post.attachments.length > 0 && (
                      <div className="flex gap-3 overflow-x-auto pb-2">
                        {post.attachments.map((att, i) => (
                          <a key={i} href={att.url} download={att.name} className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-xl border border-slate-100 text-xs font-black text-indigo-600 hover:bg-indigo-50 transition-colors">
                            {att.type === 'image' ? '🖼️' : '📄'} {att.name}
                          </a>
                        ))}
                      </div>
                    )}
                 </div>
               ))
             )}
          </div>
        </div>
      )}

      {/* PROJECTS TAB */}
      {activeTab === 'projects' && (
        <div className="space-y-8 animate-fadeIn">
          {!selectedReviewProjectId ? (
            <>
               <div className="flex justify-between items-center bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
                  <div>
                    <h3 className="text-2xl font-black text-slate-900">المشاريع التربوية</h3>
                    <p className="text-slate-400 font-bold text-sm">التخطيط والمتابعة للإنجازات</p>
                  </div>
                  <button onClick={() => setShowProjectForm(!showProjectForm)} className="bg-purple-600 text-white px-8 py-4 rounded-2xl font-black shadow-lg hover:bg-purple-700 transition-all">
                    {showProjectForm ? 'إلغاء' : '+ مشروع جديد'}
                  </button>
               </div>

               {showProjectForm && (
                 <div className="bg-white p-10 rounded-[3rem] shadow-xl border-4 border-purple-50 animate-slideDown">
                    <form onSubmit={handleCreateProject} className="space-y-6">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                         <input type="text" placeholder="اسم المشروع" value={newProjectName} onChange={e => setNewProjectName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 font-bold focus:bg-white border-2 border-slate-50 focus:border-purple-400 outline-none" />
                         <input type="text" placeholder="الأهداف العامة" value={newProjectGoals} onChange={e => setNewProjectGoals(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 font-bold focus:bg-white border-2 border-slate-50 focus:border-purple-400 outline-none" />
                      </div>
                      <textarea placeholder="المهام المطلوبة (كل مهمة في سطر)" value={newProjectTasks} onChange={e => setNewProjectTasks(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 font-bold focus:bg-white border-2 border-slate-50 focus:border-purple-400 outline-none min-h-[100px]" />

                      <div>
                        <label className="block text-sm font-black text-slate-500 mb-3">إسناد المهام إلى:</label>
                        <div className="flex flex-wrap gap-2 max-h-40 overflow-y-auto p-4 bg-slate-50 rounded-2xl border border-slate-100">
                           <button type="button" onClick={() => setSelectedTeachers([])} className={`px-4 py-2 rounded-xl text-xs font-black ${selectedTeachers.length === 0 ? 'bg-purple-600 text-white' : 'bg-white text-slate-500'}`}>الجميع</button>
                           {activeTeachers.map(t => (
                             <button 
                               key={t.id} 
                               type="button"
                               onClick={() => {
                                 setSelectedTeachers(prev => prev.includes(t.id) ? prev.filter(id => id !== t.id) : [...prev, t.id]);
                               }}
                               className={`px-4 py-2 rounded-xl text-xs font-black border transition-all ${selectedTeachers.includes(t.id) ? 'bg-purple-100 border-purple-300 text-purple-700' : 'bg-white border-slate-100 text-slate-500'}`}
                             >
                               {t.name}
                             </button>
                           ))}
                        </div>
                      </div>

                      <button type="submit" className="w-full bg-purple-600 text-white py-4 rounded-2xl font-black shadow-lg">إطلاق المشروع 🚀</button>
                    </form>
                 </div>
               )}

               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                 {projects.map(project => (
                   <div key={project.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col hover:shadow-xl transition-all group">
                      <div className="flex justify-between items-start mb-4">
                        <span className="bg-purple-50 text-purple-600 px-3 py-1 rounded-lg text-[10px] font-black">مشروع نشط</span>
                        <button onClick={() => onDeleteProject(project.id)} className="text-slate-300 hover:text-red-500">🗑️</button>
                      </div>
                      <h3 className="text-xl font-black text-slate-800 mb-2">{project.name}</h3>
                      <p className="text-slate-400 text-xs font-bold line-clamp-2 mb-6">{project.description}</p>

                      <div className="mt-auto border-t border-slate-50 pt-4 flex justify-between items-center">
                         <div className="flex -space-x-2 rtl:space-x-reverse">
                           {project.assignedTeacherIds.slice(0, 4).map((tid, idx) => (
                             <div key={idx} className="w-8 h-8 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-[8px] font-black text-slate-500">
                               {teachers.find(t => t.id === tid)?.name.charAt(0)}
                             </div>
                           ))}
                           {project.assignedTeacherIds.length > 4 && <div className="w-8 h-8 rounded-full bg-slate-100 border-2 border-white flex items-center justify-center text-[8px] font-black text-slate-500">+{project.assignedTeacherIds.length - 4}</div>}
                         </div>
                         <button onClick={() => setSelectedReviewProjectId(project.id)} className="bg-slate-900 text-white px-5 py-2 rounded-xl text-xs font-black hover:bg-purple-600 transition-colors">متابعة الإنجاز</button>
                      </div>
                   </div>
                 ))}
               </div>
            </>
          ) : (
            <div className="bg-white rounded-[3rem] shadow-xl p-10 min-h-[600px] animate-slideUp">
               {(() => {
                 const project = projects.find(p => p.id === selectedReviewProjectId);
                 if (!project) return null;

                 const targetTeachers = project.assignedTeacherIds.map(id => teachers.find(t => t.id === id)).filter(Boolean) as User[];

                 return (
                   <div className="space-y-8">
                     <div className="flex items-center justify-between border-b border-slate-100 pb-6">
                        <div className="flex items-center gap-4">
                           <button onClick={() => setSelectedReviewProjectId(null)} className="bg-slate-100 hover:bg-slate-200 px-4 py-2 rounded-xl font-bold text-slate-600 transition">عودة</button>
                           <div>
                             <h2 className="text-2xl font-black text-slate-900">{project.name}</h2>
                             <p className="text-slate-400 text-xs font-bold mt-1">قائمة المهام: {project.tasks.join(' • ')}</p>
                           </div>
                        </div>
                        <div className="text-xs font-black text-purple-600 bg-purple-50 px-4 py-2 rounded-xl">السنة الدراسية: {project.academicYear}</div>
                     </div>

                     <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        {targetTeachers.map(teacher => {
                          const submission = project.submissions[teacher.id];
                          return (
                            <div key={teacher.id} className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100">
                               <div className="flex justify-between items-center mb-4">
                                  <h4 className="font-black text-slate-800">{teacher.name}</h4>
                                  <span className={`text-[10px] font-black px-3 py-1 rounded-full ${submission ? (submission.status === 'approved' ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600') : 'bg-slate-200 text-slate-500'}`}>
                                    {submission ? (submission.status === 'approved' ? 'معتمد' : 'قيد المراجعة') : 'لم يسلم بعد'}
                                  </span>
                               </div>

                               {submission ? (
                                 <div className="space-y-4">
                                   <div className="bg-white p-4 rounded-xl border border-slate-100">
                                      <p className="text-xs text-slate-600 font-bold mb-3">{submission.notes || 'لا توجد ملاحظات مرفقة'}</p>
                                      <div className="flex flex-wrap gap-2">
                                        {submission.files.map((f, i) => (
                                          <a key={i} href={f.url} download={f.name} className="bg-indigo-50 text-indigo-600 px-3 py-1.5 rounded-lg text-[10px] font-black hover:bg-indigo-100 block truncate max-w-full">
                                            📎 {f.name}
                                          </a>
                                        ))}
                                      </div>
                                   </div>

                                   <div className="flex gap-2 justify-center pt-2">
                                      <button onClick={() => handleAwardBadge(project.id, teacher.id, '🏆')} className={`text-2xl hover:scale-125 transition ${submission.badges.includes('🏆') ? 'opacity-100' : 'opacity-30'}`}>🏆</button>
                                      <button onClick={() => handleAwardBadge(project.id, teacher.id, '🌟')} className={`text-2xl hover:scale-125 transition ${submission.badges.includes('🌟') ? 'opacity-100' : 'opacity-30'}`}>🌟</button>
                                      <button onClick={() => handleAwardBadge(project.id, teacher.id, '💎')} className={`text-2xl hover:scale-125 transition ${submission.badges.includes('💎') ? 'opacity-100' : 'opacity-30'}`}>💎</button>
                                   </div>

                                   <button 
                                      onClick={() => onUpdateProjectSubmission(project.id, { ...submission, status: 'approved' })}
                                      className="w-full bg-emerald-600 text-white py-2 rounded-xl text-xs font-black shadow-lg shadow-emerald-100 hover:bg-emerald-700"
                                   >
                                      اعتماد الإنجاز ✓
                                   </button>
                                 </div>
                               ) : (
                                 <div className="text-center py-8 text-slate-300 text-xs font-black">
                                   بانتظار رفع الملفات...
                                 </div>
                               )}
                            </div>
                          );
                        })}
                     </div>
                   </div>
                 );
               })()}
            </div>
          )}
        </div>
      )}

      {/* TEACHERS TAB */}
      {activeTab === 'teachers' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="flex justify-between items-center bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
             <div>
               <h3 className="text-2xl font-black text-slate-900">قاعدة بيانات المعلمات</h3>
               <p className="text-slate-400 font-bold text-sm">إدارة الحسابات والصلاحيات</p>
             </div>
             <button onClick={() => setShowTeacherForm(!showTeacherForm)} className="bg-emerald-600 text-white px-8 py-4 rounded-2xl font-black shadow-lg hover:bg-emerald-700 transition-all">
               {showTeacherForm ? 'إلغاء' : '+ إضافة معلمة'}
             </button>
          </div>

          {showTeacherForm && (
            <div className="bg-white p-10 rounded-[3rem] shadow-xl border-4 border-emerald-50 animate-slideDown">
               <form onSubmit={handleCreateTeacher} className="flex flex-col md:flex-row gap-6 items-end">
                  <div className="flex-1 w-full">
                    <label className="text-xs font-black text-slate-400 mb-2 block">الاسم</label>
                    <input type="text" value={newTeacherName} onChange={e => setNewTeacherName(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 font-bold outline-none border-2 border-slate-50 focus:border-emerald-400" placeholder="الاسم الثلاثي" />
                  </div>
                  <div className="flex-1 w-full">
                    <label className="text-xs font-black text-slate-400 mb-2 block">الرقم الوظيفي</label>
                    <input type="text" value={newTeacherId} onChange={e => setNewTeacherId(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 font-bold outline-none border-2 border-slate-50 focus:border-emerald-400" placeholder="12345" />
                  </div>
                  <button type="submit" className="w-full md:w-auto bg-emerald-600 text-white px-10 py-4 rounded-2xl font-black shadow-lg">حفظ</button>
               </form>
            </div>
          )}

          <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-100 overflow-hidden">
            <table className="w-full text-right">
               <thead className="bg-slate-50 text-xs font-black text-slate-500">
                 <tr>
                   <th className="p-6">المعلمة</th>
                   <th className="p-6 text-center">الرقم الوظيفي</th>
                   <th className="p-6 text-center">تاريخ الانضمام</th>
                   <th className="p-6 text-center">الإجراءات</th>
                 </tr>
               </thead>
               <tbody className="divide-y divide-slate-50">
                 {activeTeachers.map(t => (
                   <tr key={t.id} className="hover:bg-slate-50 transition">
                      <td className="p-6 font-black text-slate-800">
                        <div className="flex items-center gap-3">
                           <div className="w-8 h-8 bg-emerald-50 rounded-full flex items-center justify-center text-xs">👩‍🏫</div>
                           {t.name}
                        </div>
                      </td>
                      <td className="p-6 text-center font-mono text-slate-600">{t.code}</td>
                      <td className="p-6 text-center text-slate-400 text-xs font-bold">{t.joinedAt || '2026'}</td>
                      <td className="p-6 text-center">
                        <div className="flex items-center justify-center gap-2">
                           <button onClick={() => { const p = onResetPassword(t.id); alert(`كلمة المرور الجديدة: ${p}`); }} className="text-xs font-black text-amber-500 bg-amber-50 px-3 py-1.5 rounded-lg">إعادة تعيين كلمة المرور</button>
                           <button onClick={() => onSoftDeleteTeacher(t.id)} className="text-xs font-black text-red-500 bg-red-50 px-3 py-1.5 rounded-lg">أرشفة الحساب</button>
                        </div>
                      </td>
                   </tr>
                 ))}
               </tbody>
            </table>
          </div>
        </div>
      )}

      {/* ARCHIVE TAB */}
      {activeTab === 'archive' && (
        <div className="space-y-8 animate-fadeIn">
          <div className="bg-amber-50 p-8 rounded-[3rem] border border-amber-100">
             <h3 className="text-2xl font-black text-amber-900 mb-2">📂 الأرشيف التاريخي</h3>
             <p className="text-amber-700/60 font-bold text-sm mb-6">سجل البيانات المحفوظة والسنوات السابقة</p>
