      </div>

      {activeView === 'feed' && (
        <div className="max-w-2xl mx-auto space-y-8">
           <div className="bg-gradient-to-r from-indigo-500 to-purple-500 rounded-[2.5rem] p-8 text-white shadow-lg relative overflow-hidden">
              <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-3xl -mr-16 -mt-16"></div>
              <h2 className="text-2xl font-black mb-2 relative z-10">مرحباً، {user.name} 👋</h2>
              <p className="opacity-90 font-bold text-sm relative z-10">إليك آخر المستجدات والتعاميم الإدارية</p>
           </div>

