export default TeacherDashboard;

export enum UserRole {
  TEACHER = 'TEACHER',
  SUPERVISOR = 'SUPERVISOR'
}

export interface User {
  id: string;
  name: string;
  role: UserRole;
  code: string;
  password?: string;
  mustChangePassword?: boolean;
  isActive: boolean; // For soft delete
  joinedAt: string; // Year
  email?: string;
  phoneNumber?: string;
}

export type AttachmentType = 'link' | 'image' | 'video' | 'file';

export interface Attachment {
  type: AttachmentType;
  url: string;
  name: string;
}

export interface Post {
  id: string;
  authorId: string;
  authorName: string;
  title: string;
  content: string;
  attachments: Attachment[];
  isPinned: boolean;
  createdAt: string;
  academicYear: string;
}

export interface ProjectSubmission {
  teacherId: string;
  files: Attachment[];
  notes: string;
  status: 'pending' | 'submitted' | 'approved' | 'needs_work';
  feedback: string;
  badges: string[]; // e.g., '🏆', '🌟', '💎'
  submittedAt?: string;
}

export interface Project {
  id: string;
  name: string;
  description: string; // Goals and description
  tasks: string[];
  assignedTeacherIds: string[]; // Access control
  createdAt: string;
  academicYear: string;
  submissions: Record<string, ProjectSubmission>; // teacherId -> Submission
}

// Legacy support for old data if needed, though we are pivoting to Project-based
export interface Lesson {
  id: string;
  teacherId: string;
  teacherName: string;
  title: string;
  strategiesCount: number;
  strategies: any[];
  selfLearningSkills: any;
  effectiveStrategiesDeployment: string;
  evaluationMethods: string;
  valuesAndCitizenship: string;
  createdAt: string;
  status?: 'pending' | 'confirmed';
  supervisorNotes?: string;
  observationalNotes?: string;
}

export interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
}

import React, { useState, useEffect } from 'react';
import { UserRole, User, AuthState, Lesson, Project, Post } from './types';
import LoginForm from './components/LoginForm';
import TeacherDashboard from './components/TeacherDashboard';
import SupervisorDashboard from './components/SupervisorDashboard';
import ChangePasswordForm from './components/ChangePasswordForm';

const CURRENT_ACADEMIC_YEAR = "2025-2026";

const App: React.FC = () => {
  const [auth, setAuth] = useState<AuthState>({
    user: null,
    isAuthenticated: false,
  });

  const [lessons, setLessons] = useState<Lesson[]>(() => {
    const saved = localStorage.getItem('app_lessons');
    return saved ? JSON.parse(saved) : [];
  });

  const [teachers, setTeachers] = useState<User[]>(() => {
    const saved = localStorage.getItem('app_teachers_list');
    return saved ? JSON.parse(saved) : [];
  });

  const [projects, setProjects] = useState<Project[]>(() => {
    const saved = localStorage.getItem('app_projects');
    return saved ? JSON.parse(saved) : [];
  });

  const [posts, setPosts] = useState<Post[]>(() => {
    const saved = localStorage.getItem('app_posts');
    return saved ? JSON.parse(saved) : [];
  });

  const [showChangePassword, setShowChangePassword] = useState(false);

  useEffect(() => {
    localStorage.setItem('app_lessons', JSON.stringify(lessons));
  }, [lessons]);

  useEffect(() => {
    localStorage.setItem('app_teachers_list', JSON.stringify(teachers));
  }, [teachers]);

  useEffect(() => {
    localStorage.setItem('app_projects', JSON.stringify(projects));
  }, [projects]);

  useEffect(() => {
    localStorage.setItem('app_posts', JSON.stringify(posts));
  }, [posts]);

  const handleLogin = (user: User) => {
    if (!user.isActive) {
      alert('عذراً، هذا الحساب غير نشط. يرجى مراجعة إدارة المنصة.');
      return;
    }
    if (user.role === UserRole.TEACHER && user.mustChangePassword) {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(true);
    } else {
      setAuth({ user, isAuthenticated: true });
      setShowChangePassword(false);
    }
  };

  const handleLogout = () => {
    setAuth({ user: null, isAuthenticated: false });
    setShowChangePassword(false);
  };

  const addLesson = (newLesson: Lesson) => {
    setLessons(prev => [{ ...newLesson, status: 'pending' }, ...prev]);
  };

  const updateLesson = (updatedLesson: Lesson) => {
    setLessons(prev => prev.map(l => (l.id === updatedLesson.id ? updatedLesson : l)));
  };

  // User Management
  const handleAddTeacher = (id: string, name: string, email?: string, phoneNumber?: string) => {
    const exists = teachers.find(t => t.id === id);
    const defaultPassword = `OM${id}`;

    if (exists) {
      if (!exists.isActive) {
        if (window.confirm('هذا الحساب موجود ولكنه معطل (مؤرشف). هل تريد إعادة تفعيله؟')) {
          setTeachers(prev => prev.map(t => t.id === id ? { 
            ...t, 
            isActive: true, 
            mustChangePassword: true, 
            password: defaultPassword,
            email: email || t.email,
            phoneNumber: phoneNumber || t.phoneNumber
          } : t));
        }
        return;
      }
      return alert('هذا الرقم الوظيفي موجود مسبقاً');
    }

    const newTeacher: User = {
      id,
      code: id,
      name,
      role: UserRole.TEACHER,
      password: defaultPassword,
      mustChangePassword: true,
      isActive: true,
      joinedAt: CURRENT_ACADEMIC_YEAR,
      email,
      phoneNumber
    };
    setTeachers(prev => [...prev, newTeacher]);
  };

  const handleSoftDeleteTeacher = (teacherId: string) => {
    if (window.confirm('هل أنت متأكد من أرشفة حساب المعلمة؟ سيتم تعطيل الدخول ولكن ستبقى البيانات محفوظة في الأرشيف.')) {
      setTeachers(prev => prev.map(t => t.id === teacherId ? { ...t, isActive: false } : t));
    }
  };

  const handleResetTeacherPassword = (teacherId: string) => {
    const defaultPass = `OM${teacherId}`;
    setTeachers(prev => prev.map(t => 
      t.id === teacherId ? { ...t, password: defaultPass, mustChangePassword: true } : t
    ));
    return defaultPass;
  };

  // Posts Management
  const handleAddPost = (post: Post) => {
    setPosts(prev => [post, ...prev]);
  };

  const handleDeletePost = (postId: string) => {
    if (window.confirm('حذف هذا المنشور؟')) {
      setPosts(prev => prev.filter(p => p.id !== postId));
    }
  };

  const handleTogglePinPost = (postId: string) => {
    setPosts(prev => prev.map(p => p.id === postId ? { ...p, isPinned: !p.isPinned } : p));
  };

  // Projects Management
  const handleAddProject = (project: Project) => {
    setProjects(prev => [project, ...prev]);
  };

  const handleDeleteProject = (projectId: string) => {
    if (window.confirm('هل أنت متأكد من حذف هذا المشروع نهائياً؟')) {
      setProjects(prev => prev.filter(p => p.id !== projectId));
    }
  };

  const handleUpdateProjectSubmission = (projectId: string, submission: any) => {
    setProjects(prev => prev.map(p => {
      if (p.id === projectId) {
        return {
          ...p,
          submissions: {
            ...p.submissions,
            [submission.teacherId]: submission
          }
        };
      }
      return p;
    }));
  };

  const handlePasswordChanged = (newPassword: string) => {
    if (auth.user) {
      setTeachers(prev => prev.map(t => 
        t.id === auth.user!.id ? { ...t, password: newPassword, mustChangePassword: false } : t
      ));
      setAuth(prev => ({ 
        ...prev, 
        user: prev.user ? { ...prev.user, mustChangePassword: false, password: newPassword } : null 
      }));
      setShowChangePassword(false);
      alert('تم تحديث كلمة المرور بنجاح');
    }
  };

  if (!auth.isAuthenticated) {
    return <LoginForm onLogin={handleLogin} teachers={teachers} />;
  }

  if (showChangePassword) {
    return <ChangePasswordForm 
      onPasswordChanged={handlePasswordChanged} 
      onLogout={handleLogout} 
      currentPassword={auth.user?.password}
    />;
  }

  return (
    <div className="min-h-screen bg-[#f8fafc] font-['Tajawal'] antialiased">
