            <label className="block text-sm font-black text-slate-700 mb-2">تأكيد كلمة المرور</label>
            <input 
              type="password" 
              required 
              value={confirmPass} 
              onChange={(e) => setConfirmPass(e.target.value)} 
              className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-amber-500 outline-none text-center font-extrabold text-slate-900 placeholder:text-slate-400"
