import React, { useState } from 'react';
import { UserRole, User } from '../types';

interface LoginFormProps {
  onLogin: (user: User) => void;
  teachers: User[];
}

const LoginForm: React.FC<LoginFormProps> = ({ onLogin, teachers }) => {
  const [code, setCode] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleanCode = code.trim();
    const cleanPass = password.trim();

    if (!cleanCode || !cleanPass) {
      setError('يرجى إدخال الرقم الوظيفي وكلمة المرور');
      return;
    }

    // Supervisor Login Check
    const isSupervisor = cleanCode.toUpperCase().startsWith('S') || cleanCode.startsWith('99');

    if (isSupervisor) {
      // Support specific requested credentials (S12345 / OM12345) or default pattern
      const isValidSupervisor = 
        (cleanCode.toUpperCase() === 'S12345' && cleanPass === 'OM12345') || 
        (cleanPass === `${cleanCode}مشرف`);

      if (isValidSupervisor) {
        onLogin({ 
          id: cleanCode, 
          name: `المشرفة (${cleanCode})`, 
          role: UserRole.SUPERVISOR, 
          code: cleanCode,
          isActive: true,
          joinedAt: '2026'
        });
        return;
      } else {
        setError('كلمة مرور المشرف غير صحيحة');
        return;
      }
    }

    // Teacher check
    const teacher = teachers.find(t => t.id === cleanCode);
    if (!teacher) {
      setError('المعلمة غير مسجلة في النظام');
      return;
    }

    if (cleanPass === teacher.password) {
      onLogin(teacher);
    } else {
      setError('كلمة المرور غير صحيحة');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-[#f8fafc] px-4 font-['Tajawal'] bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]">
      <div className="max-w-md w-full bg-white/90 backdrop-blur-xl rounded-[2.5rem] shadow-2xl p-10 space-y-8 border border-white relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-purple-500 via-indigo-500 to-blue-500"></div>
        <div className="text-center">
          <div className="mb-6 inline-flex items-center justify-center w-24 h-24 bg-gradient-to-br from-indigo-50 to-purple-50 rounded-[2rem] shadow-inner relative">
             <span className="text-5xl absolute top-4 right-4">🎓</span>
             <span className="text-4xl absolute bottom-4 left-4">📖</span>
          </div>
          <h1 className="text-3xl font-black text-slate-800 mb-2 tracking-tight">منصة الإبداع</h1>
          <p className="text-slate-500 font-bold text-sm">بوابة الدخول الموحدة للكادر التعليمي والإشرافي</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 pr-2">الرقم الوظيفي</label>
            <input type="text" required value={code} onChange={(e) => setCode(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-right font-extrabold text-lg transition-all focus:bg-white text-slate-900 placeholder:text-slate-400" placeholder="أدخل الرقم الوظيفي..." />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 pr-2">كلمة المرور</label>
            <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-6 py-4 rounded-2xl bg-slate-50 border-2 border-slate-100 focus:border-indigo-500 outline-none text-right font-extrabold text-lg transition-all focus:bg-white text-slate-900 placeholder:text-slate-400" placeholder="••••••••" />
          </div>

          {error && <div className="bg-red-50 text-red-600 text-xs font-black p-4 rounded-2xl text-center animate-pulse">{error}</div>}

          <button type="submit" className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg hover:bg-indigo-600 shadow-xl shadow-indigo-100 active:scale-95 transition-all mt-4">تسجيل الدخول</button>
        </form>

        <div className="text-center text-[10px] text-slate-300 font-bold pt-4 border-t border-slate-50">
          منصة الإبداع © 2026
        </div>
      </div>
    </div>
  );
};

