};

export default SupervisorDashboard;

import React, { useState } from 'react';
import { User, Project, Post, Attachment, ProjectSubmission } from '../types';

interface TeacherDashboardProps {
  user: User;
  posts: Post[];
  projects: Project[];
  updateProjectSubmission: (projectId: string, submission: ProjectSubmission) => void;
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ user, posts, projects, updateProjectSubmission }) => {
  const [activeView, setActiveView] = useState<'feed' | 'my-projects' | 'badges'>('feed');
  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(null);
  const [submissionNote, setSubmissionNote] = useState('');
  const [submissionFiles, setSubmissionFiles] = useState<Attachment[]>([]);

  // Derived Data
  const myProjects = projects.filter(p => p.assignedTeacherIds.includes(user.id));
  const myBadges = projects.flatMap(p => p.submissions[user.id]?.badges || []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = () => {
        setSubmissionFiles(prev => [...prev, {
          type: file.type.startsWith('image') ? 'image' : 'file',
          url: reader.result as string,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmitWork = () => {
    if (selectedProjectId) {
      const existing = projects.find(p => p.id === selectedProjectId)?.submissions[user.id];

      const submission: ProjectSubmission = {
        teacherId: user.id,
        files: [...(existing?.files || []), ...submissionFiles],
        notes: submissionNote || existing?.notes || '',
        status: 'submitted',
        feedback: existing?.feedback || '',
        badges: existing?.badges || [],
        submittedAt: new Date().toLocaleDateString('ar-SA')
      };

      updateProjectSubmission(selectedProjectId, submission);
      setSubmissionNote('');
      setSubmissionFiles([]);
      alert('تم رفع الإنجاز بنجاح وسيتم مراجعته من قبل المشرفة');
    }
  };

  return (
    <div className="pb-24 animate-fadeIn">
      {/* Mobile-Friendly Navigation */}
      <div className="fixed bottom-0 left-0 w-full bg-white border-t border-slate-100 p-4 z-50 flex justify-around md:static md:bg-transparent md:border-0 md:p-0 md:justify-center md:mb-10">
         <div className="bg-white p-1.5 md:p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-lg">
            {[
              { id: 'feed', icon: '📢', label: 'الرئيسية' },
              { id: 'my-projects', icon: '🚀', label: 'مشاريعي' },
              { id: 'badges', icon: '🏆', label: 'أوسمتي' }
            ].map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveView(item.id as any); setSelectedProjectId(null); }}
                className={`flex-1 px-4 py-3 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm ${
                  activeView === item.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                <span>{item.icon}</span>
                <span>{item.label}</span>
              </button>
            ))}
         </div>
      </div>

      {activeView === 'feed' && (
        <div className="max-w-2xl mx-auto space-y-8">
           <div className="bg-gradient-to-r from-indigo-500 to-purple-500 rounded-[2.5rem] p-8 text-white shadow-lg relative overflow-hidden">
              <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-3xl -mr-16 -mt-16"></div>
              <h2 className="text-2xl font-black mb-2 relative z-10">مرحباً، {user.name} 👋</h2>
              <p className="opacity-90 font-bold text-sm relative z-10">إليك آخر المستجدات والتعاميم الإدارية</p>
           </div>

           <div className="space-y-6">
             {posts.length === 0 ? (
               <div className="text-center py-12 text-slate-300 font-bold">لا توجد تعاميم جديدة</div>
             ) : (
               posts.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()).map(post => (
                 <div key={post.id} className={`bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 ${post.isPinned ? 'border-t-4 border-t-amber-400' : ''}`}>
                    {post.isPinned && <div className="text-xs font-black text-amber-500 mb-2 flex items-center gap-1">📌 مثبت للأهمية</div>}
                    <div className="flex items-center gap-3 mb-4">
                       <div className="w-10 h-10 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600 font-black text-xs">م.م</div>
                       <div>
                          <h4 className="font-black text-slate-900">{post.title}</h4>
                          <span className="text-[10px] text-slate-400 font-bold">{post.createdAt}</span>
                       </div>
                    </div>
                    <p className="text-slate-600 font-bold text-sm leading-relaxed whitespace-pre-line mb-6 bg-slate-50/50 p-4 rounded-2xl">{post.content}</p>

                    {post.attachments.length > 0 && (
                      <div className="space-y-2">
                        {post.attachments.map((att, i) => (
                          <div key={i} className="flex items-center gap-3 bg-slate-50 p-3 rounded-xl border border-slate-100">
                             <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center text-sm shadow-sm">{att.type === 'image' ? '🖼️' : '📄'}</div>
                             <div className="flex-1 min-w-0">
                                <div className="text-xs font-black text-slate-700 truncate">{att.name}</div>
                             </div>
                             <a href={att.url} download={att.name} className="text-indigo-600 text-xs font-black px-3 py-1 bg-indigo-50 rounded-lg">تحميل</a>
                          </div>
                        ))}
                      </div>
                    )}
                 </div>
               ))
             )}
           </div>
        </div>
      )}

      {activeView === 'my-projects' && (
        <div className="space-y-8">
           {!selectedProjectId ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
