                        <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                           <span className={`text-[10px] font-black px-3 py-1 rounded-full ${sub?.status === 'approved' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}>
