import React, { useState } from 'react';
import { User, Project, Post, Attachment, ProjectSubmission, AttachmentType } from '../types';

interface TeacherDashboardProps {
  user: User;
  posts: Post[];
  projects: Project[];
  updateProjectSubmission: (projectId: string, submission: ProjectSubmission) => void;
}

const TeacherDashboard: React.FC<TeacherDashboardProps> = ({ user, posts, projects, updateProjectSubmission }) => {
  const [activeView, setActiveView] = useState<'feed' | 'my-projects' | 'badges'>('feed');
  const [selectedProjectId, setSelectedProjectId] = useState<string | null>(null);
  const [submissionNote, setSubmissionNote] = useState('');
  const [submissionFiles, setSubmissionFiles] = useState<Attachment[]>([]);

  // Link Input State
  const [linkUrl, setLinkUrl] = useState('');
  const [linkName, setLinkName] = useState('');
  const [showLinkInput, setShowLinkInput] = useState(false);

  // Derived Data
  const myProjects = projects.filter(p => p.assignedTeacherIds.includes(user.id));
  const myBadges = projects.flatMap(p => p.submissions[user.id]?.badges || []);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();

      let type: AttachmentType = 'file';
      if (file.type.startsWith('image')) type = 'image';
      else if (file.type.startsWith('video')) type = 'video';
      else if (file.type.startsWith('audio')) type = 'audio';

      reader.onload = () => {
        setSubmissionFiles(prev => [...prev, {
          type: type,
          url: reader.result as string,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAddLink = () => {
    if (linkUrl && linkName) {
      let finalUrl = linkUrl;
      if (!finalUrl.startsWith('http')) {
        finalUrl = 'https://' + finalUrl;
      }
      setSubmissionFiles(prev => [...prev, {
        type: 'link',
        url: finalUrl,
        name: linkName
      }]);
      setLinkUrl('');
      setLinkName('');
      setShowLinkInput(false);
    }
  };

  const removeFile = (index: number) => {
    setSubmissionFiles(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmitWork = () => {
    if (selectedProjectId) {
      const existing = projects.find(p => p.id === selectedProjectId)?.submissions[user.id];

      const submission: ProjectSubmission = {
        teacherId: user.id,
        files: [...(existing?.files || []), ...submissionFiles],
        notes: submissionNote || existing?.notes || '',
        status: 'submitted',
        feedback: existing?.feedback || '',
        badges: existing?.badges || [],
        submittedAt: new Date().toLocaleDateString('ar-SA')
      };

      updateProjectSubmission(selectedProjectId, submission);
      setSubmissionNote('');
      setSubmissionFiles([]);
      alert('تم رفع الإنجاز بنجاح وسيتم مراجعته من قبل المشرفة');
    }
  };

  const getIconForType = (type: string) => {
    switch (type) {
      case 'image': return '🖼️';
      case 'video': return '🎥';
      case 'audio': return '🎙️';
      case 'link': return '🔗';
      default: return '📄';
    }
  };

  return (
    <div className="pb-24 animate-fadeIn">
      {/* Mobile-Friendly Navigation */}
      <div className="fixed bottom-0 left-0 w-full bg-white border-t border-slate-100 p-4 z-50 flex justify-around md:static md:bg-transparent md:border-0 md:p-0 md:justify-center md:mb-10">
         <div className="bg-white p-1.5 md:p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-lg">
            {[
              { id: 'feed', icon: '📢', label: 'الرئيسية' },
              { id: 'my-projects', icon: '🚀', label: 'مشاريعي' },
              { id: 'badges', icon: '🏆', label: 'أوسمتي' }
            ].map(item => (
              <button
                key={item.id}
                onClick={() => { setActiveView(item.id as any); setSelectedProjectId(null); }}
                className={`flex-1 px-4 py-3 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm ${
                  activeView === item.id ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'
                }`}
              >
                <span>{item.icon}</span>
                <span>{item.label}</span>
              </button>
            ))}
         </div>
      </div>

      {activeView === 'feed' && (
        <div className="max-w-2xl mx-auto space-y-8">
           <div className="bg-gradient-to-r from-indigo-500 to-purple-500 rounded-[2.5rem] p-8 text-white shadow-lg relative overflow-hidden">
              <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full blur-3xl -mr-16 -mt-16"></div>
              <h2 className="text-2xl font-black mb-2 relative z-10">مرحباً، {user.name} 👋</h2>
              <p className="opacity-90 font-bold text-sm relative z-10">إليك آخر المستجدات والتعاميم الإدارية</p>
           </div>

           <div className="space-y-6">
             {posts.length === 0 ? (
               <div className="text-center py-12 text-slate-300 font-bold">لا توجد تعاميم جديدة</div>
             ) : (
               posts.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()).map(post => (
                 <div key={post.id} className={`bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 ${post.isPinned ? 'border-t-4 border-t-amber-400' : ''}`}>
                    {post.isPinned && <div className="text-xs font-black text-amber-500 mb-2 flex items-center gap-1">📌 مثبت للأهمية</div>}
                    <div className="flex items-center gap-3 mb-4">
                       <div className="w-10 h-10 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600 font-black text-xs">م.م</div>
                       <div>
                          <h4 className="font-black text-slate-900">{post.title}</h4>
                          <span className="text-[10px] text-slate-400 font-bold">{post.createdAt}</span>
                       </div>
                    </div>
                    <p className="text-slate-600 font-bold text-sm leading-relaxed whitespace-pre-line mb-6 bg-slate-50/50 p-4 rounded-2xl">{post.content}</p>

                    {post.attachments.length > 0 && (
                      <div className="space-y-2">
                        {post.attachments.map((att, i) => (
                          <div key={i} className="flex items-center gap-3 bg-slate-50 p-3 rounded-xl border border-slate-100">
                             <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center text-sm shadow-sm">{getIconForType(att.type)}</div>
                             <div className="flex-1 min-w-0">
                                <div className="text-xs font-black text-slate-700 truncate">{att.name}</div>
                             </div>
                             <a href={att.url} target={att.type === 'link' ? '_blank' : '_self'} download={att.type !== 'link' ? att.name : undefined} className="text-indigo-600 text-xs font-black px-3 py-1 bg-indigo-50 rounded-lg">
                               {att.type === 'link' ? 'فتح' : 'تحميل'}
                             </a>
                          </div>
                        ))}
                      </div>
                    )}
                 </div>
               ))
             )}
           </div>
        </div>
      )}

      {activeView === 'my-projects' && (
        <div className="space-y-8">
           {!selectedProjectId ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
               {myProjects.length === 0 ? (
                 <div className="col-span-full text-center py-20 text-slate-300 font-bold">لم يتم إسناد مشاريع لك بعد</div>
               ) : (
                 myProjects.map(project => {
                   const sub = project.submissions[user.id];
                   return (
                     <div key={project.id} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition-all flex flex-col">
                        <div className="mb-4">
                           <span className="bg-purple-50 text-purple-600 px-3 py-1 rounded-lg text-[10px] font-black">مشروع</span>
                        </div>
                        <h3 className="text-xl font-black text-slate-800 mb-2">{project.name}</h3>
                        <p className="text-slate-400 text-xs font-bold line-clamp-2 mb-6">{project.description}</p>

                        <div className="mt-auto pt-4 border-t border-slate-50 flex items-center justify-between">
                           <span className={`text-[10px] font-black px-3 py-1 rounded-full ${sub?.status === 'approved' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}>
                             {sub?.status === 'approved' ? 'مكتمل ✅' : sub?.status === 'submitted' ? 'جاري المراجعة ⏳' : 'قيد التنفيذ 🏃‍♀️'}
                           </span>
                           <button onClick={() => setSelectedProjectId(project.id)} className="bg-slate-900 text-white px-5 py-2 rounded-xl text-xs font-black hover:bg-purple-600 transition-colors">فتح المشروع</button>
                        </div>
                     </div>
                   );
                 })
               )}
             </div>
           ) : (
             <div className="bg-white rounded-[3rem] shadow-xl p-8 md:p-12 animate-slideUp">
                {(() => {
                  const project = projects.find(p => p.id === selectedProjectId);
                  if (!project) return null;
                  const submission = project.submissions[user.id];

                  return (
                    <div className="space-y-8">
                       <button onClick={() => setSelectedProjectId(null)} className="text-slate-400 font-bold text-xs hover:text-slate-600 mb-4">← العودة للمشاريع</button>

                       <div className="border-b border-slate-100 pb-8">
                          <h2 className="text-3xl font-black text-slate-900 mb-4">{project.name}</h2>
                          <div className="bg-slate-50 p-6 rounded-[2rem]">
                            <h4 className="font-black text-slate-700 mb-2">الأهداف:</h4>
                            <p className="text-slate-500 font-bold text-sm leading-relaxed">{project.description}</p>
                            <h4 className="font-black text-slate-700 mt-4 mb-2">المهام المطلوبة:</h4>
                            <ul className="list-disc list-inside text-slate-500 font-bold text-sm space-y-1">
                               {project.tasks.map((t, i) => <li key={i}>{t}</li>)}
                            </ul>
                          </div>
                       </div>

                       <div className="space-y-6">
                          <h3 className="text-xl font-black text-slate-800 flex items-center gap-2">
                             <span>📤</span> بوابة رفع الإنجاز
                          </h3>

                          {submission?.files && submission.files.length > 0 && (
                            <div className="bg-indigo-50/50 p-6 rounded-[2rem] border border-indigo-50">
                              <h4 className="text-xs font-black text-indigo-900 mb-3">الملفات المرفوعة سابقاً:</h4>
                              <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                                {submission.files.map((f, i) => (
                                  <a key={i} href={f.url} target={f.type === 'link' ? '_blank' : '_self'} download={f.type !== 'link' ? f.name : undefined} className="flex items-center gap-3 bg-white p-3 rounded-xl border border-indigo-100 hover:shadow-sm transition-all">
                                     <div className="w-8 h-8 bg-indigo-50 rounded-lg flex items-center justify-center text-sm">{getIconForType(f.type)}</div>
                                     <div className="flex-1 min-w-0">
                                        <div className="text-xs font-black text-slate-700 truncate">{f.name}</div>
                                        <div className="text-[8px] font-bold text-slate-400">{f.type === 'link' ? 'رابط' : f.type === 'video' ? 'فيديو' : f.type === 'audio' ? 'صوت' : 'ملف'}</div>
                                     </div>
                                  </a>
                                ))}
                              </div>
                            </div>
                          )}

                          {submission?.status === 'approved' ? (
                            <div className="bg-emerald-50 border border-emerald-100 p-8 rounded-[2rem] text-center">
                               <div className="text-4xl mb-4">🎉</div>
                               <h3 className="text-emerald-800 font-black text-lg">تم اعتماد هذا المشروع بنجاح!</h3>
                               <p className="text-emerald-600/70 font-bold text-sm mt-2">شكراً لجهودك المتميزة</p>
                            </div>
                          ) : (
                            <div className="bg-white border-2 border-slate-100 p-6 rounded-[2rem] space-y-4">
                               <textarea 
                                 placeholder="أكتبي ملاحظاتك حول التنفيذ..." 
                                 value={submissionNote}
                                 onChange={e => setSubmissionNote(e.target.value)}
                                 className="w-full bg-slate-50 rounded-2xl p-4 font-bold text-sm outline-none focus:bg-white focus:border-indigo-500 border-2 border-transparent transition-all min-h-[100px] text-slate-900"
                               />

                               <div className="space-y-3">
                                  {submissionFiles.map((f, i) => (
                                    <div key={i} className="flex justify-between items-center bg-slate-50 p-3 rounded-xl">
                                      <div className="flex items-center gap-2">
                                        <span className="text-lg">{getIconForType(f.type)}</span>
                                        <span className="text-xs font-black text-slate-600 truncate max-w-[150px]">{f.name}</span>
                                      </div>
                                      <button onClick={() => removeFile(i)} className="text-red-500 hover:text-red-700 text-xs font-black px-2">حذف ✕</button>
                                    </div>
                                  ))}

                                  <div className="grid grid-cols-2 gap-3">
                                      <label className="cursor-pointer bg-slate-50 hover:bg-slate-100 border-2 border-dashed border-slate-200 rounded-2xl p-6 text-center transition-all flex flex-col items-center justify-center">
                                        <div className="text-xl mb-1">📁</div>
                                        <div className="text-slate-400 font-black text-[10px]">رفع ملف / فيديو / صوت</div>
                                        <input type="file" onChange={handleFileUpload} className="hidden" accept="image/*,video/*,audio/*,.pdf,.doc,.docx,.ppt,.pptx" />
                                      </label>

                                      <button onClick={() => setShowLinkInput(true)} className="bg-slate-50 hover:bg-slate-100 border-2 border-dashed border-slate-200 rounded-2xl p-6 text-center transition-all flex flex-col items-center justify-center">
                                        <div className="text-xl mb-1">🔗</div>
                                        <div className="text-slate-400 font-black text-[10px]">إضافة رابط</div>
                                      </button>
                                  </div>

                                  {showLinkInput && (
                                    <div className="bg-indigo-50 p-4 rounded-2xl space-y-2 border border-indigo-100 animate-fadeIn">
                                       <input 
                                         type="text" 
                                         placeholder="اسم الرابط (مثال: شرح الدرس)" 
                                         value={linkName} 
                                         onChange={e => setLinkName(e.target.value)}
                                         className="w-full px-4 py-2 rounded-xl text-xs font-bold outline-none border border-slate-200"
                                       />
                                       <input 
                                         type="text" 
                                         placeholder="الرابط (URL)" 
                                         value={linkUrl} 
                                         onChange={e => setLinkUrl(e.target.value)}
                                         className="w-full px-4 py-2 rounded-xl text-xs font-bold outline-none border border-slate-200 text-left"
                                         dir="ltr"
                                       />
                                       <div className="flex gap-2">
                                         <button onClick={handleAddLink} className="flex-1 bg-indigo-600 text-white py-2 rounded-xl text-xs font-black">إضافة</button>
                                         <button onClick={() => setShowLinkInput(false)} className="bg-slate-200 text-slate-500 px-4 py-2 rounded-xl text-xs font-black">إلغاء</button>
                                       </div>
                                    </div>
                                  )}
                               </div>

                               <button onClick={handleSubmitWork} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black shadow-lg">رفع وتسليم العمل</button>
                            </div>
                          )}

                          {submission?.badges && submission.badges.length > 0 && (
                             <div className="bg-amber-50 p-6 rounded-[2rem] border border-amber-100">
                                <h4 className="font-black text-amber-800 mb-4 text-sm">الأوسمة الممنوحة لهذا المشروع:</h4>
                                <div className="flex gap-4 text-4xl">
                                   {submission.badges.map((b, i) => <span key={i} className="animate-bounce">{b}</span>)}
                                </div>
                             </div>
                          )}
                       </div>
                    </div>
                  );
                })()}
             </div>
           )}
        </div>
      )}

      {activeView === 'badges' && (
        <div className="text-center space-y-8 pt-10">
           <h2 className="text-2xl font-black text-slate-800">لوحة التحفيز والتقدير</h2>
           <p className="text-slate-400 font-bold text-sm">حصاد جهودك وإبداعك في المنصة</p>

           <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
              <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col items-center gap-4">
                 <div className="text-4xl">📚</div>
                 <div className="font-black text-slate-800">{myProjects.length}</div>
                 <div className="text-[10px] text-slate-400 font-bold">مشاريع مسندة</div>
              </div>
              <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 flex flex-col items-center gap-4">
                 <div className="text-4xl">✅</div>
                 <div className="font-black text-slate-800">{myProjects.filter(p => p.submissions[user.id]?.status === 'approved').length}</div>
                 <div className="text-[10px] text-slate-400 font-bold">مشاريع منجزة</div>
              </div>
              <div className="col-span-2 bg-gradient-to-br from-amber-100 to-orange-50 p-8 rounded-[2.5rem] shadow-inner border border-amber-200">
                 <h3 className="font-black text-amber-900 mb-6">مجموع الأوسمة</h3>
                 {myBadges.length === 0 ? (
                   <p className="text-amber-800/50 font-bold text-sm">واصلي الإبداع للحصول على الأوسمة!</p>
                 ) : (
                   <div className="flex flex-wrap justify-center gap-4 text-5xl">
                     {myBadges.map((b, i) => <span key={i} className="hover:scale-125 transition-transform cursor-default">{b}</span>)}
                   </div>
                 )}
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default TeacherDashboard;

import React, { useState, useMemo } from 'react';
import { User, Project, Post, ProjectSubmission, Attachment } from '../types';

interface SupervisorDashboardProps {
  teachers: User[];
  posts: Post[];
  projects: Project[];
  onAddPost: (post: Post) => void;
  onDeletePost: (id: string) => void;
  onTogglePinPost: (id: string) => void;
  onAddTeacher: (id: string, name: string, email?: string, phone?: string) => void;
  onSoftDeleteTeacher: (id: string) => void;
  onResetPassword: (teacherId: string) => string;
  onAddProject: (project: Project) => void;
  onDeleteProject: (projectId: string) => void;
  onUpdateProjectSubmission: (projectId: string, submission: ProjectSubmission) => void;
  academicYear: string;
}

const SupervisorDashboard: React.FC<SupervisorDashboardProps> = ({ 
  teachers, posts, projects, 
  onAddPost, onDeletePost, onTogglePinPost,
  onAddTeacher, onSoftDeleteTeacher, onResetPassword,
  onAddProject, onDeleteProject, onUpdateProjectSubmission,
  academicYear
}) => {
  const [activeTab, setActiveTab] = useState<'feed' | 'projects' | 'teachers' | 'archive'>('feed');

  // Post Form State
  const [postContent, setPostContent] = useState('');
  const [postTitle, setPostTitle] = useState('');
  const [postAttachments, setPostAttachments] = useState<Attachment[]>([]);
  const [isPostPinned, setIsPostPinned] = useState(false);

  // Project Form State
  const [newProjectName, setNewProjectName] = useState('');
  const [newProjectGoals, setNewProjectGoals] = useState('');
  const [newProjectTasks, setNewProjectTasks] = useState('');
  const [selectedTeachers, setSelectedTeachers] = useState<string[]>([]);
  const [showProjectForm, setShowProjectForm] = useState(false);

  // Teacher Form State
  const [newTeacherName, setNewTeacherName] = useState('');
  const [newTeacherId, setNewTeacherId] = useState('');
  const [newTeacherEmail, setNewTeacherEmail] = useState('');
  const [newTeacherPhone, setNewTeacherPhone] = useState('');
  const [showTeacherForm, setShowTeacherForm] = useState(false);

  // Selected Project for Review
  const [selectedReviewProjectId, setSelectedReviewProjectId] = useState<string | null>(null);

  // Archive Filter
  const [archiveYear, setArchiveYear] = useState(academicYear);

  const activeTeachers = useMemo(() => teachers.filter(t => t.isActive), [teachers]);
  const archivedTeachers = useMemo(() => teachers.filter(t => !t.isActive), [teachers]);

  const filteredArchiveData = useMemo(() => {
    return {
      teachers: archivedTeachers,
      projects: projects.filter(p => p.academicYear === archiveYear)
    };
  }, [archivedTeachers, projects, archiveYear]);

  // Handlers
  const handleCreatePost = (e: React.FormEvent) => {
    e.preventDefault();
    if (!postTitle || !postContent) return alert('يرجى كتابة العنوان والمحتوى');

    const newPost: Post = {
      id: Date.now().toString(),
      authorId: 'supervisor',
      authorName: 'الإدارة المدرسية',
      title: postTitle,
      content: postContent,
      attachments: postAttachments,
      isPinned: isPostPinned,
      createdAt: new Date().toLocaleDateString('ar-SA'),
      academicYear
    };
    onAddPost(newPost);
    setPostTitle('');
    setPostContent('');
    setPostAttachments([]);
    setIsPostPinned(false);
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      const reader = new FileReader();
      reader.onload = () => {
        setPostAttachments(prev => [...prev, {
          type: file.type.startsWith('image') ? 'image' : 'file',
          url: reader.result as string,
          name: file.name
        }]);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreateProject = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProjectName) return;

    const tasks = newProjectTasks.split('\n').filter(t => t.trim());

    const newProject: Project = {
      id: Date.now().toString(),
      name: newProjectName,
      description: newProjectGoals,
      tasks: tasks,
      assignedTeacherIds: selectedTeachers.length > 0 ? selectedTeachers : activeTeachers.map(t => t.id),
      createdAt: new Date().toLocaleDateString('ar-SA'),
      academicYear,
      submissions: {}
    };
    onAddProject(newProject);
    setNewProjectName('');
    setNewProjectGoals('');
    setNewProjectTasks('');
    setSelectedTeachers([]);
    setShowProjectForm(false);
  };

  const handleAwardBadge = (projectId: string, teacherId: string, badge: string) => {
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const submission = project.submissions[teacherId] || { 
      teacherId, files: [], notes: '', status: 'pending', feedback: '', badges: [] 
    };

    const newBadges = submission.badges.includes(badge) ? submission.badges : [...submission.badges, badge];
    onUpdateProjectSubmission(projectId, { ...submission, badges: newBadges });
  };

  const handleApproveSubmission = (projectId: string, teacherId: string) => {
    const project = projects.find(p => p.id === projectId);
    if (!project) return;
    const submission = project.submissions[teacherId];
    if (submission) {
      onUpdateProjectSubmission(projectId, { ...submission, status: 'approved' });
    }
  };

  const handleCreateTeacher = (e: React.FormEvent) => {
    e.preventDefault();
    if (newTeacherId && newTeacherName) {
      onAddTeacher(newTeacherId, newTeacherName, newTeacherEmail, newTeacherPhone);
      setNewTeacherId('');
      setNewTeacherName('');
      setNewTeacherEmail('');
      setNewTeacherPhone('');
      setShowTeacherForm(false);
    }
  };

  const handleResetTeacher = (id: string, name: string) => {
    if (window.confirm(`هل أنت متأكد من إعادة تعيين كلمة المرور للمعلمة ${name}؟ ستعود إلى OM${id}`)) {
      onResetPassword(id);
      alert('تم إعادة تعيين كلمة المرور بنجاح');
    }
  };

  const getIconForType = (type: string) => {
    switch (type) {
      case 'image': return '🖼️';
      case 'video': return '🎥';
      case 'audio': return '🎙️';
      case 'link': return '🔗';
      default: return '📄';
    }
  };

  return (
    <div className="space-y-8 pb-20 animate-fadeIn">
      {/* Navigation Tabs */}
      <div className="flex justify-center">
        <div className="bg-white p-2 rounded-[2rem] shadow-xl border border-slate-100 flex gap-2 w-full max-w-3xl overflow-x-auto">
          {[
            { id: 'feed', label: '📢 مركز التواصل', color: 'indigo' },
            { id: 'projects', label: '🚀 إدارة المشاريع', color: 'purple' },
            { id: 'teachers', label: '👥 المعلمات', color: 'emerald' },
            { id: 'archive', label: '📂 الأرشيف', color: 'amber' }
          ].map(tab => (
            <button
              key={tab.id}
              onClick={() => { setActiveTab(tab.id as any); setSelectedReviewProjectId(null); }}
              className={`flex-1 min-w-[100px] px-4 py-4 rounded-[1.5rem] font-black transition-all flex items-center justify-center gap-2 text-xs md:text-sm ${
                activeTab === tab.id 
                  ? `bg-${tab.color}-600 text-white shadow-lg` 
                  : `text-slate-500 hover:bg-${tab.color}-50`
              }`}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* FEED TAB */}
      {activeTab === 'feed' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-1">
             <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 sticky top-24">
                <h3 className="text-xl font-black text-slate-800 mb-6 flex items-center gap-2">
                  <span>✍️</span> إنشاء تعميم جديد
                </h3>
                <form onSubmit={handleCreatePost} className="space-y-4">
                  <input 
                    type="text" 
                    placeholder="عنوان التعميم" 
                    value={postTitle}
                    onChange={e => setPostTitle(e.target.value)}
                    className="w-full px-5 py-3 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-indigo-500 outline-none font-bold text-sm text-slate-900"
                  />
                  <textarea 
                    placeholder="نص التعميم..." 
                    value={postContent}
                    onChange={e => setPostContent(e.target.value)}
                    className="w-full px-5 py-3 rounded-2xl bg-slate-50 border-2 border-slate-50 focus:border-indigo-500 outline-none font-bold text-sm text-slate-900 min-h-[120px]"
                  />

                  <div className="flex items-center gap-2">
                     <label className="flex-1 cursor-pointer bg-slate-50 hover:bg-slate-100 px-4 py-3 rounded-xl border border-dashed border-slate-300 text-slate-500 text-xs font-black flex items-center justify-center gap-2 transition-all">
                        <span>📎 إرفاق ملف</span>
                        <input type="file" onChange={handleFileUpload} className="hidden" />
                     </label>
                     <label className={`cursor-pointer px-4 py-3 rounded-xl border-2 text-xs font-black transition-all ${isPostPinned ? 'bg-amber-50 border-amber-400 text-amber-600' : 'bg-white border-slate-100 text-slate-400'}`}>
                        📌 تثبيت
                        <input type="checkbox" checked={isPostPinned} onChange={e => setIsPostPinned(e.target.checked)} className="hidden" />
                     </label>
                  </div>

                  {postAttachments.length > 0 && (
                    <div className="flex gap-2 flex-wrap">
                      {postAttachments.map((att, i) => (
                        <div key={i} className="bg-indigo-50 text-indigo-600 px-3 py-1 rounded-lg text-[10px] font-bold truncate max-w-[150px]">
                          {att.name}
                        </div>
                      ))}
                    </div>
                  )}

                  <button type="submit" className="w-full bg-indigo-600 text-white py-4 rounded-2xl font-black shadow-lg hover:bg-indigo-700 transition-all">نشر التعميم</button>
                </form>
             </div>
          </div>

          <div className="lg:col-span-2 space-y-6">
             <h3 className="text-xl font-black text-slate-800 pr-2">📝 آخر المستجدات</h3>
             {posts.length === 0 ? (
               <div className="text-center py-20 bg-white rounded-[2.5rem] border-2 border-dashed border-slate-100 text-slate-300 font-bold">لا توجد تعاميم منشورة</div>
             ) : (
               posts.sort((a, b) => (a.isPinned === b.isPinned ? 0 : a.isPinned ? -1 : 1)).map(post => (
                 <div key={post.id} className={`bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 relative group transition-all hover:shadow-md ${post.isPinned ? 'border-r-8 border-r-amber-400' : ''}`}>
                    <div className="flex justify-between items-start mb-4">
                       <div className="flex items-center gap-3">
                          <div className="w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center text-lg">🏫</div>
                          <div>
                            <h4 className="font-black text-slate-900">{post.title}</h4>
                            <span className="text-[10px] text-slate-400 font-bold">{post.createdAt}</span>
                          </div>
                       </div>
                       <div className="flex gap-2">
                         <button onClick={() => onTogglePinPost(post.id)} className={`text-xl ${post.isPinned ? 'grayscale-0' : 'grayscale opacity-20'}`}>📌</button>
                         <button onClick={() => onDeletePost(post.id)} className="text-slate-200 hover:text-red-500 font-bold px-2">✕</button>
                       </div>
                    </div>
                    <p className="text-slate-600 font-bold text-sm leading-relaxed whitespace-pre-line mb-6">{post.content}</p>
                    {post.attachments.length > 0 && (
                      <div className="flex gap-3 overflow-x-auto pb-2">
                        {post.attachments.map((att, i) => (
                          <a key={i} href={att.url} download={att.name} className="flex items-center gap-2 bg-slate-50 px-4 py-2 rounded-xl border border-slate-100 text-xs font-black text-indigo-600 hover:bg-indigo-50 transition-colors">
                            {att.type === 'image' ? '🖼️' : '📄'} {att.name}
                          </a>
                        ))}
                      </div>
                    )}
                 </div>
               ))
             )}
          </div>
        </div>
      )}

      {/* PROJECTS TAB */}
      {activeTab === 'projects' && (
        <div className="space-y-8 animate-fadeIn">
          {!selectedReviewProjectId ? (
            <>
               <div className="flex justify-between items-center bg-white p-8 rounded-[3rem] shadow-sm border border-slate-100">
                  <div>
